                    className={`w-full text-[10px] px-4 py-4 border font-bold transition-all uppercase shadow-lg tracking-widest ${saveConfirmation ? 'bg-accent-green text-paper border-accent-green' : 'bg-selection text-paper border-selection hover:bg-selection-light'}`}
                  >
