// Chain depth mapping for reward multipliers
const CHAIN_DEPTH: Record<string, number> = {
  waist: 0,
  torso: 1, collar: 2, neck: 3, head: 3,
  l_shoulder: 3, r_shoulder: 3,
  l_elbow: 4, r_elbow: 4,
  l_hand: 5, r_hand: 5,
  l_hip: 1, r_hip: 1,
  l_knee: 2, r_knee: 2,
  l_foot: 3, r_foot: 3,
  l_toe: 4, r_toe: 4
};

const snapOutEase = (t: number) => {
  const c4 = (2 * Math.PI) / 3;
  return t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

const EASING_FUNCTIONS = {
  linear: (t: number) => t,
  easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
  snapOut: snapOutEase,
};

interface HistoryState {
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  timestamp: number;
  label?: string;
}

interface SavedPoseEntry {
  id: number;
  name: string;
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
}

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [showLabels, setShowLabels] = useState(false);
  const [baseH] = useState(150);
  const [isConsoleVisible, setIsConsoleVisible] = useState(false);
  const [activeControlTab, setActiveControlTab] = useState<'pose' | 'props' | 'library'>('pose');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const [isCalibrated, setIsCalibrated] = useState(false);
  const [isCalibrating, setIsCalibrating] = useState(false);
  const [isPlayingTimelapse, setIsPlayingTimelapse] = useState(false);
  const [tokens, setTokens] = useState(0);
  const [lHandFlash, setLHandFlash] = useState(false);
  const [rHandFlash, setRHandFlash] = useState(false);
  const [saveConfirmation, setSaveConfirmation] = useState(false);

  // Pinning State
  const [pinningMode, setPinningMode] = useState<'none' | 'rightFoot' | 'dual'>('none');
  const [pinOffset, setPinOffset] = useState<Vector2D>({ x: 0, y: 0 });

  // Tween Configuration State
  const [tweenDuration, setTweenDuration] = useState(1000);
  const [tweenEasing, setTweenEasing] = useState<'linear' | 'easeInOutQuad' | 'snapOut'>('easeInOutQuad');
  const [isTweening, setIsTweening] = useState(false);

  // Interaction Tracking
  const lastInteractionTimeRef = useRef(Date.now());
  const draggingBoneKeyRef = useRef<keyof WalkingEnginePivotOffsets | null>(null);

  // Tutorial State
  const [showTutorial, setShowTutorial] = useState(false);
  const [hasCollectedFirstPixel, setHasCollectedFirstPixel] = useState(() => {
    return localStorage.getItem('bitruvian_tutorial_done') === 'true';
  });

  // Shop State
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [purchasedPrizes, setPurchasedPrizes] = useState<string[]>([]);

  // Mask State
  const [maskImage, setMaskImage] = useState<string | null>(null);
  const [maskTransform, setMaskTransform] = useState<MaskTransform>({ x: 0, y: 0, rotation: 0, scale: 1 });

  // Core State
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(INITIAL_CHALLENGE_POSE);
  const [props, setProps] = useState<WalkingEngineProportions>({
    head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 },
    l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 },
    r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 },
    l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 },
    r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 }
  });

  // Pose Library State
  const [savedPoses, setSavedPoses] = useState<SavedPoseEntry[]>([]);

  // Target Anomaly Pixel
  const [anomaly, setAnomaly] = useState<Vector2D | null>(null);
  const anomalyRef = useRef<Vector2D | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [redoStack, setRedoStack] = useState<HistoryState[]>([]);
  const [recordingHistory, setRecordingHistory] = useState<HistoryState[]>([]);

  // Interaction Ref
  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);
  const dragStartXRef = useRef(0);
  const dragStartPivotOffsetRef = useRef(0);
  const isInteractingRef = useRef(false);
  const lastSnapshotTimeRef = useRef(0);

  const addLog = useCallback((message: string) => {
    setSystemLogs(prev => [...prev.slice(-49), { timestamp: new Date().toLocaleTimeString(), message }]);
  }, []);

  useEffect(() => {
    try {
      const storedPoses = localStorage.getItem('bitruvian_library');
      if (storedPoses) {
        const parsed = JSON.parse(storedPoses);
        if (Array.isArray(parsed)) setSavedPoses(parsed);
      }
    } catch (e) { console.error("Error loading library", e); }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('bitruvian_library', JSON.stringify(savedPoses));
    } catch (e) { console.error("Error saving library", e); }
  }, [savedPoses]);

  const recordSnapshot = useCallback((label?: string) => {
    const currentState: HistoryState = {
      pivotOffsets: { ...pivotOffsets },
      props: JSON.parse(JSON.stringify(props)),
      timestamp: Date.now(),
      label
    };
    setRecordingHistory(prev => [...prev, currentState]);
  }, [pivotOffsets, props]);

  const saveToHistory = useCallback(() => {
    const currentState: HistoryState = {
      pivotOffsets: { ...pivotOffsets },
      props: JSON.parse(JSON.stringify(props)),
      timestamp: Date.now()
    };
    setHistory(prev => [...prev.slice(-49), currentState]);
    setRedoStack([]);
  }, [pivotOffsets, props]);

  const anomalySize = useMemo(() => {
    const rawW = ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_FOREARM;
    return rawW * baseH * props.l_lower_arm.w * 0.65;
  }, [baseH, props.l_lower_arm.w]);

  const spawnAnomaly = useCallback(() => {
    const centerX = 0;
    const centerY = -300; 
    const radius = 450; 
    const angle = Math.random() * Math.PI * 2;
    const distance = Math.sqrt(Math.random()) * radius; 
    const newAnom = {
      x: centerX + Math.cos(angle) * distance,
      y: centerY + Math.sin(angle) * distance
    };
    setAnomaly(newAnom);
    anomalyRef.current = newAnom;
  }, []);

  const awardTokens = useCallback((sourceBone: string) => {
    const timeSinceLastInteraction = Date.now() - lastInteractionTimeRef.current;

    // Multipliers for "passive" collection
    let passiveMultiplier = (timeSinceLastInteraction > 1500) ? 2 : 1;

    // Multiplier based on skeletal distance from dragged joint
    let distanceBonus = 1;
    if (draggingBoneKeyRef.current) {
      const d1 = CHAIN_DEPTH[draggingBoneKeyRef.current] || 0;
      const d2 = CHAIN_DEPTH[sourceBone] || 0;
      // Bonus scales with absolute difference in chain depth
      distanceBonus = 1 + Math.abs(d1 - d2);
    } else if (isTweening) {
      // Bonus for collections during automated movement
      distanceBonus = 2.0;
    }

    const baseReward = 1;
    const gain = Math.floor(baseReward * passiveMultiplier * distanceBonus);

    setTokens(prev => prev + gain);
    addLog(`[SYSTEM]: POSE_PICKUP - UNIT TOKENS UPDATED (+${gain}) ${passiveMultiplier > 1 ? '[PASSIVE BONUS]' : ''} [${sourceBone.toUpperCase()} DISTANCE: ${distanceBonus}X]`);

    if (!hasCollectedFirstPixel) {
      setHasCollectedFirstPixel(true);
      setShowTutorial(true);
      localStorage.setItem('bitruvian_tutorial_done', 'true');
    }
  }, [hasCollectedFirstPixel, addLog, isTweening]);

  const handleAnomalyResolve = useCallback((side: 'left' | 'right', boneKey: string) => {
    if (!anomalyRef.current) return;
    if (side === 'left') {
      setLHandFlash(true);
      setTimeout(() => setLHandFlash(false), 300);
    } else {
      setRHandFlash(true);
      setTimeout(() => setRHandFlash(false), 300);
    }
    awardTokens(boneKey);
    spawnAnomaly();
  }, [spawnAnomaly, awardTokens]);

  const handleAnomalyClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!anomalyRef.current) return;
    awardTokens('head'); // Click acts as head/neck collection
    spawnAnomaly();
  };

  const updatePinOffset = useCallback(() => {
    if (pinningMode === 'none') {
        setPinOffset({ x: 0, y: 0 });
        return;
    }

    const getRot = (key: string) => ((pivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (props[key]?.h || 1);

    let pos = { x: 0, y: -50 };
    const waistRot = getRot('waist');
    const hipRot = waistRot + getRot('r_hip');
    const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg');
    const kneeRot = hipRot + getRot('r_knee');
    const kneePos = addVec(pos, rotateVec({ x: 0, y: thighLen }, hipRot));
    const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg');
    const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));

    setPinOffset({ x: -anklePos.x, y: -anklePos.y });
  }, [pinningMode, pivotOffsets, props, baseH]);

  useEffect(() => {
    updatePinOffset();
  }, [updatePinOffset]);

  const checkCollisions = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    if (!anomalyRef.current || !isCalibrated) return;

    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);

    // Points to check: Hands and Toes
    const checkJoint = (pos: Vector2D, boneName: string) => {
        const dx = pos.x - anomalyRef.current!.x;
        const dy = pos.y - anomalyRef.current!.y;
        const threshold = anomalySize * 3;
        if (dx*dx + dy*dy < threshold * threshold) {
            handleAnomalyResolve(boneName.startsWith('l') ? 'left' : 'right', boneName);
            return true;
        }
        return false;
    };

    const waistRot = getRot('waist');
    const waistLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, 'waist');
    const waistPos = { x: pinOffset.x, y: -50 + pinOffset.y };

    // Legs
    ['r', 'l'].forEach(side => {
        const hipRot = waistRot + getRot(`${side}_hip`);
        const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, `${side}_upper_leg` as any);
        const kneeRot = hipRot + getRot(`${side}_knee`);
        const kneePos = addVec(waistPos, rotateVec({ x: 0, y: thighLen }, hipRot));
        const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, `${side}_lower_leg` as any);
        const ankleRot = kneeRot + getRot(`${side}_foot`);
        const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
        const footLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, `${side}_foot` as any);
        const toePos = addVec(anklePos, rotateVec({ x: 0, y: footLen }, ankleRot));

        checkJoint(anklePos, `${side}_foot`);
        checkJoint(toePos, `${side}_toe`);
    });

    // Arms
    const torsoRot = waistRot + getRot('torso');
    const torsoLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, 'torso');
    const collarRot = torsoRot + getRot('collar');
    const collarLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, 'collar');
    const collarEnd = addVec(addVec(waistPos, rotateVec({ x: 0, y: -waistLen }, waistRot)), rotateVec({ x: 0, y: -torsoLen }, torsoRot));

    ['r', 'l'].forEach(side => {
        const sx = (side === 'r' ? RIGGING.R_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER : RIGGING.L_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER) * baseH;
        const baseShoulderRot = side === 'l' ? 90 : -90;
        const shRot = collarRot + baseShoulderRot + getRot(`${side}_shoulder`);
        const shPos = addVec(addVec(collarEnd, rotateVec({ x: 0, y: -collarLen }, collarRot)), rotateVec({ x: sx, y: 0 }, collarRot));
        const upLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, `${side}_upper_arm` as any);
        const elRot = shRot + getRot(`${side}_elbow`);
        const elPos = addVec(shPos, rotateVec({ x: 0, y: upLen }, shRot));
        const lowLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, `${side}_lower_arm` as any);
        const wristPos = addVec(elPos, rotateVec({ x: 0, y: lowLen }, elRot));

        checkJoint(wristPos, `${side}_hand`);
    });

  }, [anomalySize, handleAnomalyResolve, isCalibrated, baseH, pinOffset]);

  useEffect(() => {
    if (!anomaly || !isCalibrated) return;
    const interval = setInterval(() => checkCollisions(pivotOffsets, props), 32);
    return () => clearInterval(interval);
  }, [anomaly, isCalibrated, pivotOffsets, props, checkCollisions]);

  const undo = useCallback(() => {
    if (history.length === 0 || isPlayingTimelapse || isTweening) return;
    const previous = history[history.length - 1];
    setRedoStack(prev => [{ pivotOffsets: { ...pivotOffsets }, props: JSON.parse(JSON.stringify(props)), timestamp: Date.now() }, ...prev]);
    setHistory(prev => prev.slice(0, -1));
    setPivotOffsets(previous.pivotOffsets);
    setProps(previous.props);
  }, [history, pivotOffsets, props, isPlayingTimelapse, isTweening]);

  const redo = useCallback(() => {
    if (redoStack.length === 0 || isPlayingTimelapse || isTweening) return;
    const next = redoStack[0];
    setHistory(prev => [...prev, { pivotOffsets: { ...pivotOffsets }, props: JSON.parse(JSON.stringify(props)), timestamp: Date.now() }]);
    setRedoStack(prev => prev.slice(1));
    setPivotOffsets(next.pivotOffsets);
    setProps(next.props);
  }, [redoStack, pivotOffsets, props, isPlayingTimelapse, isTweening]);

  useEffect(() => {
    const hk = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'z') { if (e.shiftKey) redo(); else undo(); }
      else if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'y') redo();
    };
    window.addEventListener('keydown', hk);
    return () => window.removeEventListener('keydown', hk);
  }, [undo, redo]);

  const startCalibration = useCallback(() => {
    if (isCalibrated || isCalibrating || isPlayingTimelapse || isTweening) return;
    setIsCalibrating(true);
    const duration = 250;
    const startTime = performance.now();
    const startPose = { ...pivotOffsets };
    const animate = (now: number) => {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const easedProgress = snapOutEase(progress);
      const nextPose = { ...startPose };
      JOINT_KEYS.forEach(k => { nextPose[k] = startPose[k] + (T_POSE[k] - startPose[k]) * easedProgress; });
      setPivotOffsets(nextPose);
      if (progress < 1) requestAnimationFrame(animate);
      else {
        setIsCalibrating(false);
        setIsCalibrated(true);
        setIsConsoleVisible(true);
        spawnAnomaly();
      }
    };
    requestAnimationFrame(animate);
  }, [isCalibrated, isCalibrating, pivotOffsets, isPlayingTimelapse, isTweening, spawnAnomaly]);

  const handleDrag = useCallback((e: MouseEvent) => {
    if (draggingBoneKey && !isPlayingTimelapse && !isTweening) {
      lastInteractionTimeRef.current = Date.now();
      if (!isInteractingRef.current) { saveToHistory(); isInteractingRef.current = true; }
      const delta = (e.clientX - dragStartXRef.current) * 0.5;
      const nextOffsets = { ...pivotOffsets, [draggingBoneKey]: dragStartPivotOffsetRef.current + delta };
      setPivotOffsets(nextOffsets);
      const now = Date.now();
      if (now - lastSnapshotTimeRef.current > 60) { recordSnapshot(`DRAG_${draggingBoneKey}`); lastSnapshotTimeRef.current = now; }
    }
  }, [draggingBoneKey, saveToHistory, isPlayingTimelapse, isTweening, recordSnapshot, pivotOffsets]);

  useEffect(() => {
    const hu = () => { if (draggingBoneKey) recordSnapshot(`END_DRAG_${draggingBoneKey}`); setDraggingBoneKey(null); draggingBoneKeyRef.current = null; isInteractingRef.current = false; };
    if (draggingBoneKey) { 
      draggingBoneKeyRef.current = draggingBoneKey;
      window.addEventListener('mousemove', handleDrag); 
      window.addEventListener('mouseup', hu); 
    }
    return () => { window.removeEventListener('mousemove', handleDrag); window.removeEventListener('mouseup', hu); };
  }, [draggingBoneKey, handleDrag, recordSnapshot]);

  const updateProp = (key: keyof WalkingEngineProportions, axis: 'w' | 'h', val: number) => {
    if (isPlayingTimelapse || isTweening) return;
    setProps(p => ({ ...p, [key]: { ...p[key], [axis]: val } }));
  };

  const saveCurrentPose = useCallback(() => {
    if (isPlayingTimelapse || isTweening) return;
    const defaultName = `Pose ${savedPoses.length + 1}`;
    const n = window.prompt("Name this pose:", defaultName);

    if (n !== null) {
      const finalName = n.trim() || defaultName;
      const newEntry: SavedPoseEntry = { 
        id: Date.now(), 
        name: finalName, 
        pivotOffsets: { ...pivotOffsets }, 
        props: JSON.parse(JSON.stringify(props)) 
      };
      setSavedPoses(prev => [...prev, newEntry]);
      setSaveConfirmation(true);
      setTimeout(() => setSaveConfirmation(false), 2000);
      addLog(`[SYSTEM]: POSE_SAVED_SUCCESSFULLY - "${finalName.toUpperCase()}"`);
    }
  }, [pivotOffsets, props, savedPoses.length, isPlayingTimelapse, isTweening, addLog]);

  const loadPoseFromLibrary = useCallback((p: SavedPoseEntry) => {
    if (isPlayingTimelapse || isTweening) return;
    saveToHistory(); setPivotOffsets({ ...p.pivotOffsets }); setProps(JSON.parse(JSON.stringify(p.props))); recordSnapshot(`LOAD_${p.name.toUpperCase()}`);
  }, [saveToHistory, isPlayingTimelapse, isTweening, recordSnapshot]);

  const runTween = useCallback((target: SavedPoseEntry) => {
    if (isTweening || isPlayingTimelapse || isCalibrating) return;
    saveToHistory();
    setIsTweening(true);
    addLog(`SYSTEM: TWEENING TO "${target.name.toUpperCase()}"...`);

    const startPose = { ...pivotOffsets };
    const startProps = JSON.parse(JSON.stringify(props));
    const startTime = performance.now();
    const easeFn = EASING_FUNCTIONS[tweenEasing];

    const animate = (now: number) => {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / tweenDuration, 1);
      const eased = easeFn(progress);

      const nextPose = { ...pivotOffsets };
      JOINT_KEYS.forEach(k => {
        nextPose[k] = startPose[k] + (target.pivotOffsets[k] - startPose[k]) * eased;
      });

      const nextProps = JSON.parse(JSON.stringify(props));
      PROP_KEYS.forEach(k => {
        nextProps[k] = {
          w: startProps[k].w + (target.props[k].w - startProps[k].w) * eased,
          h: startProps[k].h + (target.props[k].h - startProps[k].h) * eased
        };
      });

      setPivotOffsets(nextPose);
      setProps(nextProps);

      if (progress < 1) {
        requestAnimationFrame(animate);
      } else {
        setIsTweening(false);
        addLog(`SYSTEM: TWEEN TO "${target.name.toUpperCase()}" COMPLETE.`);
        recordSnapshot(`TWEEN_END_${target.name.toUpperCase()}`);
      }
    };

    requestAnimationFrame(animate);
  }, [isTweening, isPlayingTimelapse, isCalibrating, pivotOffsets, props, tweenDuration, tweenEasing, saveToHistory, addLog, recordSnapshot]);

  const playTimelapse = useCallback(() => {
    if (recordingHistory.length < 2 || isPlayingTimelapse || isTweening) return;
    setIsPlayingTimelapse(true);
    const STEP = 250; 
    const total = (recordingHistory.length - 1) * STEP;
    const start = performance.now();
    const frame = (now: number) => {
      const elapsed = now - start;
      const progress = Math.min(elapsed / total, 1);
      const exactIndex = progress * (recordingHistory.length - 1);
      const i = Math.min(Math.floor(exactIndex), recordingHistory.length - 2);
      const u = exactIndex - i;
      const sState = recordingHistory[i];
      const eState = recordingHistory[i + 1];
      const nPivot: any = {}; JOINT_KEYS.forEach(k => { nPivot[k] = sState.pivotOffsets[k] + (eState.pivotOffsets[k] - sState.pivotOffsets[k]) * u; });
      const nProps: any = {}; PROP_KEYS.forEach(k => { nProps[k] = { w: sState.props[k].w + (eState.props[k].w - sState.props[k].w) * u, h: sState.props[k].h + (eState.props[k].h - sState.props[k].h) * u }; });
      setPivotOffsets(nPivot); setProps(nProps);
      if (progress < 1) requestAnimationFrame(frame);
      else setIsPlayingTimelapse(false);
    };
    requestAnimationFrame(frame);
  }, [recordingHistory, isPlayingTimelapse, isTweening]);

  const PoseThumbnail = ({ entry, size = 64 }: { entry: SavedPoseEntry, size?: number }) => (
    <svg viewBox="-300 -600 600 1200" width={size} height={size} className="bg-paper/40 rounded border border-ridge/50 pointer-events-none overflow-visible">
       <Mannequin pose={RESTING_BASE_POSE} pivotOffsets={entry.pivotOffsets as any} props={entry.props} showPivots={false} showLabels={false} baseUnitH={size * 0.4} onAnchorMouseDown={() => {}} draggingBoneKey={null} isPaused={true} pinningMode="none" offset={{x:0, y:0}} />
    </svg>
  );

  const buyPrize = (prizeName: string, cost: number) => {
    if (tokens >= cost) {
      setTokens(t => t - cost);
      setPurchasedPrizes(p => [...p, prizeName]);
      addLog(`SHOP: PURCHASED ${prizeName.toUpperCase()}.`);
    } else {
      addLog(`SHOP: INSUFFICIENT TOKENS FOR ${prizeName.toUpperCase()}.`);
    }
  };

  return (
    <div className="flex h-full w-full bg-paper font-mono text-ink overflow-hidden select-none">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto z-50 shadow-2xl">
          <div className="flex justify-between items-center border-b border-ridge pb-2">
            <h1 className="text-xl font-archaic tracking-widest text-ink uppercase italic">Bitruvius.Core</h1>
            <div className="flex gap-1">
              <button onClick={undo} disabled={history.length === 0 || isTweening} className="p-1 hover:bg-selection-super-light disabled:opacity-20 rounded"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M3 10h10a8 8 0 0 1 8 8v2M3 10l6-6M3 10l6 6"/></svg></button>
              <button onClick={redo} disabled={redoStack.length === 0 || isTweening} className="p-1 hover:bg-selection-super-light disabled:opacity-20 rounded"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 10H11a8 8 0 0 0-8 8v2M21 10l-6-6M21 10l-6 6"/></svg></button>
            </div>
          </div>

          <div className="flex flex-col gap-2">
            {!isCalibrated ? (
              <button onClick={startCalibration} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold hover:bg-selection-light transition-all uppercase shadow-sm">INITIALIZE ENGINE</button>
            ) : (
              <div className="flex flex-col gap-2">
                <button onClick={() => setPivotOffsets({ ...T_POSE })} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold hover:bg-selection-light transition-all uppercase text-center shadow-sm">ALIGN T-POSE</button>
                <button 
                  onClick={() => setPinningMode(prev => prev === 'rightFoot' ? 'none' : 'rightFoot')} 
                  className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase ${pinningMode === 'rightFoot' ? 'bg-accent-purple text-paper border-accent-purple' : 'bg-paper/10 border-ridge text-mono-light hover:border-selection'}`}
                >
                  {pinningMode === 'rightFoot' ? 'FOOT PINNED' : 'PIN RIGHT FOOT'}
                </button>
                <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border transition-all ${showPivots ? 'bg-selection text-paper border-selection' : 'bg-paper/10 border-ridge'}`}>ANCHORS: {showPivots ? 'ON' : 'OFF'}</button>
              </div>
            )}
          </div>

          <div className="flex border-b border-ridge">
            {(['pose', 'props', 'library'] as const).map(tab => (
              <button key={tab} onClick={() => setActiveControlTab(tab)} className={`flex-1 text-[9px] py-2 font-bold ${activeControlTab === tab ? 'bg-mono-dark text-selection border-b-2 border-selection' : 'opacity-40 hover:opacity-100'}`}>{tab.toUpperCase()}</button>
            ))}
          </div>

          <div className="flex-grow flex flex-col min-h-0">
            {activeControlTab === 'pose' && (
              <div className="flex flex-col gap-4 overflow-hidden">
                <div className="text-[8px] font-bold text-mono-light uppercase border-b border-ridge pb-1">Skeletal Rotations</div>
                <div className="flex flex-col gap-2 overflow-y-auto custom-scrollbar pr-2">
                  {JOINT_KEYS.map(k => (
                    <div key={k} className="group">
                      <div className="flex justify-between text-[8px] uppercase font-bold text-mono-light"><span>{k.replace(/_/g, ' ')}</span><span>{Math.round(pivotOffsets[k])}°</span></div>
                      <input type="range" min="-180" max="180" value={pivotOffsets[k]} onChange={(e) => setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))} className="w-full accent-selection h-1 cursor-ew-resize" />
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeControlTab === 'props' && (
              <div className="flex flex-col gap-4 overflow-hidden">
                <div className="text-[8px] font-bold text-mono-light uppercase border-b border-ridge pb-1 flex justify-between items-center"><span>Anatomical Resizing</span><button onClick={() => setProps(Object.fromEntries(PROP_KEYS.map(k => [k, { w: 1, h: 1 }])) as any)} className="text-[7px] text-selection hover:underline">RESET</button></div>
                <div className="flex flex-col gap-4 overflow-y-auto custom-scrollbar pr-2">
                  {PROP_KEYS.map(k => (
                    <div key={k} className="p-2 border border-ridge/50 rounded bg-white/30 space-y-2">
                      <div className="text-[8px] font-bold uppercase">{k.replace(/_/g, ' ')}</div>
                      <div className="space-y-1"><div className="flex justify-between text-[7px] text-mono-light uppercase"><span>Height</span><span>{props[k].h.toFixed(2)}x</span></div><input type="range" min="0.2" max="3" step="0.01" value={props[k].h} onChange={e => updateProp(k, 'h', parseFloat(e.target.value))} className="w-full h-1 accent-mono-mid" /></div>
                      <div className="space-y-1"><div className="flex justify-between text-[7px] text-mono-light uppercase"><span>Width</span><span>{props[k].w.toFixed(2)}x</span></div><input type="range" min="0.2" max="3" step="0.01" value={props[k].w} onChange={e => updateProp(k, 'w', parseFloat(e.target.value))} className="w-full h-1 accent-mono-mid" /></div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeControlTab === 'library' && (
              <div className="flex flex-col h-full gap-4 overflow-hidden">
                <div className="flex flex-col gap-2 min-h-0 flex-1">
                  <div className="text-[8px] font-bold text-mono-light uppercase border-b border-ridge pb-1">Pose Library</div>

                  {/* Tween Config UI */}
                  <div className="flex flex-col gap-2 p-2 bg-white/20 rounded border border-ridge/50 mb-2">
                    <div className="text-[7px] font-bold uppercase text-mono-light tracking-widest">Tween Settings</div>
                    <div className="flex gap-2">
                      <div className="flex-1">
                        <div className="text-[6px] uppercase opacity-60">Duration (ms)</div>
                        <input 
                          type="number" 
                          value={tweenDuration} 
                          onChange={e => setTweenDuration(parseInt(e.target.value) || 100)} 
                          className="w-full bg-mono-dark border border-ridge text-[9px] p-1 rounded-sm focus:outline-none focus:border-selection"
                        />
                      </div>
                      <div className="flex-1">
                        <div className="text-[6px] uppercase opacity-60">Easing</div>
                        <select 
                          value={tweenEasing} 
                          onChange={e => setTweenEasing(e.target.value as any)}
                          className="w-full bg-mono-dark border border-ridge text-[9px] p-1 rounded-sm focus:outline-none"
                        >
                          <option value="linear">Linear</option>
                          <option value="easeInOutQuad">Ease In Out</option>
                          <option value="snapOut">Snap Out</option>
                        </select>
                      </div>
                    </div>
                  </div>

                  <div className="flex flex-col gap-2 overflow-y-auto custom-scrollbar pr-2">
                    {savedPoses.length === 0 ? <div className="text-mono-light italic text-center py-8 text-[9px] bg-white/20 rounded border border-dashed border-ridge">Empty library.</div> : 
                      [...savedPoses].reverse().map(pe => (
                        <div key={pe.id} className="flex items-center justify-between p-2 border border-ridge/50 rounded bg-white/40 hover:bg-white/60 transition-colors group">
                          <div className="flex items-center gap-2"><PoseThumbnail entry={pe} size={32} /><span className="text-[9px] text-ink font-bold truncate max-w-[80px]">{pe.name}</span></div>
                          <div className="flex gap-1 opacity-0 group-hover:opacity-100">
                            <button onClick={() => loadPoseFromLibrary(pe)} className="text-[8px] px-2 py-1 bg-selection text-paper rounded hover:bg-selection-light">Load</button>
                            <button onClick={() => runTween(pe)} className="text-[8px] px-2 py-1 bg-mono-mid text-paper rounded hover:bg-ink">Tween</button>
                          </div>
                        </div>
                      ))
                    }
                  </div>
                </div>
                <div className="pt-2 shrink-0 relative">
                  <button 
                    onClick={saveCurrentPose} 
                    className={`w-full text-[10px] px-4 py-4 border font-bold transition-all uppercase shadow-lg tracking-widest ${saveConfirmation ? 'bg-accent-green text-paper border-accent-green' : 'bg-selection text-paper border-selection hover:bg-selection-light'}`}
                  >
                    {saveConfirmation ? '✓ POSE SAVED' : 'SAVE POSE'}
                  </button>
                </div>
              </div>
            )}
          </div>

          <div className="mt-4 shrink-0"><SystemLogger logs={systemLogs} isVisible={true} onPlayTimelapse={playTimelapse} historyCount={recordingHistory.length} /></div>
        </div>
      )}

      <div className={`flex-1 relative flex items-center justify-center bg-paper p-8 overflow-hidden transition-all duration-500 ${!isCalibrated && !isCalibrating ? 'cursor-pointer' : ''}`} onClick={() => !isCalibrated && !isCalibrating && startCalibration()}>
        <div 
          className="absolute top-4 right-4 z-50 text-right cursor-pointer hover:scale-105 active:scale-95 transition-transform"
          onClick={(e) => { e.stopPropagation(); setIsShopOpen(true); }}
        >
          <div className="text-[12px] font-archaic tracking-widest text-ink/70 uppercase">Unit Tokens:</div>
          <div className="text-2xl font-archaic text-ink tracking-[0.1em]">{tokens.toLocaleString()}</div>
        </div>

        <button onClick={(e) => { e.stopPropagation(); setIsConsoleVisible(!isConsoleVisible); }} disabled={!isCalibrated} className={`absolute top-4 left-4 z-50 p-2 rounded-full border bg-white shadow-lg ${!isCalibrated ? 'opacity-30' : 'hover:scale-110'}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={isConsoleVisible ? "M6 18L18 6M6 6l12 12" : "M4 6h16M4 12h16M4 18h16"} /></svg></button>

        {!isCalibrated && !isCalibrating && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center bg-paper/20 pointer-events-none animate-in fade-in duration-1000 uppercase">
            <h2 className="text-7xl font-archaic text-ink tracking-tighter text-center">Bitruvian Engine</h2>
            <p className="text-[10px] text-mono-light font-mono tracking-[0.8em] animate-pulse">Touch to Initialize</p>
          </div>
        )}

        <svg viewBox="-500 -700 1000 1400" className="w-full h-full drop-shadow-2xl overflow-visible relative z-10">
          <g transform={`translate(${pinOffset.x}, ${-50 + pinOffset.y})`}>
            <Mannequin pose={RESTING_BASE_POSE} pivotOffsets={{...pivotOffsets, l_hand_flash: lHandFlash, r_hand_flash: rHandFlash} as any} props={props} showPivots={showPivots && isCalibrated} showLabels={showLabels} baseUnitH={baseH} onAnchorMouseDown={(k, x) => { if (!isCalibrated || isPlayingTimelapse || isTweening) return; setDraggingBoneKey(k); dragStartXRef.current = x; dragStartPivotOffsetRef.current = pivotOffsets[k]; }} draggingBoneKey={draggingBoneKey} isPaused={true} pinningMode={pinningMode} offset={pinOffset} />
          </g>

          {anomaly && (
            <g transform={`translate(${anomaly.x}, ${anomaly.y})`}>
              <rect x={-anomalySize / 2} y={-anomalySize / 2} width={anomalySize} height={anomalySize} className="fill-ink hover:fill-accent-red cursor-crosshair transition-colors" onClick={handleAnomalyClick} />
            </g>
          )}
        </svg>

        {showTutorial && (
          <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-[320px] bg-selection text-paper p-4 shadow-2xl border border-ridge/30 animate-in slide-in-from-bottom-12 duration-500 z-[200] rounded-sm">
            <div className="flex justify-between items-start mb-2 border-b border-paper/20 pb-1">
              <span className="text-[10px] font-archaic tracking-widest uppercase">System Advisory</span>
              <button onClick={() => setShowTutorial(false)} className="text-[12px] opacity-60 hover:opacity-100">✕</button>
            </div>
            <p className="text-[11px] font-mono leading-relaxed opacity-90 uppercase">
              Congratulations, you earned a token. Touch the <span className="underline">Tokens</span> and buy a prize.
            </p>
            <button onClick={() => setShowTutorial(false)} className="mt-3 w-full border border-paper/40 py-1 text-[9px] hover:bg-paper hover:text-selection transition-colors uppercase font-bold">Dismiss Advisory</button>
          </div>
        )}

        {isShopOpen && (
          <div className="fixed inset-0 bg-ink/80 flex items-center justify-center z-[300] animate-in fade-in duration-300 backdrop-blur-sm" onClick={() => setIsShopOpen(false)}>
            <div className="w-[400px] bg-paper p-6 border-4 border-double border-ridge shadow-2xl animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center border-b-2 border-ridge mb-4 pb-2">
                <h2 className="text-3xl font-archaic tracking-tighter uppercase italic">Prize Vault</h2>
                <div className="flex flex-col items-end">
                   <span className="text-[10px] text-mono-mid uppercase">Current Balance</span>
                   <span className="text-xl font-archaic text-selection">{tokens} TOKENS</span>
                </div>
              </div>
              <div className="space-y-3 overflow-y-auto max-h-[300px] pr-2 custom-scrollbar">
                {[
                  { name: "Silver Plating", cost: 1, desc: "A sleek reflective finish for the core." },
                  { name: "Golden Anchors", cost: 5, desc: "Premium gilded skeletal pivot points." },
                  { name: "Void Processor", cost: 10, desc: "High-density black matte anatomical shell." },
                  { name: "Neon Leak", cost: 25, desc: "Active luminescence within limb joints." }
                ].map(prize => (
                  <div key={prize.name} className={`p-3 border rounded-sm flex flex-col gap-1 transition-all ${purchasedPrizes.includes(prize.name) ? 'bg-selection/10 border-selection' : 'border-ridge hover:border-selection cursor-pointer'}`}>
                    <div className="flex justify-between items-center">
                      <span className="text-[14px] font-bold uppercase tracking-tight">{prize.name}</span>
                      {purchasedPrizes.includes(prize.name) ? (
                        <span className="text-[10px] bg-accent-green/20 text-ink px-2 py-0.5 rounded-full font-bold uppercase">OWNED</span>
                      ) : (
                        <button 
                          onClick={() => buyPrize(prize.name, prize.cost)}
                          className="text-[10px] bg-selection text-paper px-3 py-1 font-bold hover:bg-selection-light active:scale-95 uppercase"
                        >
                          {prize.cost} TK
                        </button>
                      )}
                    </div>
                    <p className="text-[9px] text-mono-mid uppercase leading-tight">{prize.desc}</p>
                  </div>
                ))}
              </div>
              <button onClick={() => setIsShopOpen(false)} className="mt-6 w-full border-2 border-ridge py-2 text-[11px] font-bold uppercase hover:bg-mono-darker transition-colors tracking-widest">Close Vault</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { WalkingEnginePose, WalkingEnginePivotOffsets, WalkingEngineProportions, Vector2D, MaskTransform } from './types';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from './constants'; 
import { Mannequin } from './components/Mannequin';
import { SystemLogger } from './components/SystemLogger';

const T_POSE: WalkingEnginePivotOffsets = {
  waist: 0, neck: 0, collar: 0, torso: 0,
  l_shoulder: 0, r_shoulder: 0,
  l_elbow: 0, r_elbow: 0,
  l_hand: 0, r_hand: 0,
  l_hip: 0, r_hip: 0,
  l_knee: 0, r_knee: 0,
  l_foot: 0, r_foot: 0,
  l_toe: 0, r_toe: 0
};

const INITIAL_CHALLENGE_POSE: WalkingEnginePivotOffsets = {
  waist: 180, torso: 180, collar: 0, neck: 180,
  l_shoulder: -95, l_elbow: 180, l_hand: 180,
  r_shoulder: 95, r_elbow: 180, r_hand: 180,
  l_hip: 5, l_knee: 180, l_foot: 180, l_toe: 180,
  r_hip: -5, r_knee: 180, r_foot: 180, r_toe: 180
};

const RESTING_BASE_POSE: WalkingEnginePose = {
  waist: 0, neck: 0, collar: 0, torso: 0, 
  l_shoulder: 0, r_shoulder: 0, l_elbow: 0, r_elbow: 0, l_hand: 0, r_hand: 0, 
  l_hip: 0, r_hip: 0, l_knee: 0, r_knee: 0, l_foot: 0, r_foot: 0, l_toe: 0, r_toe: 0, 
  stride_phase: 0, y_offset: 0, x_offset: 0
};

const JOINT_KEYS: (keyof WalkingEnginePivotOffsets)[] = [
  'waist', 'torso', 'collar', 'neck',
  'l_shoulder', 'l_elbow', 'l_hand',
  'r_shoulder', 'r_elbow', 'r_hand',
  'l_hip', 'l_knee', 'l_foot', 'l_toe',
  'r_hip', 'r_knee', 'r_foot', 'r_toe'
];

const PROP_KEYS: (keyof WalkingEngineProportions)[] = [
  'head', 'collar', 'torso', 'waist',
  'l_upper_arm', 'l_lower_arm', 'l_hand',
  'r_upper_arm', 'r_lower_arm', 'r_hand',
  'l_upper_leg', 'l_lower_leg', 'l_foot', 'l_toe',
  'r_upper_leg', 'r_lower_leg', 'r_foot', 'r_toe'
];

// Chain depth for reward scaling (Toes are furthest, Waist is root)
const CHAIN_DEPTH: Record<string, number> = {
  waist: 0,
  torso: 1, collar: 2, neck: 3, head: 3,
  l_shoulder: 3, r_shoulder: 3, l_elbow: 4, r_elbow: 4, l_hand: 5, r_hand: 5,
  l_hip: 1, r_hip: 1, l_knee: 2, r_knee: 2, l_foot: 3, r_foot: 3, l_toe: 6, r_toe: 6
};

const FLOOR_Y = 350; // Stable floor baseline in SVG space

const snapOutEase = (t: number) => {
  const c4 = (2 * Math.PI) / 3;
  return t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

const EASING_FUNCTIONS = {
  linear: (t: number) => t,
  easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
  snapOut: snapOutEase,
};

interface HistoryState {
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  timestamp: number;
  label?: string;
}

interface SavedPoseEntry {
  id: number;
  name: string;
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
}

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [showLabels, setShowLabels] = useState(false);
  const [baseH] = useState(150);
  const [isConsoleVisible, setIsConsoleVisible] = useState(false);
  const [activeControlTab, setActiveControlTab] = useState<'pose' | 'props' | 'library'>('pose');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const [isCalibrated, setIsCalibrated] = useState(false);
  const [isCalibrating, setIsCalibrating] = useState(false);
  const [isPlayingTimelapse, setIsPlayingTimelapse] = useState(false);
  const [tokens, setTokens] = useState(0);
  const [lHandFlash, setLHandFlash] = useState(false);
  const [rHandFlash, setRHandFlash] = useState(false);
  const [saveConfirmation, setSaveConfirmation] = useState(false);

  // Pinning State
  const [pinningMode, setPinningMode] = useState<'none' | 'rightFoot' | 'dual'>('none');
  const [pinOffset, setPinOffset] = useState<Vector2D>({ x: 0, y: 0 });

  // Tween Configuration State
  const [tweenDuration, setTweenDuration] = useState(1000);
  const [tweenEasing, setTweenEasing] = useState<'linear' | 'easeInOutQuad' | 'snapOut'>('easeInOutQuad');
  const [isTweening, setIsTweening] = useState(false);

  // Interaction Tracking
  const lastInteractionTimeRef = useRef(Date.now());
  const draggingBoneKeyRef = useRef<keyof WalkingEnginePivotOffsets | null>(null);

  // Tutorial State
  const [showTutorial, setShowTutorial] = useState(false);
  const [hasCollectedFirstPixel, setHasCollectedFirstPixel] = useState(() => {
    return localStorage.getItem('bitruvian_tutorial_done') === 'true';
  });

  // Shop State
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [purchasedPrizes, setPurchasedPrizes] = useState<string[]>([]);

  // Mask State
  const [maskImage, setMaskImage] = useState<string | null>(null);
  const [maskTransform, setMaskTransform] = useState<MaskTransform>({ x: 0, y: 0, rotation: 0, scale: 1 });

  // Core State
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(INITIAL_CHALLENGE_POSE);
  const [props, setProps] = useState<WalkingEngineProportions>({
    head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 },
    l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 },
    r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 },
    l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 },
    r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 }
  });

  // Pose Library State
  const [savedPoses, setSavedPoses] = useState<SavedPoseEntry[]>([]);

  // Target Anomaly Pixel
  const [anomaly, setAnomaly] = useState<Vector2D | null>(null);
  const anomalyRef = useRef<Vector2D | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [redoStack, setRedoStack] = useState<HistoryState[]>([]);
  const [recordingHistory, setRecordingHistory] = useState<HistoryState[]>([]);

  // Interaction Ref
  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);
  const dragStartXRef = useRef(0);
  const dragStartPivotOffsetRef = useRef(0);
  const isInteractingRef = useRef(false);
  const lastSnapshotTimeRef = useRef(0);

  const addLog = useCallback((message: string) => {
    setSystemLogs(prev => [...prev.slice(-49), { timestamp: new Date().toLocaleTimeString(), message }]);
  }, []);

  useEffect(() => {
    try {
      const storedPoses = localStorage.getItem('bitruvian_library');
      if (storedPoses) {
        const parsed = JSON.parse(storedPoses);
        if (Array.isArray(parsed)) setSavedPoses(parsed);
      }
    } catch (e) { console.error("Error loading library", e); }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('bitruvian_library', JSON.stringify(savedPoses));
    } catch (e) { console.error("Error saving library", e); }
  }, [savedPoses]);

  const recordSnapshot = useCallback((label?: string) => {
    const currentState: HistoryState = {
      pivotOffsets: { ...pivotOffsets },
      props: JSON.parse(JSON.stringify(props)),
      timestamp: Date.now(),
      label
    };
    setRecordingHistory(prev => [...prev, currentState]);
  }, [pivotOffsets, props]);

  const saveToHistory = useCallback(() => {
    const currentState: HistoryState = {
      pivotOffsets: { ...pivotOffsets },
      props: JSON.parse(JSON.stringify(props)),
      timestamp: Date.now()
    };
    setHistory(prev => [...prev.slice(-49), currentState]);
    setRedoStack([]);
  }, [pivotOffsets, props]);

  const anomalySize = useMemo(() => {
    const rawW = ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_FOREARM;
    return rawW * baseH * props.l_lower_arm.w * 0.65;
  }, [baseH, props.l_lower_arm.w]);

  const spawnAnomaly = useCallback(() => {
    const centerX = 0;
    const centerY = -300; 
    const radius = 450; 
    const angle = Math.random() * Math.PI * 2;
    const distance = Math.sqrt(Math.random()) * radius; 
    const newAnom = {
      x: centerX + Math.cos(angle) * distance,
      y: centerY + Math.sin(angle) * distance
    };
    setAnomaly(newAnom);
    anomalyRef.current = newAnom;
  }, []);

  const awardTokens = useCallback((sourceBone: string) => {
    const timeSinceLastInteraction = Date.now() - lastInteractionTimeRef.current;

    // Multipliers
    let passiveMultiplier = (timeSinceLastInteraction > 1500 || isTweening) ? 2 : 1;
    let limbBonus = CHAIN_DEPTH[sourceBone] || 1;

    const gain = Math.floor(limbBonus * passiveMultiplier);

    setTokens(prev => prev + gain);
    addLog(`[SYSTEM]: POSE_PICKUP - UNIT TOKENS UPDATED (+${gain}) ${passiveMultiplier > 1 ? '[PASSIVE BONUS]' : ''} [${sourceBone.toUpperCase()} DEPTH: ${limbBonus}X]`);

    if (!hasCollectedFirstPixel) {
      setHasCollectedFirstPixel(true);
      setShowTutorial(true);
      localStorage.setItem('bitruvian_tutorial_done', 'true');
    }
  }, [hasCollectedFirstPixel, addLog, isTweening]);

  const handleAnomalyResolve = useCallback((side: 'left' | 'right', boneKey: string) => {
    if (!anomalyRef.current) return;
    if (side === 'left') {
      setLHandFlash(true);
      setTimeout(() => setLHandFlash(false), 300);
    } else {
      setRHandFlash(true);
      setTimeout(() => setRHandFlash(false), 300);
    }
    awardTokens(boneKey);
    spawnAnomaly();
  }, [spawnAnomaly, awardTokens]);

  const handleAnomalyClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!anomalyRef.current) return;
    awardTokens('head');
    spawnAnomaly();
  };

  const calculateAnklePos = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);

    const waistRot = getRot('waist');
    const hipRot = waistRot + getRot('r_hip');
    const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg');
    const kneeRot = hipRot + getRot('r_knee');
    const kneePos = addVec({ x: 0, y: -50 }, rotateVec({ x: 0, y: thighLen }, hipRot));
    const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg');
    const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
    return anklePos;
  }, [baseH]);

  const updatePinOffset = useCallback(() => {
    if (pinningMode === 'none') {
        setPinOffset({ x: 0, y: 0 });
        return;
    }
    const anklePos = calculateAnklePos(pivotOffsets, props);
    // Neutralize jump: Waist starts at (0,-50). Floor is at FLOOR_Y. 
    // We want anklePos + finalOffset to equal (0, FLOOR_Y)
    setPinOffset({ x: -anklePos.x, y: FLOOR_Y - anklePos.y });
  }, [pinningMode, pivotOffsets, props, calculateAnklePos]);

  useEffect(() => {
    updatePinOffset();
  }, [updatePinOffset]);

  const checkCollisions = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    if (!anomalyRef.current || !isCalibrated) return;

    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);

    const checkPoint = (pos: Vector2D, boneKey: string) => {
      const dx = pos.x - anomalyRef.current!.x;
      const dy = pos.y - anomalyRef.current!.y;
      const threshold = anomalySize * 3;
      if (dx*dx + dy*dy < threshold * threshold) {
        handleAnomalyResolve(boneKey.startsWith('l') ? 'left' : 'right', boneKey);
        return true;
      }
      return false;
    };

    const waistRot = getRot('waist');
    const waistLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, 'waist');
    const currentRoot = { x: pinOffset.x, y: -50 + pinOffset.y };

    // Toes and Hands
    ['r', 'l'].forEach(side => {
      // Leg chain
      const hipRot = waistRot + getRot(`${side}_hip`);
      const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, `${side}_upper_leg` as any);
      const kneeRot = hipRot + getRot(`${side}_knee`);
      const kneePos = addVec(currentRoot, rotateVec({ x: 0, y: thighLen }, hipRot));
      const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, `${side}_lower_leg` as any);
      const ankleRot = kneeRot + getRot(`${side}_foot`);
      const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
      const footLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, `${side}_foot` as any);
      const toePos = addVec(anklePos, rotateVec({ x: 0, y: footLen }, ankleRot));

      if (checkPoint(anklePos, `${side}_foot`)) return;
      if (checkPoint(toePos, `${side}_toe`)) return;

      // Arm chain
      const torsoRot = waistRot + getRot('torso');
      const torsoLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, 'torso');
      const collarRot = torsoRot + getRot('collar');
      const collarLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, 'collar');
      const collarEnd = addVec(addVec(currentRoot, rotateVec({ x: 0, y: -waistLen }, waistRot)), rotateVec({ x: 0, y: -torsoLen }, torsoRot));
      const sx = (side === 'r' ? RIGGING.R_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER : RIGGING.L_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER) * baseH;
      const baseShoulderRot = side === 'l' ? 90 : -90;
      const shRot = collarRot + baseShoulderRot + getRot(`${side}_shoulder`);
      const shPos = addVec(addVec(collarEnd, rotateVec({ x: 0, y: -collarLen }, collarRot)), rotateVec({ x: sx, y: 0 }, collarRot));
      const upLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, `${side}_upper_arm` as any);
      const elRot = shRot + getRot(`${side}_elbow`);
      const elPos = addVec(shPos, rotateVec({ x: 0, y: upLen }, shRot));
      const lowLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, `${side}_lower_arm` as any);
      const wristPos = addVec(elPos, rotateVec({ x: 0, y: lowLen }, elRot));

      checkPoint(wristPos, `${side}_hand`);
    });

  }, [anomalySize, handleAnomalyResolve, isCalibrated, baseH, pinOffset]);

  useEffect(() => {
    if (!anomaly || !isCalibrated) return;
    const interval = setInterval(() => checkCollisions(pivotOffsets, props), 32);
    return () => clearInterval(interval);
  }, [anomaly, isCalibrated, pivotOffsets, props, checkCollisions]);

  const undo = useCallback(() => {
    if (history.length === 0 || isPlayingTimelapse || isTweening) return;
    const previous = history[history.length - 1];
    setRedoStack(prev => [{ pivotOffsets: { ...pivotOffsets }, props: JSON.parse(JSON.stringify(props)), timestamp: Date.now() }, ...prev]);
    setHistory(prev => prev.slice(0, -1));
    setPivotOffsets(previous.pivotOffsets);
    setProps(previous.props);
  }, [history, pivotOffsets, props, isPlayingTimelapse, isTweening]);

  const redo = useCallback(() => {
    if (redoStack.length === 0 || isPlayingTimelapse || isTweening) return;
    const next = redoStack[0];
    setHistory(prev => [...prev, { pivotOffsets: { ...pivotOffsets }, props: JSON.parse(JSON.stringify(props)), timestamp: Date.now() }]);
    setRedoStack(prev => prev.slice(1));
    setPivotOffsets(next.pivotOffsets);
    setProps(next.props);
  }, [redoStack, pivotOffsets, props, isPlayingTimelapse, isTweening]);

  useEffect(() => {
    const hk = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'z') { if (e.shiftKey) redo(); else undo(); }
      else if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'y') redo();
    };
    window.addEventListener('keydown', hk);
    return () => window.removeEventListener('keydown', hk);
  }, [undo, redo]);

  const startCalibration = useCallback(() => {
    if (isCalibrated || isCalibrating || isPlayingTimelapse || isTweening) return;
    setIsCalibrating(true);
    const duration = 250;
    const startTime = performance.now();
    const startPose = { ...pivotOffsets };
    const animate = (now: number) => {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const easedProgress = snapOutEase(progress);
      const nextPose = { ...startPose };
      JOINT_KEYS.forEach(k => { nextPose[k] = startPose[k] + (T_POSE[k] - startPose[k]) * easedProgress; });
      setPivotOffsets(nextPose);
      if (progress < 1) requestAnimationFrame(animate);
      else {
        setIsCalibrating(false);
        setIsCalibrated(true);
        setIsConsoleVisible(true);
        spawnAnomaly();
      }
    };
    requestAnimationFrame(animate);
  }, [isCalibrated, isCalibrating, pivotOffsets, isPlayingTimelapse, isTweening, spawnAnomaly]);

  const handleDrag = useCallback((e: MouseEvent) => {
    if (draggingBoneKey && !isPlayingTimelapse && !isTweening) {
      lastInteractionTimeRef.current = Date.now();
      if (!isInteractingRef.current) { saveToHistory(); isInteractingRef.current = true; }
      const delta = (e.clientX - dragStartXRef.current) * 0.5;
      const nextOffsets = { ...pivotOffsets, [draggingBoneKey]: dragStartPivotOffsetRef.current + delta };
      setPivotOffsets(nextOffsets);
      const now = Date.now();
      if (now - lastSnapshotTimeRef.current > 60) { recordSnapshot(`DRAG_${draggingBoneKey}`); lastSnapshotTimeRef.current = now; }
    }
  }, [draggingBoneKey, saveToHistory, isPlayingTimelapse, isTweening, recordSnapshot, pivotOffsets]);

  useEffect(() => {
    const hu = () => { if (draggingBoneKey) recordSnapshot(`END_DRAG_${draggingBoneKey}`); setDraggingBoneKey(null); draggingBoneKeyRef.current = null; isInteractingRef.current = false; };
    if (draggingBoneKey) { 
      draggingBoneKeyRef.current = draggingBoneKey;
      window.addEventListener('mousemove', handleDrag); 
      window.addEventListener('mouseup', hu); 
    }
    return () => { window.removeEventListener('mousemove', handleDrag); window.removeEventListener('mouseup', hu); };
  }, [draggingBoneKey, handleDrag, recordSnapshot]);

  const updateProp = (key: keyof WalkingEngineProportions, axis: 'w' | 'h', val: number) => {
    if (isPlayingTimelapse || isTweening) return;
    setProps(p => ({ ...p, [key]: { ...p[key], [axis]: val } }));
  };

  const saveCurrentPose = useCallback(() => {
    if (isPlayingTimelapse || isTweening) return;
    const defaultName = `Pose ${savedPoses.length + 1}`;
    const n = window.prompt("Name this pose:", defaultName);

    if (n !== null) {
      const finalName = n.trim() || defaultName;
      const newEntry: SavedPoseEntry = { 
        id: Date.now(), 
        name: finalName, 
        pivotOffsets: { ...pivotOffsets }, 
        props: JSON.parse(JSON.stringify(props)) 
      };
      setSavedPoses(prev => [...prev, newEntry]);
      setSaveConfirmation(true);
      setTimeout(() => setSaveConfirmation(false), 2000);
      addLog(`[SYSTEM]: POSE_SAVED_SUCCESSFULLY - "${finalName.toUpperCase()}"`);
    }
  }, [pivotOffsets, props, savedPoses.length, isPlayingTimelapse, isTweening, addLog]);

  const loadPoseFromLibrary = useCallback((p: SavedPoseEntry) => {
    if (isPlayingTimelapse || isTweening) return;
    saveToHistory(); setPivotOffsets({ ...p.pivotOffsets }); setProps(JSON.parse(JSON.stringify(p.props))); recordSnapshot(`LOAD_${p.name.toUpperCase()}`);
  }, [saveToHistory, isPlayingTimelapse, isTweening, recordSnapshot]);

  const runTween = useCallback((target: SavedPoseEntry) => {
    if (isTweening || isPlayingTimelapse || isCalibrating) return;
    saveToHistory();
    setIsTweening(true);
    addLog(`SYSTEM: TWEENING TO "${target.name.toUpperCase()}"...`);

    const startPose = { ...pivotOffsets };
    const startProps = JSON.parse(JSON.stringify(props));
    const startTime = performance.now();
    const easeFn = EASING_FUNCTIONS[tweenEasing];

    const animate = (now: number) => {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / tweenDuration, 1);
      const eased = easeFn(progress);

      const nextPose = { ...pivotOffsets };
      JOINT_KEYS.forEach(k => {
        nextPose[k] = startPose[k] + (target.pivotOffsets[k] - startPose[k]) * eased;
      });

      const nextProps = JSON.parse(JSON.stringify(props));
      PROP_KEYS.forEach(k => {
        nextProps[k] = {
          w: startProps[k].w + (target.props[k].w - startProps[k].w) * eased,
          h: startProps[k].h + (target.props[k].h - startProps[k].h) * eased
        };
      });

      setPivotOffsets(nextPose);
      setProps(nextProps);

      if (progress < 1) {
        requestAnimationFrame(animate);
      } else {
        setIsTweening(false);
        addLog(`SYSTEM: TWEEN TO "${target.name.toUpperCase()}" COMPLETE.`);
        recordSnapshot(`TWEEN_END_${target.name.toUpperCase()}`);
      }
    };

    requestAnimationFrame(animate);
  }, [isTweening, isPlayingTimelapse, isCalibrating, pivotOffsets, props, tweenDuration, tweenEasing, saveToHistory, addLog, recordSnapshot]);

  const playTimelapse = useCallback(() => {
    if (recordingHistory.length < 2 || isPlayingTimelapse || isTweening) return;
    setIsPlayingTimelapse(true);
    const STEP = 250; 
    const total = (recordingHistory.length - 1) * STEP;
    const start = performance.now();
    const frame = (now: number) => {
      const elapsed = now - start;
      const progress = Math.min(elapsed / total, 1);
      const exactIndex = progress * (recordingHistory.length - 1);
      const i = Math.min(Math.floor(exactIndex), recordingHistory.length - 2);
      const u = exactIndex - i;
      const sState = recordingHistory[i];
      const eState = recordingHistory[i + 1];
      const nPivot: any = {}; JOINT_KEYS.forEach(k => { nPivot[k] = sState.pivotOffsets[k] + (eState.pivotOffsets[k] - sState.pivotOffsets[k]) * u; });
      const nProps: any = {}; PROP_KEYS.forEach(k => { nProps[k] = { w: sState.props[k].w + (eState.props[k].w - sState.props[k].w) * u, h: sState.props[k].h + (eState.props[k].h - sState.props[k].h) * u }; });
      setPivotOffsets(nPivot); setProps(nProps);
      if (progress < 1) requestAnimationFrame(frame);
      else setIsPlayingTimelapse(false);
    };
    requestAnimationFrame(frame);
  }, [recordingHistory, isPlayingTimelapse, isTweening]);

  const PoseThumbnail = ({ entry, size = 64 }: { entry: SavedPoseEntry, size?: number }) => (
    <svg viewBox="-300 -600 600 1200" width={size} height={size} className="bg-paper/40 rounded border border-ridge/50 pointer-events-none overflow-visible">
       <Mannequin pose={RESTING_BASE_POSE} pivotOffsets={entry.pivotOffsets as any} props={entry.props} showPivots={false} showLabels={false} baseUnitH={size * 0.4} onAnchorMouseDown={() => {}} draggingBoneKey={null} isPaused={true} pinningMode="none" offset={{x:0, y:0}} />
    </svg>
  );

  const buyPrize = (prizeName: string, cost: number) => {
    if (tokens >= cost) {
      setTokens(t => t - cost);
      setPurchasedPrizes(p => [...p, prizeName]);
      addLog(`SHOP: PURCHASED ${prizeName.toUpperCase()}.`);
    } else {
      addLog(`SHOP: INSUFFICIENT TOKENS FOR ${prizeName.toUpperCase()}.`);
    }
  };

  return (
    <div className="flex h-full w-full bg-paper font-mono text-ink overflow-hidden select-none">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto z-50 shadow-2xl">
          <div className="flex justify-between items-center border-b border-ridge pb-2">
            <h1 className="text-xl font-archaic tracking-widest text-ink uppercase italic">Bitruvius.Core</h1>
            <div className="flex gap-1">
              <button onClick={undo} disabled={history.length === 0 || isTweening} className="p-1 hover:bg-selection-super-light disabled:opacity-20 rounded"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M3 10h10a8 8 0 0 1 8 8v2M3 10l6-6M3 10l6 6"/></svg></button>
              <button onClick={redo} disabled={redoStack.length === 0 || isTweening} className="p-1 hover:bg-selection-super-light disabled:opacity-20 rounded"><svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 10H11a8 8 0 0 0-8 8v2M21 10l-6-6M21 10l-6 6"/></svg></button>
            </div>
          </div>

          <div className="flex flex-col gap-2">
            {!isCalibrated ? (
              <button onClick={startCalibration} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold hover:bg-selection-light transition-all uppercase shadow-sm">INITIALIZE ENGINE</button>
            ) : (
              <div className="flex flex-col gap-2">
                <button onClick={() => setPivotOffsets({ ...T_POSE })} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold hover:bg-selection-light transition-all uppercase text-center shadow-sm">ALIGN T-POSE</button>
                <button 
                  onClick={() => setPinningMode(prev => prev === 'rightFoot' ? 'none' : 'rightFoot')} 
                  className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase ${pinningMode === 'rightFoot' ? 'bg-accent-purple text-paper border-accent-purple' : 'bg-paper/10 border-ridge text-mono-light hover:border-selection'}`}
                >
                  {pinningMode === 'rightFoot' ? 'FOOT PINNED' : 'PIN RIGHT FOOT'}
                </button>
                <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border transition-all ${showPivots ? 'bg-selection text-paper border-selection' : 'bg-paper/10 border-ridge'}`}>ANCHORS: {showPivots ? 'ON' : 'OFF'}</button>
              </div>
            )}
          </div>

          <div className="flex border-b border-ridge">
            {(['pose', 'props', 'library'] as const).map(tab => (
              <button key={tab} onClick={() => setActiveControlTab(tab)} className={`flex-1 text-[9px] py-2 font-bold ${activeControlTab === tab ? 'bg-mono-dark text-selection border-b-2 border-selection' : 'opacity-40 hover:opacity-100'}`}>{tab.toUpperCase()}</button>
            ))}
          </div>

          <div className="flex-grow flex flex-col min-h-0">
            {activeControlTab === 'pose' && (
              <div className="flex flex-col gap-4 overflow-hidden">
                <div className="text-[8px] font-bold text-mono-light uppercase border-b border-ridge pb-1">Skeletal Rotations</div>
                <div className="flex flex-col gap-2 overflow-y-auto custom-scrollbar pr-2">
                  {JOINT_KEYS.map(k => (
                    <div key={k} className="group">
                      <div className="flex justify-between text-[8px] uppercase font-bold text-mono-light"><span>{k.replace(/_/g, ' ')}</span><span>{Math.round(pivotOffsets[k])}°</span></div>
                      <input type="range" min="-180" max="180" value={pivotOffsets[k]} onChange={(e) => setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))} className="w-full accent-selection h-1 cursor-ew-resize" />
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeControlTab === 'props' && (
              <div className="flex flex-col gap-4 overflow-hidden">
                <div className="text-[8px] font-bold text-mono-light uppercase border-b border-ridge pb-1 flex justify-between items-center"><span>Anatomical Resizing</span><button onClick={() => setProps(Object.fromEntries(PROP_KEYS.map(k => [k, { w: 1, h: 1 }])) as any)} className="text-[7px] text-selection hover:underline">RESET</button></div>
                <div className="flex flex-col gap-4 overflow-y-auto custom-scrollbar pr-2">
                  {PROP_KEYS.map(k => (
                    <div key={k} className="p-2 border border-ridge/50 rounded bg-white/30 space-y-2">
                      <div className="text-[8px] font-bold uppercase">{k.replace(/_/g, ' ')}</div>
                      <div className="space-y-1"><div className="flex justify-between text-[7px] text-mono-light uppercase"><span>Height</span><span>{props[k].h.toFixed(2)}x</span></div><input type="range" min="0.2" max="3" step="0.01" value={props[k].h} onChange={e => updateProp(k, 'h', parseFloat(e.target.value))} className="w-full h-1 accent-mono-mid" /></div>
                      <div className="space-y-1"><div className="flex justify-between text-[7px] text-mono-light uppercase"><span>Width</span><span>{props[k].w.toFixed(2)}x</span></div><input type="range" min="0.2" max="3" step="0.01" value={props[k].w} onChange={e => updateProp(k, 'w', parseFloat(e.target.value))} className="w-full h-1 accent-mono-mid" /></div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeControlTab === 'library' && (
              <div className="flex flex-col h-full gap-4 overflow-hidden">
                <div className="flex flex-col gap-2 min-h-0 flex-1">
                  <div className="text-[8px] font-bold text-mono-light uppercase border-b border-ridge pb-1">Pose Library</div>

                  {/* Tween Config UI */}
                  <div className="flex flex-col gap-2 p-2 bg-white/20 rounded border border-ridge/50 mb-2">
                    <div className="text-[7px] font-bold uppercase text-mono-light tracking-widest">Tween Settings</div>
                    <div className="flex gap-2">
                      <div className="flex-1">
                        <div className="text-[6px] uppercase opacity-60">Duration (ms)</div>
                        <input 
                          type="number" 
                          value={tweenDuration} 
                          onChange={e => setTweenDuration(parseInt(e.target.value) || 100)} 
                          className="w-full bg-mono-dark border border-ridge text-[9px] p-1 rounded-sm focus:outline-none focus:border-selection"
                        />
                      </div>
                      <div className="flex-1">
                        <div className="text-[6px] uppercase opacity-60">Easing</div>
                        <select 
                          value={tweenEasing} 
                          onChange={e => setTweenEasing(e.target.value as any)}
                          className="w-full bg-mono-dark border border-ridge text-[9px] p-1 rounded-sm focus:outline-none"
                        >
                          <option value="linear">Linear</option>
                          <option value="easeInOutQuad">Ease In Out</option>
                          <option value="snapOut">Snap Out</option>
                        </select>
                      </div>
                    </div>
                  </div>

                  <div className="flex flex-col gap-2 overflow-y-auto custom-scrollbar pr-2">
                    {savedPoses.length === 0 ? <div className="text-mono-light italic text-center py-8 text-[9px] bg-white/20 rounded border border-dashed border-ridge">Empty library.</div> : 
                      [...savedPoses].reverse().map(pe => (
                        <div key={pe.id} className="flex items-center justify-between p-2 border border-ridge/50 rounded bg-white/40 hover:bg-white/60 transition-colors group">
                          <div className="flex items-center gap-2"><PoseThumbnail entry={pe} size={32} /><span className="text-[9px] text-ink font-bold truncate max-w-[80px]">{pe.name}</span></div>
                          <div className="flex gap-1 opacity-0 group-hover:opacity-100">
                            <button onClick={() => loadPoseFromLibrary(pe)} className="text-[8px] px-2 py-1 bg-selection text-paper rounded hover:bg-selection-light">Load</button>
                            <button onClick={() => runTween(pe)} className="text-[8px] px-2 py-1 bg-mono-mid text-paper rounded hover:bg-ink">Tween</button>
                          </div>
                        </div>
                      ))
                    }
                  </div>
                </div>
                <div className="pt-2 shrink-0 relative">
                  <button 
                    onClick={saveCurrentPose} 
                    className={`w-full text-[10px] px-4 py-4 border font-bold transition-all uppercase shadow-lg tracking-widest ${saveConfirmation ? 'bg-accent-green text-paper border-accent-green' : 'bg-selection text-paper border-selection hover:bg-selection-light'}`}
                  >
                    {saveConfirmation ? '✓ POSE SAVED' : 'SAVE POSE'}
                  </button>
                </div>
              </div>
            )}
          </div>

          <div className="mt-4 shrink-0"><SystemLogger logs={systemLogs} isVisible={true} onPlayTimelapse={playTimelapse} historyCount={recordingHistory.length} /></div>
        </div>
      )}

      <div className={`flex-1 relative flex items-center justify-center bg-paper p-8 overflow-hidden transition-all duration-500 ${!isCalibrated && !isCalibrating ? 'cursor-pointer' : ''}`} onClick={() => !isCalibrated && !isCalibrating && startCalibration()}>
        <div 
          className="absolute top-4 right-4 z-50 text-right cursor-pointer hover:scale-105 active:scale-95 transition-transform"
          onClick={(e) => { e.stopPropagation(); setIsShopOpen(true); }}
        >
          <div className="text-[12px] font-archaic tracking-widest text-ink/70 uppercase">Unit Tokens:</div>
          <div className="text-2xl font-archaic text-ink tracking-[0.1em]">{tokens.toLocaleString()}</div>
        </div>

        <button onClick={(e) => { e.stopPropagation(); setIsConsoleVisible(!isConsoleVisible); }} disabled={!isCalibrated} className={`absolute top-4 left-4 z-50 p-2 rounded-full border bg-white shadow-lg ${!isCalibrated ? 'opacity-30' : 'hover:scale-110'}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={isConsoleVisible ? "M6 18L18 6M6 6l12 12" : "M4 6h16M4 12h16M4 18h16"} /></svg></button>

        {!isCalibrated && !isCalibrating && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center bg-paper/20 pointer-events-none animate-in fade-in duration-1000 uppercase">
            <h2 className="text-7xl font-archaic text-ink tracking-tighter text-center">Bitruvian Engine</h2>
            <p className="text-[10px] text-mono-light font-mono tracking-[0.8em] animate-pulse">Touch to Initialize</p>
          </div>
        )}

        <svg viewBox="-500 -700 1000 1400" className="w-full h-full drop-shadow-2xl overflow-visible relative z-10">
          <g transform={`translate(${pinOffset.x}, ${-50 + pinOffset.y})`}>
            <Mannequin pose={RESTING_BASE_POSE} pivotOffsets={{...pivotOffsets, l_hand_flash: lHandFlash, r_hand_flash: rHandFlash} as any} props={props} showPivots={showPivots && isCalibrated} showLabels={showLabels} baseUnitH={baseH} onAnchorMouseDown={(k, x) => { if (!isCalibrated || isPlayingTimelapse || isTweening) return; setDraggingBoneKey(k); dragStartXRef.current = x; dragStartPivotOffsetRef.current = pivotOffsets[k]; }} draggingBoneKey={draggingBoneKey} isPaused={true} pinningMode={pinningMode} offset={pinOffset} />
          </g>

          {anomaly && (
            <g transform={`translate(${anomaly.x}, ${anomaly.y})`}>
              <rect x={-anomalySize / 2} y={-anomalySize / 2} width={anomalySize} height={anomalySize} className="fill-ink hover:fill-accent-red cursor-crosshair transition-colors" onClick={handleAnomalyClick} />
            </g>
          )}
        </svg>

        {showTutorial && (
          <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-[320px] bg-selection text-paper p-4 shadow-2xl border border-ridge/30 animate-in slide-in-from-bottom-12 duration-500 z-[200] rounded-sm">
            <div className="flex justify-between items-start mb-2 border-b border-paper/20 pb-1">
              <span className="text-[10px] font-archaic tracking-widest uppercase">System Advisory</span>
              <button onClick={() => setShowTutorial(false)} className="text-[12px] opacity-60 hover:opacity-100">✕</button>
            </div>
            <p className="text-[11px] font-mono leading-relaxed opacity-90 uppercase">
              Congratulations, you earned a token. Touch the <span className="underline">Tokens</span> and buy a prize.
            </p>
            <button onClick={() => setShowTutorial(false)} className="mt-3 w-full border border-paper/40 py-1 text-[9px] hover:bg-paper hover:text-selection transition-colors uppercase font-bold">Dismiss Advisory</button>
          </div>
        )}

        {isShopOpen && (
          <div className="fixed inset-0 bg-ink/80 flex items-center justify-center z-[300] animate-in fade-in duration-300 backdrop-blur-sm" onClick={() => setIsShopOpen(false)}>
            <div className="w-[400px] bg-paper p-6 border-4 border-double border-ridge shadow-2xl animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center border-b-2 border-ridge mb-4 pb-2">
                <h2 className="text-3xl font-archaic tracking-tighter uppercase italic">Prize Vault</h2>
                <div className="flex flex-col items-end">
                   <span className="text-[10px] text-mono-mid uppercase">Current Balance</span>
                   <span className="text-xl font-archaic text-selection">{tokens} TOKENS</span>
                </div>
              </div>
              <div className="space-y-3 overflow-y-auto max-h-[300px] pr-2 custom-scrollbar">
                {[
                  { name: "Silver Plating", cost: 1, desc: "A sleek reflective finish for the core." },
                  { name: "Golden Anchors", cost: 5, desc: "Premium gilded skeletal pivot points." },
                  { name: "Void Processor", cost: 10, desc: "High-density black matte anatomical shell." },
                  { name: "Neon Leak", cost: 25, desc: "Active luminescence within limb joints." }
                ].map(prize => (
                  <div key={prize.name} className={`p-3 border rounded-sm flex flex-col gap-1 transition-all ${purchasedPrizes.includes(prize.name) ? 'bg-selection/10 border-selection' : 'border-ridge hover:border-selection cursor-pointer'}`}>
                    <div className="flex justify-between items-center">
                      <span className="text-[14px] font-bold uppercase tracking-tight">{prize.name}</span>
                      {purchasedPrizes.includes(prize.name) ? (
                        <span className="text-[10px] bg-accent-green/20 text-ink px-2 py-0.5 rounded-full font-bold uppercase">OWNED</span>
                      ) : (
                        <button 
                          onClick={() => buyPrize(prize.name, prize.cost)}
                          className="text-[10px] bg-selection text-paper px-3 py-1 font-bold hover:bg-selection-light active:scale-95 uppercase"
                        >
                          {prize.cost} TK
                        </button>
                      )}
                    </div>
                    <p className="text-[9px] text-mono-mid uppercase leading-tight">{prize.desc}</p>
                  </div>
                ))}
              </div>
              <button onClick={() => setIsShopOpen(false)} className="mt-6 w-full border-2 border-ridge py-2 text-[11px] font-bold uppercase hover:bg-mono-darker transition-colors tracking-widest">Close Vault</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { WalkingEnginePose, WalkingEnginePivotOffsets, WalkingEngineProportions, Vector2D, MaskTransform } from './types';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from './constants'; 
import { Mannequin } from './components/Mannequin';
import { SystemLogger } from './components/SystemLogger';

const T_POSE: WalkingEnginePivotOffsets = {
  waist: 0, neck: 0, collar: 0, torso: 0,
  l_shoulder: 0, r_shoulder: 0,
  l_elbow: 0, r_elbow: 0,
  l_hand: 0, r_hand: 0,
  l_hip: 0, r_hip: 0,
  l_knee: 0, r_knee: 0,
  l_foot: 0, r_foot: 0,
  l_toe: 0, r_toe: 0
};

const INITIAL_CHALLENGE_POSE: WalkingEnginePivotOffsets = {
  waist: 180, torso: 180, collar: 0, neck: 180,
  l_shoulder: -95, l_elbow: 180, l_hand: 180,
  r_shoulder: 95, r_elbow: 180, r_hand: 180,
  l_hip: 5, l_knee: 180, l_foot: 180, l_toe: 180,
  r_hip: -5, r_knee: 180, r_foot: 180, r_toe: 180
};

const RESTING_BASE_POSE: WalkingEnginePose = {
  waist: 0, neck: 0, collar: 0, torso: 0, 
  l_shoulder: 0, r_shoulder: 0, l_elbow: 0, r_elbow: 0, l_hand: 0, r_hand: 0, 
  l_hip: 0, r_hip: 0, l_knee: 0, r_knee: 0, l_foot: 0, r_foot: 0, l_toe: 0, r_toe: 0, 
  stride_phase: 0, y_offset: 0, x_offset: 0
};

const JOINT_KEYS: (keyof WalkingEnginePivotOffsets)[] = [
  'waist', 'torso', 'collar', 'neck',
  'l_shoulder', 'l_elbow', 'l_hand',
  'r_shoulder', 'r_elbow', 'r_hand',
  'l_hip', 'l_knee', 'l_foot', 'l_toe',
  'r_hip', 'r_knee', 'r_foot', 'r_toe'
];

const PROP_KEYS: (keyof WalkingEngineProportions)[] = [
  'head', 'collar', 'torso', 'waist',
  'l_upper_arm', 'l_lower_arm', 'l_hand',
  'r_upper_arm', 'r_lower_arm', 'r_hand',
  'l_upper_leg', 'l_lower_leg', 'l_foot', 'l_toe',
  'r_upper_leg', 'r_lower_leg', 'r_foot', 'r_toe'
];

// Chain depth for reward scaling (Toes/Hands are furthest, Waist is root)
const CHAIN_DEPTH: Record<string, number> = {
  waist: 0,
  torso: 1, collar: 2, neck: 3, head: 4,
  l_shoulder: 3, r_shoulder: 3, l_elbow: 4, r_elbow: 4, l_hand: 5, r_hand: 5,
  l_hip: 1, r_hip: 1, l_knee: 2, r_knee: 2, l_foot: 3, r_foot: 3, l_toe: 4, r_toe: 4
};

const snapOutEase = (t: number) => {
  const c4 = (2 * Math.PI) / 3;
  return t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

const EASING_FUNCTIONS = {
  linear: (t: number) => t,
  easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
  snapOut: snapOutEase,
};

interface HistoryState {
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  timestamp: number;
  label?: string;
}

interface SavedPoseEntry {
  id: number;
  name: string;
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
}

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [showLabels, setShowLabels] = useState(false);
  const [baseH] = useState(150);
  const [isConsoleVisible, setIsConsoleVisible] = useState(false);
  const [activeControlTab, setActiveControlTab] = useState<'pose' | 'props' | 'library'>('pose');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const [isCalibrated, setIsCalibrated] = useState(false);
  const [isCalibrating, setIsCalibrating] = useState(false);
  const [isPlayingTimelapse, setIsPlayingTimelapse] = useState(false);
  const [tokens, setTokens] = useState(0);
  const [lHandFlash, setLHandFlash] = useState(false);
  const [rHandFlash, setRHandFlash] = useState(false);
  const [saveConfirmation, setSaveConfirmation] = useState(false);

  // Pinning State
  const [pinningMode, setPinningMode] = useState<'none' | 'rightFoot' | 'dual'>('none');
  const [pinOffset, setPinOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const pinnedWorldPosRef = useRef<Vector2D | null>(null);

  // Tween Configuration State
  const [tweenDuration, setTweenDuration] = useState(1000);
  const [tweenEasing, setTweenEasing] = useState<'linear' | 'easeInOutQuad' | 'snapOut'>('easeInOutQuad');
  const [isTweening, setIsTweening] = useState(false);

  // Interaction Tracking
  const lastInteractionTimeRef = useRef(Date.now());
  const draggingBoneKeyRef = useRef<keyof WalkingEnginePivotOffsets | null>(null);

  // Core State
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(INITIAL_CHALLENGE_POSE);
  const [props, setProps] = useState<WalkingEngineProportions>({
    head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 },
    l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 },
    r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 },
    l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 },
    r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 }
  });

  // Pose Library State
  const [savedPoses, setSavedPoses] = useState<SavedPoseEntry[]>([]);

  // Anomaly State
  const [anomaly, setAnomaly] = useState<Vector2D | null>(null);
  const anomalyRef = useRef<Vector2D | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [redoStack, setRedoStack] = useState<HistoryState[]>([]);
  const [recordingHistory, setRecordingHistory] = useState<HistoryState[]>([]);

  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);
  const dragStartXRef = useRef(0);
  const dragStartPivotOffsetRef = useRef(0);
  const isInteractingRef = useRef(false);
  const lastSnapshotTimeRef = useRef(0);

  const addLog = useCallback((message: string) => {
    setSystemLogs(prev => [...prev.slice(-49), { timestamp: new Date().toLocaleTimeString(), message }]);
  }, []);

  useEffect(() => {
    try {
      const storedPoses = localStorage.getItem('bitruvian_library');
      if (storedPoses) {
        const parsed = JSON.parse(storedPoses);
        if (Array.isArray(parsed)) setSavedPoses(parsed);
      }
    } catch (e) { console.error("Error loading library", e); }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('bitruvian_library', JSON.stringify(savedPoses));
    } catch (e) { console.error("Error saving library", e); }
  }, [savedPoses]);

  const awardTokens = useCallback((sourceBone: string) => {
    const timeSinceLastInteraction = Date.now() - lastInteractionTimeRef.current;

    // Passive multiplier for collections made via tweens or gravity (indirect movement)
    let passiveMultiplier = (timeSinceLastInteraction > 1500 || isTweening) ? 2 : 1;

    // Distance bonus: Difference in skeletal depth between controlled joint and collecting joint
    let distanceBonus = 1;
    if (draggingBoneKeyRef.current) {
      const depthDrag = CHAIN_DEPTH[draggingBoneKeyRef.current] || 0;
      const depthCollect = CHAIN_DEPTH[sourceBone] || 0;
      distanceBonus = 1 + Math.abs(depthDrag - depthCollect);
    }

    const gain = Math.floor(distanceBonus * passiveMultiplier);
    setTokens(prev => prev + gain);
    addLog(`[SYSTEM]: POSE_PICKUP - UNIT TOKENS UPDATED (+${gain}) ${passiveMultiplier > 1 ? '[PASSIVE BONUS]' : ''} [${sourceBone.toUpperCase()} CHAIN BONUS: ${distanceBonus}X]`);
  }, [addLog, isTweening]);

  const handleAnomalyResolve = useCallback((side: 'left' | 'right', boneKey: string) => {
    if (!anomalyRef.current) return;
    if (side === 'left') {
      setLHandFlash(true);
      setTimeout(() => setLHandFlash(false), 300);
    } else {
      setRHandFlash(true);
      setTimeout(() => setRHandFlash(false), 300);
    }
    awardTokens(boneKey);
    spawnAnomaly();
  }, [awardTokens]);

  const spawnAnomaly = useCallback(() => {
    const angle = Math.random() * Math.PI * 2;
    const distance = 150 + Math.random() * 350;
    const newAnom = {
      x: Math.cos(angle) * distance,
      y: -250 + Math.sin(angle) * distance
    };
    setAnomaly(newAnom);
    anomalyRef.current = newAnom;
  }, []);

  const calculateAnklePos = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);

    const waistRot = getRot('waist');
    const hipRot = waistRot + getRot('r_hip');
    const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg');
    const kneeRot = hipRot + getRot('r_knee');
    const kneePos = rotateVec({ x: 0, y: thighLen }, hipRot);
    const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg');
    const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
    return anklePos;
  }, [baseH]);

  const togglePinning = useCallback(() => {
    if (pinningMode === 'none') {
      const local = calculateAnklePos(pivotOffsets, props);
      pinnedWorldPosRef.current = {
        x: local.x + pinOffset.x,
        y: local.y - 50 + pinOffset.y
      };
      setPinningMode('rightFoot');
      addLog(`[SYSTEM]: PINNING ENABLED - RIGHT ANKLE ANCHORED.`);
    } else {
      setPinningMode('none');
      pinnedWorldPosRef.current = null;
      setPinOffset({ x: 0, y: 0 });
      addLog(`[SYSTEM]: PINNING DISABLED.`);
    }
  }, [pinningMode, calculateAnklePos, pivotOffsets, props, pinOffset, addLog]);

  const updatePinOffset = useCallback(() => {
    if (pinningMode === 'none' || !pinnedWorldPosRef.current) return;

    const currentLocal = calculateAnklePos(pivotOffsets, props);

    // We want currentLocal + {newPinOffset.x, -50 + newPinOffset.y} = pinnedWorldPosRef.current
    const nextX = pinnedWorldPosRef.current.x - currentLocal.x;
    const nextY = pinnedWorldPosRef.current.y - currentLocal.y + 50;

    setPinOffset({ x: nextX, y: nextY });
  }, [pinningMode, calculateAnklePos, pivotOffsets, props]);

  useEffect(() => {
    if (pinningMode !== 'none') updatePinOffset();
  }, [pivotOffsets, props, updatePinOffset]);

  const checkCollisions = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    if (!anomalyRef.current || !isCalibrated) return;

    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);
    const threshold = anomalySize * 3;

    const checkPoint = (pos: Vector2D, boneKey: string) => {
      const dx = pos.x - anomalyRef.current!.x;
      const dy = pos.y - anomalyRef.current!.y;
      if (dx*dx + dy*dy < threshold * threshold) {
        handleAnomalyResolve(boneKey.startsWith('l') ? 'left' : 'right', boneKey);
        return true;
      }
      return false;
    };

    const waistRot = getRot('waist');
    const rootPos = { x: pinOffset.x, y: -50 + pinOffset.y };

    // Check Hands and Toes
    ['r', 'l'].forEach(side => {
      // Leg Chain
      const hipRot = waistRot + getRot(`${side}_hip`);
      const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, `${side}_upper_leg` as any);
      const kneeRot = hipRot + getRot(`${side}_knee`);
      const kneePos = addVec(rootPos, rotateVec({ x: 0, y: thighLen }, hipRot));
      const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, `${side}_lower_leg` as any);
      const ankleRot = kneeRot + getRot(`${side}_foot`);
      const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
      const footLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, `${side}_foot` as any);
      const toePos = addVec(anklePos, rotateVec({ x: 0, y: footLen }, ankleRot));

      if (checkPoint(toePos, `${side}_toe`)) return;

      // Arm Chain
      const torsoRot = waistRot + getRot('torso');
      const collarRot = torsoRot + getRot('collar');
      const waistLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, 'waist');
      const torsoLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, 'torso');
      const collarLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, 'collar');
      const collarEnd = addVec(addVec(rootPos, rotateVec({ x: 0, y: -waistLen }, waistRot)), rotateVec({ x: 0, y: -torsoLen }, torsoRot));
      const sx = (side === 'r' ? RIGGING.R_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER : RIGGING.L_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER) * baseH;
      const shRot = collarRot + (side === 'l' ? 90 : -90) + getRot(`${side}_shoulder`);
      const shPos = addVec(addVec(collarEnd, rotateVec({ x: 0, y: -collarLen }, collarRot)), rotateVec({ x: sx, y: 0 }, collarRot));
      const upLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, `${side}_upper_arm` as any);
      const elRot = shRot + getRot(`${side}_elbow`);
      const elPos = addVec(shPos, rotateVec({ x: 0, y: upLen }, shRot));
      const lowLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, `${side}_lower_arm` as any);
      const wristPos = addVec(elPos, rotateVec({ x: 0, y: lowLen }, elRot));

      checkPoint(wristPos, `${side}_hand`);
    });
  }, [anomalySize, handleAnomalyResolve, isCalibrated, baseH, pinOffset]);

  useEffect(() => {
    if (!anomaly || !isCalibrated) return;
    const interval = setInterval(() => checkCollisions(pivotOffsets, props), 32);
    return () => clearInterval(interval);
  }, [anomaly, isCalibrated, pivotOffsets, props, checkCollisions]);

  const handleDrag = useCallback((e: MouseEvent) => {
    if (draggingBoneKey && !isPlayingTimelapse && !isTweening) {
      lastInteractionTimeRef.current = Date.now();
      const delta = (e.clientX - dragStartXRef.current) * 0.5;
      setPivotOffsets(p => ({ ...p, [draggingBoneKey]: dragStartPivotOffsetRef.current + delta }));
    }
  }, [draggingBoneKey, isPlayingTimelapse, isTweening]);

  useEffect(() => {
    const hu = () => { setDraggingBoneKey(null); draggingBoneKeyRef.current = null; };
    if (draggingBoneKey) {
      draggingBoneKeyRef.current = draggingBoneKey;
      window.addEventListener('mousemove', handleDrag);
      window.addEventListener('mouseup', hu);
    }
    return () => {
      window.removeEventListener('mousemove', handleDrag);
      window.removeEventListener('mouseup', hu);
    };
  }, [draggingBoneKey, handleDrag]);

  const saveCurrentPose = useCallback(() => {
    const n = window.prompt("Name this pose:");
    if (n !== null) {
      const name = n.trim() || `Pose ${savedPoses.length + 1}`;
      setSavedPoses(prev => [...prev, { id: Date.now(), name, pivotOffsets: { ...pivotOffsets }, props: JSON.parse(JSON.stringify(props)) }]);
      setSaveConfirmation(true);
      setTimeout(() => setSaveConfirmation(false), 1500);
      addLog(`[SYSTEM]: POSE_SAVED_SUCCESSFULLY - "${name.toUpperCase()}"`);
    }
  }, [pivotOffsets, props, savedPoses.length, addLog]);

  const startCalibration = useCallback(() => {
    setIsCalibrating(true);
    const start = performance.now();
    const initPose = { ...pivotOffsets };
    const animate = (now: number) => {
      const t = Math.min((now - start) / 400, 1);
      const eased = snapOutEase(t);
      const next: any = {};
      JOINT_KEYS.forEach(k => { next[k] = initPose[k] + (T_POSE[k] - initPose[k]) * eased; });
      setPivotOffsets(next);
      if (t < 1) requestAnimationFrame(animate);
      else { setIsCalibrating(false); setIsCalibrated(true); setIsConsoleVisible(true); spawnAnomaly(); }
    };
    requestAnimationFrame(animate);
  }, [pivotOffsets, spawnAnomaly]);

  const runTween = useCallback((target: SavedPoseEntry) => {
    if (isTweening) return;
    setIsTweening(true);
    const start = performance.now();
    const initPose = { ...pivotOffsets };
    const initProps = JSON.parse(JSON.stringify(props));
    const animate = (now: number) => {
      const t = Math.min((now - start) / tweenDuration, 1);
      const eased = EASING_FUNCTIONS[tweenEasing](t);
      const nextPose: any = {}; JOINT_KEYS.forEach(k => { nextPose[k] = initPose[k] + (target.pivotOffsets[k] - initPose[k]) * eased; });
      const nextProps: any = {}; PROP_KEYS.forEach(k => { nextProps[k] = { w: initProps[k].w + (target.props[k].w - initProps[k].w) * eased, h: initProps[k].h + (target.props[k].h - initProps[k].h) * eased }; });
      setPivotOffsets(nextPose);
      setProps(nextProps);
      if (t < 1) requestAnimationFrame(animate);
      else setIsTweening(false);
    };
    requestAnimationFrame(animate);
  }, [isTweening, pivotOffsets, props, tweenDuration, tweenEasing]);

  const anomalySize = useMemo(() => 15, []);

  return (
    <div className="flex h-full w-full bg-paper font-mono text-ink overflow-hidden select-none">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto z-50">
          <div className="flex justify-between items-center border-b border-ridge pb-2">
            <h1 className="text-xl font-archaic tracking-widest uppercase italic">Bitruvius.Core</h1>
          </div>

          <div className="flex flex-col gap-2">
            {!isCalibrated ? (
              <button onClick={startCalibration} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase">INITIALIZE ENGINE</button>
            ) : (
              <div className="flex flex-col gap-2">
                <button onClick={() => setPivotOffsets({ ...T_POSE })} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase">T-POSE</button>
                <button 
                  onClick={togglePinning} 
                  className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase ${pinningMode !== 'none' ? 'bg-accent-purple text-paper border-accent-purple' : 'bg-paper/10 border-ridge text-mono-light'}`}
                >
                  {pinningMode !== 'none' ? 'FOOT PINNED' : 'PIN FOOT'}
                </button>
                <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border ${showPivots ? 'bg-selection text-paper' : 'border-ridge'}`}>ANCHORS: {showPivots ? 'ON' : 'OFF'}</button>
              </div>
            )}
          </div>

          <div className="flex border-b border-ridge">
            {(['pose', 'props', 'library'] as const).map(tab => (
              <button key={tab} onClick={() => setActiveControlTab(tab)} className={`flex-1 text-[9px] py-2 font-bold ${activeControlTab === tab ? 'text-selection border-b-2 border-selection' : 'opacity-40'}`}>{tab.toUpperCase()}</button>
            ))}
          </div>

          <div className="flex-grow flex flex-col min-h-0">
            {activeControlTab === 'pose' && (
              <div className="flex flex-col gap-2 overflow-y-auto custom-scrollbar">
                {JOINT_KEYS.map(k => (
                  <div key={k} className="p-1">
                    <div className="flex justify-between text-[8px] uppercase font-bold text-mono-light"><span>{k}</span><span>{Math.round(pivotOffsets[k])}°</span></div>
                    <input type="range" min="-180" max="180" value={pivotOffsets[k]} onChange={e => setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))} className="w-full accent-selection h-1" />
                  </div>
                ))}
              </div>
            )}
            {activeControlTab === 'library' && (
              <div className="flex flex-col h-full gap-2">
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                  {savedPoses.map(pe => (
                    <div key={pe.id} className="flex items-center justify-between p-2 border-b border-ridge hover:bg-white/40 group">
                      <span className="text-[10px] uppercase font-bold">{pe.name}</span>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100">
                        <button onClick={() => setPivotOffsets({ ...pe.pivotOffsets })} className="text-[8px] px-2 py-1 bg-selection text-paper uppercase">Load</button>
                        <button onClick={() => runTween(pe)} className="text-[8px] px-2 py-1 bg-mono-mid text-paper uppercase">Tween</button>
                      </div>
                    </div>
                  ))}
                </div>
                <button 
                  onClick={saveCurrentPose} 
                  className={`w-full py-3 text-[10px] font-bold uppercase transition-all ${saveConfirmation ? 'bg-accent-green text-paper' : 'bg-selection text-paper'}`}
                >
                  {saveConfirmation ? '✓ SAVED' : 'SAVE POSE'}
                </button>
              </div>
            )}
          </div>

          <div className="mt-auto pt-4"><SystemLogger logs={systemLogs} isVisible={true} historyCount={tokens} /></div>
        </div>
      )}

      <div className="flex-1 relative bg-paper flex items-center justify-center overflow-hidden" onClick={() => !isCalibrated && !isCalibrating && startCalibration()}>
        <div className="absolute top-4 right-4 z-50 text-right">
          <div className="text-[10px] text-mono-mid uppercase tracking-widest">Unit Tokens</div>
          <div className="text-2xl font-archaic">{tokens.toLocaleString()}</div>
        </div>

        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 border border-ridge bg-white rounded-full"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7" /></svg></button>

        {!isCalibrated && !isCalibrating && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none">
            <h2 className="text-6xl font-archaic uppercase tracking-tighter">Bitruvian Station</h2>
            <p className="text-[10px] uppercase tracking-[0.5em] animate-pulse">Touch to Wake Core</p>
          </div>
        )}

        <svg viewBox="-500 -700 1000 1400" className="w-full h-full overflow-visible relative z-10">
          <g transform={`translate(${pinOffset.x}, ${-50 + pinOffset.y})`}>
            <Mannequin 
              pose={RESTING_BASE_POSE} 
              pivotOffsets={{...pivotOffsets, l_hand_flash: lHandFlash, r_hand_flash: rHandFlash} as any} 
              props={props} 
              showPivots={showPivots && isCalibrated} 
              showLabels={showLabels} 
              baseUnitH={baseH} 
              onAnchorMouseDown={(k, x) => { setDraggingBoneKey(k); dragStartXRef.current = x; dragStartPivotOffsetRef.current = pivotOffsets[k]; }} 
              draggingBoneKey={draggingBoneKey} 
              isPaused={true} 
              pinningMode={pinningMode} 
              offset={pinOffset} 
            />
          </g>
          {anomaly && (
            <g transform={`translate(${anomaly.x}, ${anomaly.y})`}>
              <rect x={-anomalySize / 2} y={-anomalySize / 2} width={anomalySize} height={anomalySize} className="fill-ink hover:fill-accent-red cursor-crosshair transition-colors" />
            </g>
          )}
        </svg>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useCallback } from 'react';
import { Bone } from './Bone';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from '../constants';
import { WalkingEnginePose, WalkingEngineProportions, WalkingEnginePivotOffsets, Vector2D, MaskTransform } from '../types';

interface MannequinProps {
  pose: WalkingEnginePose;
  pivotOffsets: WalkingEnginePivotOffsets & { l_hand_flash?: boolean; r_hand_flash?: boolean };
  props: WalkingEngineProportions;
  showPivots: boolean;
  showLabels: boolean;
  baseUnitH: number;
  onAnchorMouseDown: (boneKey: keyof WalkingEnginePivotOffsets, clientX: number) => void;
  draggingBoneKey: keyof WalkingEnginePivotOffsets | null;
  isPaused: boolean;
  pinningMode: 'none' | 'rightFoot' | 'dual';
  maskImage?: string | null;
  maskTransform?: MaskTransform;
  offset: Vector2D;
}

const RENDER_ORDER: (keyof WalkingEngineProportions)[] = [
    'waist', 'torso', 'l_upper_leg', 'r_upper_leg', 'l_lower_leg', 'r_lower_leg', 'l_foot', 'r_foot', 'l_toe', 'r_toe', 
    'collar', 'head', 'l_upper_arm', 'r_upper_arm', 'l_lower_arm', 'r_lower_arm', 'l_hand', 'r_hand'
];

const partDefinitions: Record<keyof WalkingEngineProportions, any> = {
    head: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HEAD, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HEAD_WIDTH, variant: 'head-tall-oval', drawsUpwards: true, label: 'Head', boneKey: 'neck' },
    collar: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR_WIDTH, variant: 'collar-horizontal-oval-shape', drawsUpwards: true, label: 'Collar', boneKey: 'collar' },
    torso: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO_WIDTH, variant: 'torso-teardrop-pointy-down', drawsUpwards: true, label: 'Upper Body', boneKey: 'torso' },
    waist: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST_WIDTH, variant: 'waist-teardrop-pointy-up', drawsUpwards: true, label: 'Lower Body', boneKey: 'waist' },
    r_upper_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_ARM, variant: 'deltoid-shape', label: 'Shoulder', boneKey: 'r_shoulder' },
    r_lower_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_FOREARM, variant: 'limb-tapered', label: 'Forearm', boneKey: 'r_elbow' },
    r_hand: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND_WIDTH, variant: 'hand-foot-arrowhead-shape', label: 'Hand', boneKey: 'r_hand' },
    l_upper_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_ARM, variant: 'deltoid-shape', label: 'Shoulder', boneKey: 'l_shoulder' },
    l_lower_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_FOREARM, variant: 'limb-tapered', label: 'Forearm', boneKey: 'l_elbow' },
    l_hand: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND_WIDTH, variant: 'hand-foot-arrowhead-shape', label: 'Hand', boneKey: 'l_hand' },
    r_upper_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_THIGH, variant: 'limb-tapered', label: 'Thigh', boneKey: 'r_hip' },
    r_lower_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_CALF, variant: 'limb-tapered', label: 'Calf', boneKey: 'r_knee' },
    r_foot: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT_WIDTH, variant: 'foot-block-shape', label: 'Foot', boneKey: 'r_foot' },
    r_toe: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE_WIDTH, variant: 'toe-rounded-cap', label: 'Toe', boneKey: 'r_toe' },
    l_upper_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_THIGH, variant: 'limb-tapered', label: 'Thigh', boneKey: 'l_hip' },
    l_lower_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_CALF, variant: 'limb-tapered', label: 'Calf', boneKey: 'l_knee' },
    l_foot: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT_WIDTH, variant: 'foot-block-shape', label: 'Foot', boneKey: 'l_foot' },
    l_toe: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE_WIDTH, variant: 'toe-rounded-cap', label: 'Toe', boneKey: 'l_toe' },
};

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

export const Mannequin: React.FC<MannequinProps> = ({
  pose, pivotOffsets, props, showPivots, showLabels, baseUnitH,
  onAnchorMouseDown, draggingBoneKey, isPaused, pinningMode,
  maskImage, maskTransform, offset
}) => {
    const getScaledDimension = useCallback((raw: number, key: keyof WalkingEngineProportions, axis: 'w' | 'h') => {
        return raw * baseUnitH * (props[key]?.[axis] || 1);
    }, [props, baseUnitH]);

    const globalTransforms = useMemo(() => {
        const trans: Partial<Record<keyof WalkingEngineProportions, { position: Vector2D; rotation: number }>> = {};
        const getRot = (key: string) => ((pose as any)[key] || 0) + ((pivotOffsets as any)[key] || 0);

        const waistLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, 'waist', 'h');
        const waistRot = getRot('waist');
        trans.waist = { position: { x: 0, y: 0 }, rotation: waistRot };

        const torsoLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, 'torso', 'h');
        const torsoRot = waistRot + getRot('torso');
        trans.torso = { position: addVec(trans.waist.position, rotateVec({ x: 0, y: -waistLen }, waistRot)), rotation: torsoRot };

        const collarLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, 'collar', 'h');
        const collarRot = torsoRot + getRot('collar');
        trans.collar = { position: addVec(trans.torso.position, rotateVec({ x: 0, y: -torsoLen }, torsoRot)), rotation: collarRot };

        const neckRot = collarRot + getRot('neck');
        trans.head = { position: addVec(trans.collar.position, rotateVec({ x: 0, y: -collarLen }, collarRot)), rotation: neckRot };

        ['r', 'l'].forEach(side => {
            const sx = (side === 'r' ? RIGGING.R_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER : RIGGING.L_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER) * baseUnitH;
            const shRot = collarRot + (side === 'l' ? 90 : -90) + getRot(`${side}_shoulder`);
            const collarEnd = addVec(trans.collar!.position, rotateVec({ x: 0, y: -collarLen }, collarRot));
            const shPos = addVec(collarEnd, rotateVec({ x: sx, y: 0 }, collarRot));
            trans[`${side}_upper_arm` as keyof WalkingEngineProportions] = { position: shPos, rotation: shRot };
            const upLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, `${side}_upper_arm` as any, 'h');
            const elRot = shRot + getRot(`${side}_elbow`);
            const elPos = addVec(shPos, rotateVec({ x: 0, y: upLen }, shRot));
            trans[`${side}_lower_arm` as keyof WalkingEngineProportions] = { position: elPos, rotation: elRot };
            const lowLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, `${side}_lower_arm` as any, 'h');
            const handRot = elRot + getRot(`${side}_hand`);
            trans[`${side}_hand` as keyof WalkingEngineProportions] = { position: addVec(elPos, rotateVec({ x: 0, y: lowLen }, elRot)), rotation: handRot };
        });

        ['r', 'l'].forEach(side => {
            // Legs follow waist rotation (Waist for whole lower body)
            const hipRot = waistRot + getRot(`${side}_hip`);
            trans[`${side}_upper_leg` as keyof WalkingEngineProportions] = { position: trans.waist!.position, rotation: hipRot };
            const thighLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, `${side}_upper_leg` as any, 'h');
            const kneeRot = hipRot + getRot(`${side}_knee`);
            const kneePos = addVec(trans.waist!.position, rotateVec({ x: 0, y: thighLen }, hipRot));
            trans[`${side}_lower_leg` as keyof WalkingEngineProportions] = { position: kneePos, rotation: kneeRot };
            const calfLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, `${side}_lower_leg` as any, 'h');
            const ankleRot = kneeRot + getRot(`${side}_foot`);
            const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
            trans[`${side}_foot` as keyof WalkingEngineProportions] = { position: anklePos, rotation: ankleRot };
            const footLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, `${side}_foot` as any, 'h');
            const toeRot = ankleRot + getRot(`${side}_toe`);
            trans[`${side}_toe` as keyof WalkingEngineProportions] = { position: addVec(anklePos, rotateVec({ x: 0, y: footLen }, ankleRot)), rotation: toeRot };
        });

        return trans;
    }, [pose, pivotOffsets, getScaledDimension, baseUnitH]);

    return (
        <g>
            {RENDER_ORDER.map(partKey => {
                const p = partDefinitions[partKey];
                const t = globalTransforms[partKey];
                if (!p || !t) return null;

                const colorClass = (partKey === 'collar') ? 'fill-olive' : 
                                  (partKey === 'l_hand' && pivotOffsets.l_hand_flash) ? 'fill-accent-red' : 
                                  (partKey === 'r_hand' && pivotOffsets.r_hand_flash) ? 'fill-accent-red' : 'fill-mono-dark';

                return (
                    <g key={partKey} transform={`translate(${t.position.x}, ${t.position.y}) rotate(${t.rotation})`}>
                        <Bone 
                            rotation={0}
                            length={getScaledDimension(p.rawH, partKey, 'h')}
                            width={getScaledDimension(p.rawW, partKey, 'w')}
                            variant={p.variant}
                            drawsUpwards={p.drawsUpwards}
                            label={p.label}
                            boneKey={p.boneKey}
                            proportionKey={partKey}
                            showPivots={showPivots}
                            showLabel={showLabels}
                            onAnchorMouseDown={onAnchorMouseDown}
                            isBeingDragged={draggingBoneKey === p.boneKey}
                            isPausedAndPivotsVisible={true} 
                            colorClass={colorClass}
                            isPinned={pinningMode === 'rightFoot' && partKey === 'r_foot'}
                        />
                    </g>
                );
            })}
        </g>
    );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { WalkingEnginePose, WalkingEnginePivotOffsets, WalkingEngineProportions, Vector2D, MaskTransform } from './types';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from './constants'; 
import { Mannequin } from './components/Mannequin';
import { SystemLogger } from './components/SystemLogger';

const T_POSE: WalkingEnginePivotOffsets = {
  waist: 0, neck: 0, collar: 0, torso: 0,
  l_shoulder: 0, r_shoulder: 0,
  l_elbow: 0, r_elbow: 0,
  l_hand: 0, r_hand: 0,
  l_hip: 0, r_hip: 0,
  l_knee: 0, r_knee: 0,
  l_foot: 0, r_foot: 0,
  l_toe: 0, r_toe: 0
};

const INITIAL_CHALLENGE_POSE: WalkingEnginePivotOffsets = {
  waist: 180, torso: 180, collar: 0, neck: 180,
  l_shoulder: -95, l_elbow: 180, l_hand: 180,
  r_shoulder: 95, r_elbow: 180, r_hand: 180,
  l_hip: 5, l_knee: 180, l_foot: 180, l_toe: 180,
  r_hip: -5, r_knee: 180, r_foot: 180, r_toe: 180
};

const RESTING_BASE_POSE: WalkingEnginePose = {
  waist: 0, neck: 0, collar: 0, torso: 0, 
  l_shoulder: 0, r_shoulder: 0, l_elbow: 0, r_elbow: 0, l_hand: 0, r_hand: 0, 
  l_hip: 0, r_hip: 0, l_knee: 0, r_knee: 0, l_foot: 0, r_foot: 0, l_toe: 0, r_toe: 0, 
  stride_phase: 0, y_offset: 0, x_offset: 0
};

const JOINT_KEYS: (keyof WalkingEnginePivotOffsets)[] = [
  'waist', 'torso', 'collar', 'neck',
  'l_shoulder', 'l_elbow', 'l_hand',
  'r_shoulder', 'r_elbow', 'r_hand',
  'l_hip', 'l_knee', 'l_foot', 'l_toe',
  'r_hip', 'r_knee', 'r_foot', 'r_toe'
];

const PROP_KEYS: (keyof WalkingEngineProportions)[] = [
  'head', 'collar', 'torso', 'waist',
  'l_upper_arm', 'l_lower_arm', 'l_hand',
  'r_upper_arm', 'r_lower_arm', 'r_hand',
  'l_upper_leg', 'l_lower_leg', 'l_foot', 'l_toe',
  'r_upper_leg', 'r_lower_leg', 'r_foot', 'r_toe'
];

// Chain depth for reward scaling (Toes/Hands are furthest, Waist is root)
const CHAIN_DEPTH: Record<string, number> = {
  waist: 0,
  torso: 1, collar: 2, neck: 3, head: 4,
  l_shoulder: 3, r_shoulder: 3, l_elbow: 4, r_elbow: 4, l_hand: 5, r_hand: 5,
  l_hip: 1, r_hip: 1, l_knee: 2, r_knee: 2, l_foot: 3, r_foot: 3, l_toe: 4, r_toe: 4
};

const snapOutEase = (t: number) => {
  const c4 = (2 * Math.PI) / 3;
  return t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

const EASING_FUNCTIONS = {
  linear: (t: number) => t,
  easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
  snapOut: snapOutEase,
};

interface HistoryState {
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  timestamp: number;
  label?: string;
}

interface SavedPoseEntry {
  id: number;
  name: string;
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
}

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [showLabels, setShowLabels] = useState(false);
  const [baseH] = useState(150);
  const [isConsoleVisible, setIsConsoleVisible] = useState(false);
  const [activeControlTab, setActiveControlTab] = useState<'pose' | 'props' | 'library'>('pose');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const [isCalibrated, setIsCalibrated] = useState(false);
  const [isCalibrating, setIsCalibrating] = useState(false);
  const [isPlayingTimelapse, setIsPlayingTimelapse] = useState(false);
  const [tokens, setTokens] = useState(0);
  const [lHandFlash, setLHandFlash] = useState(false);
  const [rHandFlash, setRHandFlash] = useState(false);
  const [saveConfirmation, setSaveConfirmation] = useState(false);

  // Fix: Declare anomalySize early to avoid "used before declaration" errors in checkCollisions
  const anomalySize = useMemo(() => 15, []);

  // Pinning State
  const [pinningMode, setPinningMode] = useState<'none' | 'rightFoot' | 'dual'>('none');
  const [pinOffset, setPinOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const pinnedWorldPosRef = useRef<Vector2D | null>(null);

  // Tween Configuration State
  const [tweenDuration, setTweenDuration] = useState(1000);
  const [tweenEasing, setTweenEasing] = useState<'linear' | 'easeInOutQuad' | 'snapOut'>('easeInOutQuad');
  const [isTweening, setIsTweening] = useState(false);

  // Interaction Tracking
  const lastInteractionTimeRef = useRef(Date.now());
  const draggingBoneKeyRef = useRef<keyof WalkingEnginePivotOffsets | null>(null);

  // Core State
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(INITIAL_CHALLENGE_POSE);
  const [props, setProps] = useState<WalkingEngineProportions>({
    head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 },
    l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 },
    r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 },
    l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 },
    r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 }
  });

  // Pose Library State
  const [savedPoses, setSavedPoses] = useState<SavedPoseEntry[]>([]);

  // Anomaly State
  const [anomaly, setAnomaly] = useState<Vector2D | null>(null);
  const anomalyRef = useRef<Vector2D | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [redoStack, setRedoStack] = useState<HistoryState[]>([]);
  const [recordingHistory, setRecordingHistory] = useState<HistoryState[]>([]);

  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);
  const dragStartXRef = useRef(0);
  const dragStartPivotOffsetRef = useRef(0);
  const isInteractingRef = useRef(false);
  const lastSnapshotTimeRef = useRef(0);

  const addLog = useCallback((message: string) => {
    setSystemLogs(prev => [...prev.slice(-49), { timestamp: new Date().toLocaleTimeString(), message }]);
  }, []);

  useEffect(() => {
    try {
      const storedPoses = localStorage.getItem('bitruvian_library');
      if (storedPoses) {
        const parsed = JSON.parse(storedPoses);
        if (Array.isArray(parsed)) setSavedPoses(parsed);
      }
    } catch (e) { console.error("Error loading library", e); }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('bitruvian_library', JSON.stringify(savedPoses));
    } catch (e) { console.error("Error saving library", e); }
  }, [savedPoses]);

  const awardTokens = useCallback((sourceBone: string) => {
    const timeSinceLastInteraction = Date.now() - lastInteractionTimeRef.current;

    // Passive multiplier for collections made via tweens or gravity (indirect movement)
    let passiveMultiplier = (timeSinceLastInteraction > 1500 || isTweening) ? 2 : 1;

    // Distance bonus: Difference in skeletal depth between controlled joint and collecting joint
    let distanceBonus = 1;
    if (draggingBoneKeyRef.current) {
      const depthDrag = CHAIN_DEPTH[draggingBoneKeyRef.current] || 0;
      const depthCollect = CHAIN_DEPTH[sourceBone] || 0;
      distanceBonus = 1 + Math.abs(depthDrag - depthCollect);
    }

    const gain = Math.floor(distanceBonus * passiveMultiplier);
    setTokens(prev => prev + gain);
    addLog(`[SYSTEM]: POSE_PICKUP - UNIT TOKENS UPDATED (+${gain}) ${passiveMultiplier > 1 ? '[PASSIVE BONUS]' : ''} [${sourceBone.toUpperCase()} CHAIN BONUS: ${distanceBonus}X]`);
  }, [addLog, isTweening]);

  const handleAnomalyResolve = useCallback((side: 'left' | 'right', boneKey: string) => {
    if (!anomalyRef.current) return;
    if (side === 'left') {
      setLHandFlash(true);
      setTimeout(() => setLHandFlash(false), 300);
    } else {
      setRHandFlash(true);
      setTimeout(() => setRHandFlash(false), 300);
    }
    awardTokens(boneKey);
    spawnAnomaly();
  }, [awardTokens]);

  const spawnAnomaly = useCallback(() => {
    const angle = Math.random() * Math.PI * 2;
    const distance = 150 + Math.random() * 350;
    const newAnom = {
      x: Math.cos(angle) * distance,
      y: -250 + Math.sin(angle) * distance
    };
    setAnomaly(newAnom);
    anomalyRef.current = newAnom;
  }, []);

  const calculateAnklePos = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);

    const waistRot = getRot('waist');
    const hipRot = waistRot + getRot('r_hip');
    const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg');
    const kneeRot = hipRot + getRot('r_knee');
    const kneePos = rotateVec({ x: 0, y: thighLen }, hipRot);
    const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg');
    const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
    return anklePos;
  }, [baseH]);

  const togglePinning = useCallback(() => {
    if (pinningMode === 'none') {
      const local = calculateAnklePos(pivotOffsets, props);
      pinnedWorldPosRef.current = {
        x: local.x + pinOffset.x,
        y: local.y - 50 + pinOffset.y
      };
      setPinningMode('rightFoot');
      addLog(`[SYSTEM]: PINNING ENABLED - RIGHT ANKLE ANCHORED.`);
    } else {
      setPinningMode('none');
      pinnedWorldPosRef.current = null;
      setPinOffset({ x: 0, y: 0 });
      addLog(`[SYSTEM]: PINNING DISABLED.`);
    }
  }, [pinningMode, calculateAnklePos, pivotOffsets, props, pinOffset, addLog]);

  const updatePinOffset = useCallback(() => {
    if (pinningMode === 'none' || !pinnedWorldPosRef.current) return;

    const currentLocal = calculateAnklePos(pivotOffsets, props);

    // We want currentLocal + {newPinOffset.x, -50 + newPinOffset.y} = pinnedWorldPosRef.current
    const nextX = pinnedWorldPosRef.current.x - currentLocal.x;
    const nextY = pinnedWorldPosRef.current.y - currentLocal.y + 50;

    setPinOffset({ x: nextX, y: nextY });
  }, [pinningMode, calculateAnklePos, pivotOffsets, props]);

  useEffect(() => {
    if (pinningMode !== 'none') updatePinOffset();
  }, [pivotOffsets, props, updatePinOffset]);

  const checkCollisions = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    if (!anomalyRef.current || !isCalibrated) return;

    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);
    const threshold = anomalySize * 3;

    const checkPoint = (pos: Vector2D, boneKey: string) => {
      const dx = pos.x - anomalyRef.current!.x;
      const dy = pos.y - anomalyRef.current!.y;
      if (dx*dx + dy*dy < threshold * threshold) {
        handleAnomalyResolve(boneKey.startsWith('l') ? 'left' : 'right', boneKey);
        return true;
      }
      return false;
    };

    const waistRot = getRot('waist');
    const rootPos = { x: pinOffset.x, y: -50 + pinOffset.y };

    // Check Hands and Toes
    ['r', 'l'].forEach(side => {
      // Leg Chain
      const hipRot = waistRot + getRot(`${side}_hip`);
      const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, `${side}_upper_leg` as any);
      const kneeRot = hipRot + getRot(`${side}_knee`);
      const kneePos = addVec(rootPos, rotateVec({ x: 0, y: thighLen }, hipRot));
      const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, `${side}_lower_leg` as any);
      const ankleRot = kneeRot + getRot(`${side}_foot`);
      const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
      const footLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, `${side}_foot` as any);
      const toePos = addVec(anklePos, rotateVec({ x: 0, y: footLen }, ankleRot));

      if (checkPoint(toePos, `${side}_toe`)) return;

      // Arm Chain
      const torsoRot = waistRot + getRot('torso');
      const collarRot = torsoRot + getRot('collar');
      const waistLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, 'waist');
      const torsoLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, 'torso');
      const collarLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, 'collar');
      const collarEnd = addVec(addVec(rootPos, rotateVec({ x: 0, y: -waistLen }, waistRot)), rotateVec({ x: 0, y: -torsoLen }, torsoRot));
      const sx = (side === 'r' ? RIGGING.R_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER : RIGGING.L_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER) * baseH;
      const shRot = collarRot + (side === 'l' ? 90 : -90) + getRot(`${side}_shoulder`);
      const shPos = addVec(addVec(collarEnd, rotateVec({ x: 0, y: -collarLen }, collarRot)), rotateVec({ x: sx, y: 0 }, collarRot));
      const upLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, `${side}_upper_arm` as any);
      const elRot = shRot + getRot(`${side}_elbow`);
      const elPos = addVec(shPos, rotateVec({ x: 0, y: upLen }, shRot));
      const lowLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, `${side}_lower_arm` as any);
      const wristPos = addVec(elPos, rotateVec({ x: 0, y: lowLen }, elRot));

      checkPoint(wristPos, `${side}_hand`);
    });
  }, [anomalySize, handleAnomalyResolve, isCalibrated, baseH, pinOffset]);

  useEffect(() => {
    if (!anomaly || !isCalibrated) return;
    const interval = setInterval(() => checkCollisions(pivotOffsets, props), 32);
    return () => clearInterval(interval);
  }, [anomaly, isCalibrated, pivotOffsets, props, checkCollisions]);

  const handleDrag = useCallback((e: MouseEvent) => {
    if (draggingBoneKey && !isPlayingTimelapse && !isTweening) {
      lastInteractionTimeRef.current = Date.now();
      const delta = (e.clientX - dragStartXRef.current) * 0.5;
      setPivotOffsets(p => ({ ...p, [draggingBoneKey]: dragStartPivotOffsetRef.current + delta }));
    }
  }, [draggingBoneKey, isPlayingTimelapse, isTweening]);

  useEffect(() => {
    const hu = () => { setDraggingBoneKey(null); draggingBoneKeyRef.current = null; };
    if (draggingBoneKey) {
      draggingBoneKeyRef.current = draggingBoneKey;
      window.addEventListener('mousemove', handleDrag);
      window.addEventListener('mouseup', hu);
    }
    return () => {
      window.removeEventListener('mousemove', handleDrag);
      window.removeEventListener('mouseup', hu);
    };
  }, [draggingBoneKey, handleDrag]);

  const saveCurrentPose = useCallback(() => {
    const n = window.prompt("Name this pose:");
    if (n !== null) {
      const name = n.trim() || `Pose ${savedPoses.length + 1}`;
      setSavedPoses(prev => [...prev, { id: Date.now(), name, pivotOffsets: { ...pivotOffsets }, props: JSON.parse(JSON.stringify(props)) }]);
      setSaveConfirmation(true);
      setTimeout(() => setSaveConfirmation(false), 1500);
      addLog(`[SYSTEM]: POSE_SAVED_SUCCESSFULLY - "${name.toUpperCase()}"`);
    }
  }, [pivotOffsets, props, savedPoses.length, addLog]);

  const startCalibration = useCallback(() => {
    setIsCalibrating(true);
    const start = performance.now();
    const initPose = { ...pivotOffsets };
    const animate = (now: number) => {
      const t = Math.min((now - start) / 400, 1);
      const eased = snapOutEase(t);
      const next: any = {};
      JOINT_KEYS.forEach(k => { next[k] = initPose[k] + (T_POSE[k] - initPose[k]) * eased; });
      setPivotOffsets(next);
      if (t < 1) requestAnimationFrame(animate);
      else { setIsCalibrating(false); setIsCalibrated(true); setIsConsoleVisible(true); spawnAnomaly(); }
    };
    requestAnimationFrame(animate);
  }, [pivotOffsets, spawnAnomaly]);

  const runTween = useCallback((target: SavedPoseEntry) => {
    if (isTweening) return;
    setIsTweening(true);
    const start = performance.now();
    const initPose = { ...pivotOffsets };
    const initProps = JSON.parse(JSON.stringify(props));
    const animate = (now: number) => {
      const t = Math.min((now - start) / tweenDuration, 1);
      const eased = EASING_FUNCTIONS[tweenEasing](t);
      const nextPose: any = {}; JOINT_KEYS.forEach(k => { nextPose[k] = initPose[k] + (target.pivotOffsets[k] - initPose[k]) * eased; });
      const nextProps: any = {}; PROP_KEYS.forEach(k => { nextProps[k] = { w: initProps[k].w + (target.props[k].w - initProps[k].w) * eased, h: initProps[k].h + (target.props[k].h - initProps[k].h) * eased }; });
      setPivotOffsets(nextPose);
      setProps(nextProps);
      if (t < 1) requestAnimationFrame(animate);
      else setIsTweening(false);
    };
    requestAnimationFrame(animate);
  }, [isTweening, pivotOffsets, props, tweenDuration, tweenEasing]);


  return (
    <div className="flex h-full w-full bg-paper font-mono text-ink overflow-hidden select-none">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto z-50">
          <div className="flex justify-between items-center border-b border-ridge pb-2">
            <h1 className="text-xl font-archaic tracking-widest uppercase italic">Bitruvius.Core</h1>
          </div>

          <div className="flex flex-col gap-2">
            {!isCalibrated ? (
              <button onClick={startCalibration} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase">INITIALIZE ENGINE</button>
            ) : (
              <div className="flex flex-col gap-2">
                <button onClick={() => setPivotOffsets({ ...T_POSE })} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase">T-POSE</button>
                <button 
                  onClick={togglePinning} 
                  className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase ${pinningMode !== 'none' ? 'bg-accent-purple text-paper border-accent-purple' : 'bg-paper/10 border-ridge text-mono-light'}`}
                >
                  {pinningMode !== 'none' ? 'FOOT PINNED' : 'PIN FOOT'}
                </button>
                <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border ${showPivots ? 'bg-selection text-paper' : 'border-ridge'}`}>ANCHORS: {showPivots ? 'ON' : 'OFF'}</button>
              </div>
            )}
          </div>

          <div className="flex border-b border-ridge">
            {(['pose', 'props', 'library'] as const).map(tab => (
              <button key={tab} onClick={() => setActiveControlTab(tab)} className={`flex-1 text-[9px] py-2 font-bold ${activeControlTab === tab ? 'text-selection border-b-2 border-selection' : 'opacity-40'}`}>{tab.toUpperCase()}</button>
            ))}
          </div>

          <div className="flex-grow flex flex-col min-h-0">
            {activeControlTab === 'pose' && (
              <div className="flex flex-col gap-2 overflow-y-auto custom-scrollbar">
                {JOINT_KEYS.map(k => (
                  <div key={k} className="p-1">
                    <div className="flex justify-between text-[8px] uppercase font-bold text-mono-light"><span>{k}</span><span>{Math.round(pivotOffsets[k])}°</span></div>
                    <input type="range" min="-180" max="180" value={pivotOffsets[k]} onChange={e => setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))} className="w-full accent-selection h-1" />
                  </div>
                ))}
              </div>
            )}
            {activeControlTab === 'library' && (
              <div className="flex flex-col h-full gap-2">
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                  {savedPoses.map(pe => (
                    <div key={pe.id} className="flex items-center justify-between p-2 border-b border-ridge hover:bg-white/40 group">
                      <span className="text-[10px] uppercase font-bold">{pe.name}</span>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100">
                        <button onClick={() => setPivotOffsets({ ...pe.pivotOffsets })} className="text-[8px] px-2 py-1 bg-selection text-paper uppercase">Load</button>
                        <button onClick={() => runTween(pe)} className="text-[8px] px-2 py-1 bg-mono-mid text-paper uppercase">Tween</button>
                      </div>
                    </div>
                  ))}
                </div>
                <button 
                  onClick={saveCurrentPose} 
                  className={`w-full py-3 text-[10px] font-bold uppercase transition-all ${saveConfirmation ? 'bg-accent-green text-paper' : 'bg-selection text-paper'}`}
                >
                  {saveConfirmation ? '✓ SAVED' : 'SAVE POSE'}
                </button>
              </div>
            )}
          </div>

          <div className="mt-auto pt-4"><SystemLogger logs={systemLogs} isVisible={true} historyCount={tokens} /></div>
        </div>
      )}

      <div className="flex-1 relative bg-paper flex items-center justify-center overflow-hidden" onClick={() => !isCalibrated && !isCalibrating && startCalibration()}>
        <div className="absolute top-4 right-4 z-50 text-right">
          <div className="text-[10px] text-mono-mid uppercase tracking-widest">Unit Tokens</div>
          <div className="text-2xl font-archaic">{tokens.toLocaleString()}</div>
        </div>

        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 border border-ridge bg-white rounded-full"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7" /></svg></button>

        {!isCalibrated && !isCalibrating && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none">
            <h2 className="text-6xl font-archaic uppercase tracking-tighter">Bitruvian Station</h2>
            <p className="text-[10px] uppercase tracking-[0.5em] animate-pulse">Touch to Wake Core</p>
          </div>
        )}

        <svg viewBox="-500 -700 1000 1400" className="w-full h-full overflow-visible relative z-10">
          <g transform={`translate(${pinOffset.x}, ${-50 + pinOffset.y})`}>
            <Mannequin 
              pose={RESTING_BASE_POSE} 
              pivotOffsets={{...pivotOffsets, l_hand_flash: lHandFlash, r_hand_flash: rHandFlash} as any} 
              props={props} 
              showPivots={showPivots && isCalibrated} 
              showLabels={showLabels} 
              baseUnitH={baseH} 
              onAnchorMouseDown={(k, x) => { setDraggingBoneKey(k); dragStartXRef.current = x; dragStartPivotOffsetRef.current = pivotOffsets[k]; }} 
              draggingBoneKey={draggingBoneKey} 
              isPaused={true} 
              pinningMode={pinningMode} 
              offset={pinOffset} 
            />
          </g>
          {anomaly && (
            <g transform={`translate(${anomaly.x}, ${anomaly.y})`}>
              <rect x={-anomalySize / 2} y={-anomalySize / 2} width={anomalySize} height={anomalySize} className="fill-ink hover:fill-accent-red cursor-crosshair transition-colors" />
            </g>
          )}
        </svg>
      </div>
    </div>
  );
};

export default App;

export type Vector2D = { x: number; y: number; };

export type MaskTransform = {
  x: number;
  y: number;
  rotation: number;
  scale: number;
};

export type JointMode = 'standard' | 'bend' | 'stretch';

export type WalkingEnginePose = {
  waist: number;
  neck: number; 
  collar: number; 
  torso: number;
  l_shoulder: number; r_shoulder: number;
  l_elbow: number; r_elbow: number;
  l_hand: number; r_hand: number;
  l_hip: number; r_hip: number;
  l_knee: number; r_knee: number;
  l_foot: number; r_foot: number;
  l_toe: number; r_toe: number;
  stride_phase: number;
  y_offset: number;
  x_offset: number;
};

export type WalkingEnginePivotOffsets = {
  waist: number;
  neck: number; 
  collar: number; 
  torso: number;
  l_shoulder: number; r_shoulder: number;
  l_elbow: number; r_elbow: number;
  l_hand: number; r_hand: number;
  l_hip: number; r_hip: number;
  l_knee: number; r_knee: number;
  l_foot: number; r_foot: number;
  l_toe: number; r_toe: number;
};

export type WalkingEngineProportions = {
  head: { w: number; h: number };
  collar: { w: number; h: number };
  torso: { w: number; h: number };
  waist: { w: number; h: number };
  l_upper_arm: { w: number; h: number };
  l_lower_arm: { w: number; h: number };
  l_hand: { w: number; h: number };
  r_upper_arm: { w: number; h: number };
  r_lower_arm: { w: number; h: number };
  r_hand: { w: number; h: number };
  l_upper_leg: { w: number; h: number };
  l_lower_leg: { w: number; h: number };
  l_foot: { w: number; h: number };
  l_toe: { w: number; h: number };
  r_upper_leg: { w: number; h: number };
  r_lower_leg: { w: number; h: number };
  r_foot: { w: number; h: number };
  r_toe: { w: number; h: number };
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { WalkingEnginePose, WalkingEnginePivotOffsets, WalkingEngineProportions, Vector2D, MaskTransform, JointMode } from './types';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from './constants'; 
import { Mannequin } from './components/Mannequin';
import { SystemLogger } from './components/SystemLogger';

const T_POSE: WalkingEnginePivotOffsets = {
  waist: 0, neck: 0, collar: 0, torso: 0,
  l_shoulder: 0, r_shoulder: 0,
  l_elbow: 0, r_elbow: 0,
  l_hand: 0, r_hand: 0,
  l_hip: 0, r_hip: 0,
  l_knee: 0, r_knee: 0,
  l_foot: 0, r_foot: 0,
  l_toe: 0, r_toe: 0
};

const INITIAL_CHALLENGE_POSE: WalkingEnginePivotOffsets = {
  waist: 180, torso: 180, collar: 0, neck: 180,
  l_shoulder: -95, l_elbow: 180, l_hand: 180,
  r_shoulder: 95, r_elbow: 180, r_hand: 180,
  l_hip: 5, l_knee: 180, l_foot: 180, l_toe: 180,
  r_hip: -5, r_knee: 180, r_foot: 180, r_toe: 180
};

const RESTING_BASE_POSE: WalkingEnginePose = {
  waist: 0, neck: 0, collar: 0, torso: 0, 
  l_shoulder: 0, r_shoulder: 0, l_elbow: 0, r_elbow: 0, l_hand: 0, r_hand: 0, 
  l_hip: 0, r_hip: 0, l_knee: 0, r_knee: 0, l_foot: 0, r_foot: 0, l_toe: 0, r_toe: 0, 
  stride_phase: 0, y_offset: 0, x_offset: 0
};

const JOINT_KEYS: (keyof WalkingEnginePivotOffsets)[] = [
  'waist', 'torso', 'collar', 'neck',
  'l_shoulder', 'l_elbow', 'l_hand',
  'r_shoulder', 'r_elbow', 'r_hand',
  'l_hip', 'l_knee', 'l_foot', 'l_toe',
  'r_hip', 'r_knee', 'r_foot', 'r_toe'
];

const PROP_KEYS: (keyof WalkingEngineProportions)[] = [
  'head', 'collar', 'torso', 'waist',
  'l_upper_arm', 'l_lower_arm', 'l_hand',
  'r_upper_arm', 'r_lower_arm', 'r_hand',
  'l_upper_leg', 'l_lower_leg', 'l_foot', 'l_toe',
  'r_upper_leg', 'r_lower_leg', 'r_foot', 'r_toe'
];

const CHAIN_DEPTH: Record<string, number> = {
  waist: 0, torso: 1, collar: 2, neck: 3, head: 4,
  l_shoulder: 3, r_shoulder: 3, l_elbow: 4, r_elbow: 4, l_hand: 5, r_hand: 5,
  l_hip: 1, r_hip: 1, l_knee: 2, r_knee: 2, l_foot: 3, r_foot: 3, l_toe: 4, r_toe: 4
};

const snapOutEase = (t: number) => {
  const c4 = (2 * Math.PI) / 3;
  return t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

const EASING_FUNCTIONS = {
  linear: (t: number) => t,
  easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
  snapOut: snapOutEase,
};

interface HistoryState {
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
  timestamp: number;
}

interface SavedPoseEntry {
  id: number;
  name: string;
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
}

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [showLabels, setShowLabels] = useState(false);
  const [baseH] = useState(150);
  const [isConsoleVisible, setIsConsoleVisible] = useState(false);
  const [activeControlTab, setActiveControlTab] = useState<'pose' | 'props' | 'library'>('pose');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const [isCalibrated, setIsCalibrated] = useState(false);
  const [isCalibrating, setIsCalibrating] = useState(false);
  const [isPlayingTimelapse, setIsPlayingTimelapse] = useState(false);
  const [tokens, setTokens] = useState(0);
  const [lHandFlash, setLHandFlash] = useState(false);
  const [rHandFlash, setRHandFlash] = useState(false);
  const [saveConfirmation, setSaveConfirmation] = useState(false);

  const anomalySize = useMemo(() => 15, []);

  // New State: Joint Modes and Hierarchy
  const [jointModes, setJointModes] = useState<Record<keyof WalkingEnginePivotOffsets, JointMode>>(
    Object.fromEntries(JOINT_KEYS.map(k => [k, 'standard'])) as any
  );
  const [isReversed, setIsReversed] = useState(false);

  // Pinning State
  const [pinningMode, setPinningMode] = useState<'none' | 'rightFoot' | 'dual'>('none');
  const [pinOffset, setPinOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const pinnedWorldPosRef = useRef<Vector2D | null>(null);

  // Tween Configuration State
  const [tweenDuration, setTweenDuration] = useState(1000);
  const [tweenEasing, setTweenEasing] = useState<'linear' | 'easeInOutQuad' | 'snapOut'>('easeInOutQuad');
  const [isTweening, setIsTweening] = useState(false);

  // Interaction Tracking
  const lastInteractionTimeRef = useRef(Date.now());
  const draggingBoneKeyRef = useRef<keyof WalkingEnginePivotOffsets | null>(null);

  // Core State
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(INITIAL_CHALLENGE_POSE);
  const [props, setProps] = useState<WalkingEngineProportions>({
    head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 },
    l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 },
    r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 },
    l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 },
    r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 }
  });

  // Pose Library State
  const [savedPoses, setSavedPoses] = useState<SavedPoseEntry[]>([]);

  // Anomaly State
  const [anomaly, setAnomaly] = useState<Vector2D | null>(null);
  const anomalyRef = useRef<Vector2D | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [redoStack, setRedoStack] = useState<HistoryState[]>([]);

  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);
  const dragStartXRef = useRef(0);
  const dragStartPivotOffsetRef = useRef(0);

  const addLog = useCallback((message: string) => {
    setSystemLogs(prev => [...prev.slice(-49), { timestamp: new Date().toLocaleTimeString(), message }]);
  }, []);

  useEffect(() => {
    try {
      const storedPoses = localStorage.getItem('bitruvian_library');
      if (storedPoses) {
        const parsed = JSON.parse(storedPoses);
        if (Array.isArray(parsed)) setSavedPoses(parsed);
      }
    } catch (e) { console.error("Error loading library", e); }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('bitruvian_library', JSON.stringify(savedPoses));
    } catch (e) { console.error("Error saving library", e); }
  }, [savedPoses]);

  const awardTokens = useCallback((sourceBone: string) => {
    const timeSinceLastInteraction = Date.now() - lastInteractionTimeRef.current;
    let passiveMultiplier = (timeSinceLastInteraction > 1500 || isTweening) ? 2 : 1;
    let limbBonus = CHAIN_DEPTH[sourceBone] || 1;
    const gain = Math.floor(limbBonus * passiveMultiplier);
    setTokens(prev => prev + gain);
    addLog(`[SYSTEM]: POSE_PICKUP - UNIT TOKENS UPDATED (+${gain}) ${passiveMultiplier > 1 ? '[PASSIVE BONUS]' : ''} [${sourceBone.toUpperCase()} DEPTH: ${limbBonus}X]`);
  }, [addLog, isTweening]);

  const handleAnomalyResolve = useCallback((side: 'left' | 'right', boneKey: string) => {
    if (!anomalyRef.current) return;
    if (side === 'left') { setLHandFlash(true); setTimeout(() => setLHandFlash(false), 300); }
    else { setRHandFlash(true); setTimeout(() => setRHandFlash(false), 300); }
    awardTokens(boneKey);
    spawnAnomaly();
  }, [awardTokens]);

  const spawnAnomaly = useCallback(() => {
    const angle = Math.random() * Math.PI * 2;
    const distance = 150 + Math.random() * 350;
    const newAnom = { x: Math.cos(angle) * distance, y: -250 + Math.sin(angle) * distance };
    setAnomaly(newAnom);
    anomalyRef.current = newAnom;
  }, []);

  const calculateAnklePos = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);
    const waistRot = getRot('waist');
    const hipRot = waistRot + getRot('r_hip');
    const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg');
    const kneeRot = hipRot + getRot('r_knee');
    const kneePos = rotateVec({ x: 0, y: thighLen }, hipRot);
    const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg');
    const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
    return anklePos;
  }, [baseH]);

  const togglePinning = useCallback(() => {
    if (pinningMode === 'none') {
      const local = calculateAnklePos(pivotOffsets, props);
      pinnedWorldPosRef.current = { x: local.x + pinOffset.x, y: local.y - 50 + pinOffset.y };
      setPinningMode('rightFoot');
      addLog(`[SYSTEM]: PINNING ENABLED - RIGHT ANKLE ANCHORED.`);
    } else {
      setPinningMode('none');
      pinnedWorldPosRef.current = null;
      setPinOffset({ x: 0, y: 0 });
      addLog(`[SYSTEM]: PINNING DISABLED.`);
    }
  }, [pinningMode, calculateAnklePos, pivotOffsets, props, pinOffset, addLog]);

  const updatePinOffset = useCallback(() => {
    if (pinningMode === 'none' || !pinnedWorldPosRef.current) return;
    const currentLocal = calculateAnklePos(pivotOffsets, props);
    const nextX = pinnedWorldPosRef.current.x - currentLocal.x;
    const nextY = pinnedWorldPosRef.current.y - currentLocal.y + 50;
    setPinOffset({ x: nextX, y: nextY });
  }, [pinningMode, calculateAnklePos, pivotOffsets, props]);

  useEffect(() => {
    if (pinningMode !== 'none') updatePinOffset();
  }, [pivotOffsets, props, updatePinOffset]);

  const handleDrag = useCallback((e: MouseEvent) => {
    if (draggingBoneKey && !isPlayingTimelapse && !isTweening) {
      lastInteractionTimeRef.current = Date.now();
      const delta = (e.clientX - dragStartXRef.current) * 0.5;
      setPivotOffsets(p => ({ ...p, [draggingBoneKey]: dragStartPivotOffsetRef.current + delta }));
    }
  }, [draggingBoneKey, isPlayingTimelapse, isTweening]);

  useEffect(() => {
    const hu = () => { setDraggingBoneKey(null); draggingBoneKeyRef.current = null; };
    if (draggingBoneKey) {
      draggingBoneKeyRef.current = draggingBoneKey;
      window.addEventListener('mousemove', handleDrag);
      window.addEventListener('mouseup', hu);
    }
    return () => { window.removeEventListener('mousemove', handleDrag); window.removeEventListener('mouseup', hu); };
  }, [draggingBoneKey, handleDrag]);

  const setJointMode = (key: keyof WalkingEnginePivotOffsets, mode: JointMode) => {
    setJointModes(prev => ({ ...prev, [key]: mode }));
    addLog(`[SYSTEM]: JOINT_MODE_UPDATE - ${key.toUpperCase()} SET TO ${mode.toUpperCase()}`);
  };

  return (
    <div className="flex h-full w-full bg-paper font-mono text-ink overflow-hidden select-none">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto z-50">
          <div className="flex justify-between items-center border-b border-ridge pb-2">
            <h1 className="text-xl font-archaic tracking-widest uppercase italic">Bitruvius.Core</h1>
          </div>

          <div className="flex flex-col gap-2">
            {!isCalibrated ? (
              <button onClick={() => setIsCalibrated(true)} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase">INITIALIZE ENGINE</button>
            ) : (
              <div className="flex flex-col gap-2">
                <button onClick={() => setPivotOffsets({ ...T_POSE })} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase">T-POSE</button>
                <div className="grid grid-cols-2 gap-2">
                    <button 
                    onClick={togglePinning} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase ${pinningMode !== 'none' ? 'bg-accent-purple text-paper border-accent-purple' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {pinningMode !== 'none' ? 'FOOT PINNED' : 'PIN FOOT'}
                    </button>
                    <button 
                    onClick={() => { setIsReversed(!isReversed); addLog(`[SYSTEM]: HIERARCHY_REVERSED - ROOT SET TO ${!isReversed ? 'HEAD' : 'WAIST'}`); }} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase ${isReversed ? 'bg-accent-red text-paper border-accent-red' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {isReversed ? 'REVERSED' : 'REVERSE'}
                    </button>
                </div>
                <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border ${showPivots ? 'bg-selection text-paper' : 'border-ridge'}`}>ANCHORS: {showPivots ? 'ON' : 'OFF'}</button>
              </div>
            )}
          </div>

          <div className="flex border-b border-ridge">
            {(['pose', 'props', 'library'] as const).map(tab => (
              <button key={tab} onClick={() => setActiveControlTab(tab)} className={`flex-1 text-[9px] py-2 font-bold ${activeControlTab === tab ? 'text-selection border-b-2 border-selection' : 'opacity-40'}`}>{tab.toUpperCase()}</button>
            ))}
          </div>

          <div className="flex-grow flex flex-col min-h-0">
            {activeControlTab === 'pose' && (
              <div className="flex flex-col gap-3 overflow-y-auto custom-scrollbar py-2">
                {JOINT_KEYS.map(k => (
                  <div key={k} className="p-1 border-b border-ridge/30 last:border-0">
                    <div className="flex justify-between text-[8px] uppercase font-bold text-mono-light mb-1">
                        <span>{k}</span>
                        <div className="flex gap-1">
                            {(['standard', 'bend', 'stretch'] as JointMode[]).map(m => (
                                <button 
                                    key={m} 
                                    onClick={() => setJointMode(k, m)}
                                    className={`px-1 rounded-sm border ${jointModes[k] === m ? 'bg-selection text-paper border-selection' : 'border-ridge text-mono-mid opacity-40 hover:opacity-100'}`}
                                >
                                    {m[0].toUpperCase()}
                                </button>
                            ))}
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <input type="range" min="-180" max="180" value={pivotOffsets[k]} onChange={e => setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))} className="flex-1 accent-selection h-1" />
                        <span className="text-[8px] font-mono text-mono-mid w-8 text-right">{Math.round(pivotOffsets[k])}°</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
            {activeControlTab === 'library' && (
              <div className="flex flex-col h-full gap-2">
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                  {savedPoses.map(pe => (
                    <div key={pe.id} className="flex items-center justify-between p-2 border-b border-ridge hover:bg-white/40 group">
                      <span className="text-[10px] uppercase font-bold">{pe.name}</span>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100">
                        <button onClick={() => { setPivotOffsets({ ...pe.pivotOffsets }); setJointModes({ ...pe.jointModes }); }} className="text-[8px] px-2 py-1 bg-selection text-paper uppercase">Load</button>
                        <button onClick={() => runTween(pe)} className="text-[8px] px-2 py-1 bg-mono-mid text-paper uppercase">Tween</button>
                      </div>
                    </div>
                  ))}
                </div>
                <button 
                  onClick={saveCurrentPose} 
                  className={`w-full py-3 text-[10px] font-bold uppercase transition-all ${saveConfirmation ? 'bg-accent-green text-paper' : 'bg-selection text-paper'}`}
                >
                  {saveConfirmation ? '✓ SAVED' : 'SAVE POSE'}
                </button>
              </div>
            )}
          </div>

          <div className="mt-auto pt-4"><SystemLogger logs={systemLogs} isVisible={true} historyCount={tokens} /></div>
        </div>
      )}

      <div className="flex-1 relative bg-paper flex items-center justify-center overflow-hidden" onClick={() => !isCalibrated && !isCalibrating && setIsCalibrated(true)}>
        <div className="absolute top-4 right-4 z-50 text-right">
          <div className="text-[10px] text-mono-mid uppercase tracking-widest">Unit Tokens</div>
          <div className="text-2xl font-archaic">{tokens.toLocaleString()}</div>
        </div>

        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 border border-ridge bg-white rounded-full transition-transform hover:scale-110 active:scale-95"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7" /></svg></button>

        {!isCalibrated && !isCalibrating && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none bg-paper/20">
            <h2 className="text-6xl font-archaic uppercase tracking-tighter">Bitruvian Station</h2>
            <p className="text-[10px] uppercase tracking-[0.5em] animate-pulse">Touch to Wake Core</p>
          </div>
        )}

        <svg viewBox="-500 -700 1000 1400" className="w-full h-full overflow-visible relative z-10">
          <g transform={`translate(${pinOffset.x}, ${-50 + pinOffset.y})`}>
            <Mannequin 
              pose={RESTING_BASE_POSE} 
              pivotOffsets={{...pivotOffsets, l_hand_flash: lHandFlash, r_hand_flash: rHandFlash} as any} 
              props={props} 
              showPivots={showPivots && isCalibrated} 
              showLabels={showLabels} 
              baseUnitH={baseH} 
              onAnchorMouseDown={(k, x) => { setDraggingBoneKey(k); dragStartXRef.current = x; dragStartPivotOffsetRef.current = pivotOffsets[k]; }} 
              draggingBoneKey={draggingBoneKey} 
              isPaused={true} 
              pinningMode={pinningMode} 
              offset={pinOffset} 
              isReversed={isReversed}
              jointModes={jointModes}
            />
          </g>
          {anomaly && (
            <g transform={`translate(${anomaly.x}, ${anomaly.y})`}>
              <rect x={-anomalySize / 2} y={-anomalySize / 2} width={anomalySize} height={anomalySize} className="fill-ink hover:fill-accent-red cursor-crosshair transition-colors" />
            </g>
          )}
        </svg>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useCallback } from 'react';
import { Bone } from './Bone';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from '../constants';
import { WalkingEnginePose, WalkingEngineProportions, WalkingEnginePivotOffsets, Vector2D, MaskTransform, JointMode } from '../types';

interface MannequinProps {
  pose: WalkingEnginePose;
  pivotOffsets: WalkingEnginePivotOffsets & { l_hand_flash?: boolean; r_hand_flash?: boolean };
  props: WalkingEngineProportions;
  showPivots: boolean;
  showLabels: boolean;
  baseUnitH: number;
  onAnchorMouseDown: (boneKey: keyof WalkingEnginePivotOffsets, clientX: number) => void;
  draggingBoneKey: keyof WalkingEnginePivotOffsets | null;
  isPaused: boolean;
  pinningMode: 'none' | 'rightFoot' | 'dual';
  maskImage?: string | null;
  maskTransform?: MaskTransform;
  offset: Vector2D;
  isReversed?: boolean;
  jointModes?: Record<keyof WalkingEnginePivotOffsets, JointMode>;
}

const RENDER_ORDER: (keyof WalkingEngineProportions)[] = [
    'waist', 'torso', 'l_upper_leg', 'r_upper_leg', 'l_lower_leg', 'r_lower_leg', 'l_foot', 'r_foot', 'l_toe', 'r_toe', 
    'collar', 'head', 'l_upper_arm', 'r_upper_arm', 'l_lower_arm', 'r_lower_arm', 'l_hand', 'r_hand'
];

const partDefinitions: Record<keyof WalkingEngineProportions, any> = {
    head: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HEAD, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HEAD_WIDTH, variant: 'head-tall-oval', drawsUpwards: true, label: 'Head', boneKey: 'neck' },
    collar: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR_WIDTH, variant: 'collar-horizontal-oval-shape', drawsUpwards: true, label: 'Collar', boneKey: 'collar' },
    torso: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO_WIDTH, variant: 'torso-teardrop-pointy-down', drawsUpwards: true, label: 'Upper Body', boneKey: 'torso' },
    waist: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST_WIDTH, variant: 'waist-teardrop-pointy-up', drawsUpwards: true, label: 'Lower Body', boneKey: 'waist' },
    r_upper_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_ARM, variant: 'deltoid-shape', label: 'Shoulder', boneKey: 'r_shoulder' },
    r_lower_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_FOREARM, variant: 'limb-tapered', label: 'Forearm', boneKey: 'r_elbow' },
    r_hand: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND_WIDTH, variant: 'hand-foot-arrowhead-shape', label: 'Hand', boneKey: 'r_hand' },
    l_upper_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_ARM, variant: 'deltoid-shape', label: 'Shoulder', boneKey: 'l_shoulder' },
    l_lower_arm: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_FOREARM, variant: 'limb-tapered', label: 'Forearm', boneKey: 'l_elbow' },
    l_hand: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HAND_WIDTH, variant: 'hand-foot-arrowhead-shape', label: 'Hand', boneKey: 'l_hand' },
    r_upper_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_THIGH, variant: 'limb-tapered', label: 'Thigh', boneKey: 'r_hip' },
    r_lower_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_CALF, variant: 'limb-tapered', label: 'Calf', boneKey: 'r_knee' },
    r_foot: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT_WIDTH, variant: 'foot-block-shape', label: 'Foot', boneKey: 'r_foot' },
    r_toe: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE_WIDTH, variant: 'toe-rounded-cap', label: 'Toe', boneKey: 'r_toe' },
    l_upper_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_THIGH, variant: 'limb-tapered', label: 'Thigh', boneKey: 'l_hip' },
    l_lower_leg: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LIMB_WIDTH_CALF, variant: 'limb-tapered', label: 'Calf', boneKey: 'l_knee' },
    l_foot: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT_WIDTH, variant: 'foot-block-shape', label: 'Foot', boneKey: 'l_foot' },
    l_toe: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TOE_WIDTH, variant: 'toe-rounded-cap', label: 'Toe', boneKey: 'l_toe' },
};

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

export const Mannequin: React.FC<MannequinProps> = ({
  pose, pivotOffsets, props, showPivots, showLabels, baseUnitH,
  onAnchorMouseDown, draggingBoneKey, isPaused, pinningMode,
  maskImage, maskTransform, offset, isReversed, jointModes
}) => {
    const getScaledDimension = useCallback((raw: number, key: keyof WalkingEngineProportions, axis: 'w' | 'h') => {
        return raw * baseUnitH * (props[key]?.[axis] || 1);
    }, [props, baseUnitH]);

    const calculateJointRotation = (boneKey: string, parentRot: number) => {
        const local = ((pose as any)[boneKey] || 0) + ((pivotOffsets as any)[boneKey] || 0);
        const mode = jointModes?.[boneKey as keyof WalkingEnginePivotOffsets] || 'standard';

        switch(mode) {
            case 'bend': return parentRot * 2 + local;
            case 'stretch': return local;
            default: return parentRot + local;
        }
    };

    const globalTransforms = useMemo(() => {
        const trans: Partial<Record<keyof WalkingEngineProportions, { position: Vector2D; rotation: number }>> = {};

        if (!isReversed) {
            // --- Standard Hierarchy (Waist as Root) ---
            const waistLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, 'waist', 'h');
            const waistRot = calculateJointRotation('waist', 0);
            trans.waist = { position: { x: 0, y: 0 }, rotation: waistRot };

            const torsoLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, 'torso', 'h');
            const torsoRot = calculateJointRotation('torso', waistRot);
            trans.torso = { position: addVec(trans.waist.position, rotateVec({ x: 0, y: -waistLen }, waistRot)), rotation: torsoRot };

            const collarLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, 'collar', 'h');
            const collarRot = calculateJointRotation('collar', torsoRot);
            trans.collar = { position: addVec(trans.torso.position, rotateVec({ x: 0, y: -torsoLen }, torsoRot)), rotation: collarRot };

            const neckRot = calculateJointRotation('neck', collarRot);
            trans.head = { position: addVec(trans.collar.position, rotateVec({ x: 0, y: -collarLen }, collarRot)), rotation: neckRot };

            // Arms and Legs follow collar and waist respectively
            ['r', 'l'].forEach(side => {
                const sx = (side === 'r' ? RIGGING.R_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER : RIGGING.L_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER) * baseUnitH;
                const shRot = calculateJointRotation(`${side}_shoulder`, collarRot + (side === 'l' ? 90 : -90));
                const collarEnd = addVec(trans.collar!.position, rotateVec({ x: 0, y: -collarLen }, collarRot));
                const shPos = addVec(collarEnd, rotateVec({ x: sx, y: 0 }, collarRot));
                trans[`${side}_upper_arm` as keyof WalkingEngineProportions] = { position: shPos, rotation: shRot };
                const upLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, `${side}_upper_arm` as any, 'h');
                const elRot = calculateJointRotation(`${side}_elbow`, shRot);
                const elPos = addVec(shPos, rotateVec({ x: 0, y: upLen }, shRot));
                trans[`${side}_lower_arm` as keyof WalkingEngineProportions] = { position: elPos, rotation: elRot };
                const lowLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, `${side}_lower_arm` as any, 'h');
                const handRot = calculateJointRotation(`${side}_hand`, elRot);
                trans[`${side}_hand` as keyof WalkingEngineProportions] = { position: addVec(elPos, rotateVec({ x: 0, y: lowLen }, elRot)), rotation: handRot };
            });

            ['r', 'l'].forEach(side => {
                const hipRot = calculateJointRotation(`${side}_hip`, waistRot);
                trans[`${side}_upper_leg` as keyof WalkingEngineProportions] = { position: trans.waist!.position, rotation: hipRot };
                const thighLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, `${side}_upper_leg` as any, 'h');
                const kneeRot = calculateJointRotation(`${side}_knee`, hipRot);
                const kneePos = addVec(trans.waist!.position, rotateVec({ x: 0, y: thighLen }, hipRot));
                trans[`${side}_lower_leg` as keyof WalkingEngineProportions] = { position: kneePos, rotation: kneeRot };
                const calfLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, `${side}_lower_leg` as any, 'h');
                const ankleRot = calculateJointRotation(`${side}_foot`, kneeRot);
                const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
                trans[`${side}_foot` as keyof WalkingEngineProportions] = { position: anklePos, rotation: ankleRot };
                const footLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, `${side}_foot` as any, 'h');
                const toeRot = calculateJointRotation(`${side}_toe`, ankleRot);
                trans[`${side}_toe` as keyof WalkingEngineProportions] = { position: addVec(anklePos, rotateVec({ x: 0, y: footLen }, ankleRot)), rotation: toeRot };
            });
        } else {
            // --- Reversed Hierarchy (Head as Root) ---
            const neckRot = calculateJointRotation('neck', 0);
            trans.head = { position: { x: 0, y: 0 }, rotation: neckRot };

            const collarLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, 'collar', 'h');
            const collarRot = calculateJointRotation('collar', neckRot);
            trans.collar = { position: addVec(trans.head.position, rotateVec({ x: 0, y: collarLen }, neckRot)), rotation: collarRot };

            const torsoLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, 'torso', 'h');
            const torsoRot = calculateJointRotation('torso', collarRot);
            trans.torso = { position: addVec(trans.collar.position, rotateVec({ x: 0, y: collarLen }, collarRot)), rotation: torsoRot };

            const waistLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, 'waist', 'h');
            const waistRot = calculateJointRotation('waist', torsoRot);
            trans.waist = { position: addVec(trans.torso.position, rotateVec({ x: 0, y: torsoLen }, torsoRot)), rotation: waistRot };

            // Arms and Legs follow the chain down
            ['r', 'l'].forEach(side => {
                const sx = (side === 'r' ? RIGGING.R_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER : RIGGING.L_SHOULDER_X_OFFSET_FROM_COLLAR_CENTER) * baseUnitH;
                const shRot = calculateJointRotation(`${side}_shoulder`, collarRot + (side === 'l' ? 90 : -90));
                const shPos = addVec(trans.collar!.position, rotateVec({ x: sx, y: 0 }, collarRot));
                trans[`${side}_upper_arm` as keyof WalkingEngineProportions] = { position: shPos, rotation: shRot };
                const upLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.UPPER_ARM, `${side}_upper_arm` as any, 'h');
                const elRot = calculateJointRotation(`${side}_elbow`, shRot);
                const elPos = addVec(shPos, rotateVec({ x: 0, y: upLen }, shRot));
                trans[`${side}_lower_arm` as keyof WalkingEngineProportions] = { position: elPos, rotation: elRot };
                const lowLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LOWER_ARM, `${side}_lower_arm` as any, 'h');
                const handRot = calculateJointRotation(`${side}_hand`, elRot);
                trans[`${side}_hand` as keyof WalkingEngineProportions] = { position: addVec(elPos, rotateVec({ x: 0, y: lowLen }, elRot)), rotation: handRot };
            });

            ['r', 'l'].forEach(side => {
                const hipRot = calculateJointRotation(`${side}_hip`, waistRot);
                trans[`${side}_upper_leg` as keyof WalkingEngineProportions] = { position: trans.waist!.position, rotation: hipRot };
                const thighLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, `${side}_upper_leg` as any, 'h');
                const kneeRot = calculateJointRotation(`${side}_knee`, hipRot);
                const kneePos = addVec(trans.waist!.position, rotateVec({ x: 0, y: thighLen }, hipRot));
                trans[`${side}_lower_leg` as keyof WalkingEngineProportions] = { position: kneePos, rotation: kneeRot };
                const calfLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, `${side}_lower_leg` as any, 'h');
                const ankleRot = calculateJointRotation(`${side}_foot`, kneeRot);
                const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
                trans[`${side}_foot` as keyof WalkingEngineProportions] = { position: anklePos, rotation: ankleRot };
                const footLen = getScaledDimension(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.FOOT, `${side}_foot` as any, 'h');
                const toeRot = calculateJointRotation(`${side}_toe`, ankleRot);
                trans[`${side}_toe` as keyof WalkingEngineProportions] = { position: addVec(anklePos, rotateVec({ x: 0, y: footLen }, ankleRot)), rotation: toeRot };
            });
        }

        return trans;
    }, [pose, pivotOffsets, getScaledDimension, baseUnitH, isReversed, jointModes]);

    return (
        <g>
            {RENDER_ORDER.map(partKey => {
                const p = partDefinitions[partKey];
                const t = globalTransforms[partKey];
                if (!p || !t) return null;

                const colorClass = (partKey === 'collar') ? 'fill-olive' : 
                                  (partKey === 'l_hand' && pivotOffsets.l_hand_flash) ? 'fill-accent-red' : 
                                  (partKey === 'r_hand' && pivotOffsets.r_hand_flash) ? 'fill-accent-red' : 'fill-mono-dark';

                return (
                    <g key={partKey} transform={`translate(${t.position.x}, ${t.position.y}) rotate(${t.rotation})`}>
                        <Bone 
                            rotation={0}
                            length={getScaledDimension(p.rawH, partKey, 'h')}
                            width={getScaledDimension(p.rawW, partKey, 'w')}
                            variant={p.variant}
                            drawsUpwards={p.drawsUpwards}
                            label={p.label}
                            boneKey={p.boneKey}
                            proportionKey={partKey}
                            showPivots={showPivots}
                            showLabel={showLabels}
                            onAnchorMouseDown={onAnchorMouseDown}
                            isBeingDragged={draggingBoneKey === p.boneKey}
                            isPausedAndPivotsVisible={true} 
                            colorClass={colorClass}
                            isPinned={pinningMode === 'rightFoot' && partKey === 'r_foot'}
                        />
                    </g>
                );
            })}
        </g>
    );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { WalkingEnginePose, WalkingEnginePivotOffsets, WalkingEngineProportions, Vector2D, MaskTransform, JointMode } from './types';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from './constants'; 
import { Mannequin } from './components/Mannequin';
import { SystemLogger } from './components/SystemLogger';

const T_POSE: WalkingEnginePivotOffsets = {
  waist: 0, neck: 0, collar: 0, torso: 0,
  l_shoulder: 0, r_shoulder: 0,
  l_elbow: 0, r_elbow: 0,
  l_hand: 0, r_hand: 0,
  l_hip: 0, r_hip: 0,
  l_knee: 0, r_knee: 0,
  l_foot: 0, r_foot: 0,
  l_toe: 0, r_toe: 0
};

const INITIAL_CHALLENGE_POSE: WalkingEnginePivotOffsets = {
  waist: 180, torso: 180, collar: 0, neck: 180,
  l_shoulder: -95, l_elbow: 180, l_hand: 180,
  r_shoulder: 95, r_elbow: 180, r_hand: 180,
  l_hip: 5, l_knee: 180, l_foot: 180, l_toe: 180,
  r_hip: -5, r_knee: 180, r_foot: 180, r_toe: 180
};

const RESTING_BASE_POSE: WalkingEnginePose = {
  waist: 0, neck: 0, collar: 0, torso: 0, 
  l_shoulder: 0, r_shoulder: 0, l_elbow: 0, r_elbow: 0, l_hand: 0, r_hand: 0, 
  l_hip: 0, r_hip: 0, l_knee: 0, r_knee: 0, l_foot: 0, r_foot: 0, l_toe: 0, r_toe: 0, 
  stride_phase: 0, y_offset: 0, x_offset: 0
};

const JOINT_KEYS: (keyof WalkingEnginePivotOffsets)[] = [
  'waist', 'torso', 'collar', 'neck',
  'l_shoulder', 'l_elbow', 'l_hand',
  'r_shoulder', 'r_elbow', 'r_hand',
  'l_hip', 'l_knee', 'l_foot', 'l_toe',
  'r_hip', 'r_knee', 'r_foot', 'r_toe'
];

const PROP_KEYS: (keyof WalkingEngineProportions)[] = [
  'head', 'collar', 'torso', 'waist',
  'l_upper_arm', 'l_lower_arm', 'l_hand',
  'r_upper_arm', 'r_lower_arm', 'r_hand',
  'l_upper_leg', 'l_lower_leg', 'l_foot', 'l_toe',
  'r_upper_leg', 'r_lower_leg', 'r_foot', 'r_toe'
];

const CHAIN_DEPTH: Record<string, number> = {
  waist: 0, torso: 1, collar: 2, neck: 3, head: 4,
  l_shoulder: 3, r_shoulder: 3, l_elbow: 4, r_elbow: 4, l_hand: 5, r_hand: 5,
  l_hip: 1, r_hip: 1, l_knee: 2, r_knee: 2, l_foot: 3, r_foot: 3, l_toe: 4, r_toe: 4
};

const snapOutEase = (t: number) => {
  const c4 = (2 * Math.PI) / 3;
  return t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

const EASING_FUNCTIONS = {
  linear: (t: number) => t,
  easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
  snapOut: snapOutEase,
};

interface HistoryState {
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
  timestamp: number;
}

interface SavedPoseEntry {
  id: number;
  name: string;
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
}

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [showLabels, setShowLabels] = useState(false);
  const [baseH] = useState(150);
  const [isConsoleVisible, setIsConsoleVisible] = useState(false);
  const [activeControlTab, setActiveControlTab] = useState<'pose' | 'props' | 'library'>('pose');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const [isCalibrated, setIsCalibrated] = useState(false);
  const [isCalibrating, setIsCalibrating] = useState(false);
  const [isPlayingTimelapse, setIsPlayingTimelapse] = useState(false);
  const [tokens, setTokens] = useState(0);
  const [lHandFlash, setLHandFlash] = useState(false);
  const [rHandFlash, setRHandFlash] = useState(false);
  const [saveConfirmation, setSaveConfirmation] = useState(false);

  const anomalySize = useMemo(() => 15, []);

  // New State: Joint Modes and Hierarchy
  const [jointModes, setJointModes] = useState<Record<keyof WalkingEnginePivotOffsets, JointMode>>(
    Object.fromEntries(JOINT_KEYS.map(k => [k, 'standard'])) as any
  );
  const [isReversed, setIsReversed] = useState(false);

  // Pinning State
  const [pinningMode, setPinningMode] = useState<'none' | 'rightFoot' | 'dual'>('none');
  const [pinOffset, setPinOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const pinnedWorldPosRef = useRef<Vector2D | null>(null);

  // Tween Configuration State
  const [tweenDuration, setTweenDuration] = useState(1000);
  const [tweenEasing, setTweenEasing] = useState<'linear' | 'easeInOutQuad' | 'snapOut'>('easeInOutQuad');
  const [isTweening, setIsTweening] = useState(false);

  // Interaction Tracking
  const lastInteractionTimeRef = useRef(Date.now());
  const draggingBoneKeyRef = useRef<keyof WalkingEnginePivotOffsets | null>(null);

  // Core State
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(INITIAL_CHALLENGE_POSE);
  const [props, setProps] = useState<WalkingEngineProportions>({
    head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 },
    l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 },
    r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 },
    l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 },
    r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 }
  });

  // Pose Library State
  const [savedPoses, setSavedPoses] = useState<SavedPoseEntry[]>([]);

  // Anomaly State
  const [anomaly, setAnomaly] = useState<Vector2D | null>(null);
  const anomalyRef = useRef<Vector2D | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [redoStack, setRedoStack] = useState<HistoryState[]>([]);

  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);
  const dragStartXRef = useRef(0);
  const dragStartPivotOffsetRef = useRef(0);

  const addLog = useCallback((message: string) => {
    setSystemLogs(prev => [...prev.slice(-49), { timestamp: new Date().toLocaleTimeString(), message }]);
  }, []);

  useEffect(() => {
    try {
      const storedPoses = localStorage.getItem('bitruvian_library');
      if (storedPoses) {
        const parsed = JSON.parse(storedPoses);
        if (Array.isArray(parsed)) setSavedPoses(parsed);
      }
    } catch (e) { console.error("Error loading library", e); }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('bitruvian_library', JSON.stringify(savedPoses));
    } catch (e) { console.error("Error saving library", e); }
  }, [savedPoses]);

  const awardTokens = useCallback((sourceBone: string) => {
    const timeSinceLastInteraction = Date.now() - lastInteractionTimeRef.current;
    let passiveMultiplier = (timeSinceLastInteraction > 1500 || isTweening) ? 2 : 1;
    let limbBonus = CHAIN_DEPTH[sourceBone] || 1;
    const gain = Math.floor(limbBonus * passiveMultiplier);
    setTokens(prev => prev + gain);
    addLog(`[SYSTEM]: POSE_PICKUP - UNIT TOKENS UPDATED (+${gain}) ${passiveMultiplier > 1 ? '[PASSIVE BONUS]' : ''} [${sourceBone.toUpperCase()} DEPTH: ${limbBonus}X]`);
  }, [addLog, isTweening]);

  const handleAnomalyResolve = useCallback((side: 'left' | 'right', boneKey: string) => {
    if (!anomalyRef.current) return;
    if (side === 'left') { setLHandFlash(true); setTimeout(() => setLHandFlash(false), 300); }
    else { setRHandFlash(true); setTimeout(() => setRHandFlash(false), 300); }
    awardTokens(boneKey);
    spawnAnomaly();
  }, [awardTokens]);

  const spawnAnomaly = useCallback(() => {
    const angle = Math.random() * Math.PI * 2;
    const distance = 150 + Math.random() * 350;
    const newAnom = { x: Math.cos(angle) * distance, y: -250 + Math.sin(angle) * distance };
    setAnomaly(newAnom);
    anomalyRef.current = newAnom;
  }, []);

  const calculateAnklePos = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);
    const waistRot = getRot('waist');
    const hipRot = waistRot + getRot('r_hip');
    const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg');
    const kneeRot = hipRot + getRot('r_knee');
    const kneePos = rotateVec({ x: 0, y: thighLen }, hipRot);
    const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg');
    const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
    return anklePos;
  }, [baseH]);

  const togglePinning = useCallback(() => {
    if (pinningMode === 'none') {
      const local = calculateAnklePos(pivotOffsets, props);
      pinnedWorldPosRef.current = { x: local.x + pinOffset.x, y: local.y - 50 + pinOffset.y };
      setPinningMode('rightFoot');
      addLog(`[SYSTEM]: PINNING ENABLED - RIGHT ANKLE ANCHORED.`);
    } else {
      setPinningMode('none');
      pinnedWorldPosRef.current = null;
      setPinOffset({ x: 0, y: 0 });
      addLog(`[SYSTEM]: PINNING DISABLED.`);
    }
  }, [pinningMode, calculateAnklePos, pivotOffsets, props, pinOffset, addLog]);

  const updatePinOffset = useCallback(() => {
    if (pinningMode === 'none' || !pinnedWorldPosRef.current) return;
    const currentLocal = calculateAnklePos(pivotOffsets, props);
    const nextX = pinnedWorldPosRef.current.x - currentLocal.x;
    const nextY = pinnedWorldPosRef.current.y - currentLocal.y + 50;
    setPinOffset({ x: nextX, y: nextY });
  }, [pinningMode, calculateAnklePos, pivotOffsets, props]);

  useEffect(() => {
    if (pinningMode !== 'none') updatePinOffset();
  }, [pivotOffsets, props, updatePinOffset]);

  const handleDrag = useCallback((e: MouseEvent) => {
    if (draggingBoneKey && !isPlayingTimelapse && !isTweening) {
      lastInteractionTimeRef.current = Date.now();
      const delta = (e.clientX - dragStartXRef.current) * 0.5;
      setPivotOffsets(p => ({ ...p, [draggingBoneKey]: dragStartPivotOffsetRef.current + delta }));
    }
  }, [draggingBoneKey, isPlayingTimelapse, isTweening]);

  useEffect(() => {
    const hu = () => { setDraggingBoneKey(null); draggingBoneKeyRef.current = null; };
    if (draggingBoneKey) {
      draggingBoneKeyRef.current = draggingBoneKey;
      window.addEventListener('mousemove', handleDrag);
      window.addEventListener('mouseup', hu);
    }
    return () => { window.removeEventListener('mousemove', handleDrag); window.removeEventListener('mouseup', hu); };
  }, [draggingBoneKey, handleDrag]);

  const setJointMode = (key: keyof WalkingEnginePivotOffsets, mode: JointMode) => {
    setJointModes(prev => ({ ...prev, [key]: mode }));
    addLog(`[SYSTEM]: JOINT_MODE_UPDATE - ${key.toUpperCase()} SET TO ${mode.toUpperCase()}`);
  };

  // --- Fix: Implemented runTween and saveCurrentPose ---

  /**
   * Linear interpolation for the pose offsets over time using requestAnimationFrame.
   */
  const runTween = useCallback((target: SavedPoseEntry) => {
    if (isTweening) return;
    setIsTweening(true);
    const startPivot = { ...pivotOffsets };
    const startTime = performance.now();

    const animate = (currentTime: number) => {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / tweenDuration, 1);
      const easedProgress = EASING_FUNCTIONS[tweenEasing](progress);

      const nextPivot = { ...startPivot };
      JOINT_KEYS.forEach(key => {
        const startValue = startPivot[key];
        const endValue = target.pivotOffsets[key];
        nextPivot[key] = startValue + (endValue - startValue) * easedProgress;
      });

      setPivotOffsets(nextPivot);

      if (progress < 1) {
        requestAnimationFrame(animate);
      } else {
        setIsTweening(false);
        setJointModes(target.jointModes);
        setProps(target.props);
        addLog(`[SYSTEM]: TWEEN_COMPLETE - POSE "${target.name.toUpperCase()}" LOADED.`);
      }
    };

    requestAnimationFrame(animate);
  }, [isTweening, pivotOffsets, tweenDuration, tweenEasing, addLog]);

  /**
   * Saves the current anatomical state into the local library and mirrors to localStorage.
   */
  const saveCurrentPose = useCallback(() => {
    const newEntry: SavedPoseEntry = {
      id: Date.now(),
      name: `Pose ${savedPoses.length + 1}`,
      pivotOffsets: { ...pivotOffsets },
      props: { ...props },
      jointModes: { ...jointModes }
    };
    setSavedPoses(prev => [...prev, newEntry]);
    setSaveConfirmation(true);
    addLog(`[SYSTEM]: POSE_SAVED - ENTITY ID: ${newEntry.id}`);
    setTimeout(() => setSaveConfirmation(false), 2000);
  }, [savedPoses, pivotOffsets, props, jointModes, addLog]);

  return (
    <div className="flex h-full w-full bg-paper font-mono text-ink overflow-hidden select-none">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto z-50">
          <div className="flex justify-between items-center border-b border-ridge pb-2">
            <h1 className="text-xl font-archaic tracking-widest uppercase italic">Bitruvius.Core</h1>
          </div>

          <div className="flex flex-col gap-2">
            {!isCalibrated ? (
              <button onClick={() => setIsCalibrated(true)} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase">INITIALIZE ENGINE</button>
            ) : (
              <div className="flex flex-col gap-2">
                <button onClick={() => setPivotOffsets({ ...T_POSE })} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase">T-POSE</button>
                <div className="grid grid-cols-2 gap-2">
                    <button 
                    onClick={togglePinning} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase ${pinningMode !== 'none' ? 'bg-accent-purple text-paper border-accent-purple' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {pinningMode !== 'none' ? 'FOOT PINNED' : 'PIN FOOT'}
                    </button>
                    <button 
                    onClick={() => { setIsReversed(!isReversed); addLog(`[SYSTEM]: HIERARCHY_REVERSED - ROOT SET TO ${!isReversed ? 'HEAD' : 'WAIST'}`); }} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase ${isReversed ? 'bg-accent-red text-paper border-accent-red' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {isReversed ? 'REVERSED' : 'REVERSE'}
                    </button>
                </div>
                <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border ${showPivots ? 'bg-selection text-paper' : 'border-ridge'}`}>ANCHORS: {showPivots ? 'ON' : 'OFF'}</button>
              </div>
            )}
          </div>

          <div className="flex border-b border-ridge">
            {(['pose', 'props', 'library'] as const).map(tab => (
              <button key={tab} onClick={() => setActiveControlTab(tab)} className={`flex-1 text-[9px] py-2 font-bold ${activeControlTab === tab ? 'text-selection border-b-2 border-selection' : 'opacity-40'}`}>{tab.toUpperCase()}</button>
            ))}
          </div>

          <div className="flex-grow flex flex-col min-h-0">
            {activeControlTab === 'pose' && (
              <div className="flex flex-col gap-3 overflow-y-auto custom-scrollbar py-2">
                {JOINT_KEYS.map(k => (
                  <div key={k} className="p-1 border-b border-ridge/30 last:border-0">
                    <div className="flex justify-between text-[8px] uppercase font-bold text-mono-light mb-1">
                        <span>{k}</span>
                        <div className="flex gap-1">
                            {(['standard', 'bend', 'stretch'] as JointMode[]).map(m => (
                                <button 
                                    key={m} 
                                    onClick={() => setJointMode(k, m)}
                                    className={`px-1 rounded-sm border ${jointModes[k] === m ? 'bg-selection text-paper border-selection' : 'border-ridge text-mono-mid opacity-40 hover:opacity-100'}`}
                                >
                                    {m[0].toUpperCase()}
                                </button>
                            ))}
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <input type="range" min="-180" max="180" value={pivotOffsets[k]} onChange={e => setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))} className="flex-1 accent-selection h-1" />
                        <span className="text-[8px] font-mono text-mono-mid w-8 text-right">{Math.round(pivotOffsets[k])}°</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
            {activeControlTab === 'library' && (
              <div className="flex flex-col h-full gap-2">
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                  {savedPoses.map(pe => (
                    <div key={pe.id} className="flex items-center justify-between p-2 border-b border-ridge hover:bg-white/40 group">
                      <span className="text-[10px] uppercase font-bold">{pe.name}</span>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100">
                        <button onClick={() => { setPivotOffsets({ ...pe.pivotOffsets }); setJointModes({ ...pe.jointModes }); }} className="text-[8px] px-2 py-1 bg-selection text-paper uppercase">Load</button>
                        <button onClick={() => runTween(pe)} className="text-[8px] px-2 py-1 bg-mono-mid text-paper uppercase">Tween</button>
                      </div>
                    </div>
                  ))}
                </div>
                <button 
                  onClick={saveCurrentPose} 
                  className={`w-full py-3 text-[10px] font-bold uppercase transition-all ${saveConfirmation ? 'bg-accent-green text-paper' : 'bg-selection text-paper'}`}
                >
                  {saveConfirmation ? '✓ SAVED' : 'SAVE POSE'}
                </button>
              </div>
            )}
          </div>

          <div className="mt-auto pt-4"><SystemLogger logs={systemLogs} isVisible={true} historyCount={tokens} /></div>
        </div>
      )}

      <div className="flex-1 relative bg-paper flex items-center justify-center overflow-hidden" onClick={() => !isCalibrated && !isCalibrating && setIsCalibrated(true)}>
        <div className="absolute top-4 right-4 z-50 text-right">
          <div className="text-[10px] text-mono-mid uppercase tracking-widest">Unit Tokens</div>
          <div className="text-2xl font-archaic">{tokens.toLocaleString()}</div>
        </div>

        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 border border-ridge bg-white rounded-full transition-transform hover:scale-110 active:scale-95"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7" /></svg></button>

        {!isCalibrated && !isCalibrating && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none bg-paper/20">
            <h2 className="text-6xl font-archaic uppercase tracking-tighter">Bitruvian Station</h2>
            <p className="text-[10px] uppercase tracking-[0.5em] animate-pulse">Touch to Wake Core</p>
          </div>
        )}

        <svg viewBox="-500 -700 1000 1400" className="w-full h-full overflow-visible relative z-10">
          <g transform={`translate(${pinOffset.x}, ${-50 + pinOffset.y})`}>
            <Mannequin 
              pose={RESTING_BASE_POSE} 
              pivotOffsets={{...pivotOffsets, l_hand_flash: lHandFlash, r_hand_flash: rHandFlash} as any} 
              props={props} 
              showPivots={showPivots && isCalibrated} 
              showLabels={showLabels} 
              baseUnitH={baseH} 
              onAnchorMouseDown={(k, x) => { setDraggingBoneKey(k); dragStartXRef.current = x; dragStartPivotOffsetRef.current = pivotOffsets[k]; }} 
              draggingBoneKey={draggingBoneKey} 
              isPaused={true} 
              pinningMode={pinningMode} 
              offset={pinOffset} 
              isReversed={isReversed}
              jointModes={jointModes}
            />
          </g>
          {anomaly && (
            <g transform={`translate(${anomaly.x}, ${anomaly.y})`}>
              <rect x={-anomalySize / 2} y={-anomalySize / 2} width={anomalySize} height={anomalySize} className="fill-ink hover:fill-accent-red cursor-crosshair transition-colors" />
            </g>
          )}
        </svg>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { WalkingEnginePose, WalkingEnginePivotOffsets, WalkingEngineProportions, Vector2D, MaskTransform, JointMode } from './types';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from './constants'; 
import { Mannequin } from './components/Mannequin';
import { SystemLogger } from './components/SystemLogger';

const T_POSE: WalkingEnginePivotOffsets = {
  waist: 0, neck: 0, collar: 0, torso: 0,
  l_shoulder: 0, r_shoulder: 0,
  l_elbow: 0, r_elbow: 0,
  l_hand: 0, r_hand: 0,
  l_hip: 0, r_hip: 0,
  l_knee: 0, r_knee: 0,
  l_foot: 0, r_foot: 0,
  l_toe: 0, r_toe: 0
};

const INITIAL_CHALLENGE_POSE: WalkingEnginePivotOffsets = {
  waist: 180, torso: 180, collar: 0, neck: 180,
  l_shoulder: -95, l_elbow: 180, l_hand: 180,
  r_shoulder: 95, r_elbow: 180, r_hand: 180,
  l_hip: 5, l_knee: 180, l_foot: 180, l_toe: 180,
  r_hip: -5, r_knee: 180, r_foot: 180, r_toe: 180
};

const RESTING_BASE_POSE: WalkingEnginePose = {
  waist: 0, neck: 0, collar: 0, torso: 0, 
  l_shoulder: 0, r_shoulder: 0, l_elbow: 0, r_elbow: 0, l_hand: 0, r_hand: 0, 
  l_hip: 0, r_hip: 0, l_knee: 0, r_knee: 0, l_foot: 0, r_foot: 0, l_toe: 0, r_toe: 0, 
  stride_phase: 0, y_offset: 0, x_offset: 0
};

const JOINT_KEYS: (keyof WalkingEnginePivotOffsets)[] = [
  'waist', 'torso', 'collar', 'neck',
  'l_shoulder', 'l_elbow', 'l_hand',
  'r_shoulder', 'r_elbow', 'r_hand',
  'l_hip', 'l_knee', 'l_foot', 'l_toe',
  'r_hip', 'r_knee', 'r_foot', 'r_toe'
];

const PROP_KEYS: (keyof WalkingEngineProportions)[] = [
  'head', 'collar', 'torso', 'waist',
  'l_upper_arm', 'l_lower_arm', 'l_hand',
  'r_upper_arm', 'r_lower_arm', 'r_hand',
  'l_upper_leg', 'l_lower_leg', 'l_foot', 'l_toe',
  'r_upper_leg', 'r_lower_leg', 'r_foot', 'r_toe'
];

const CHAIN_DEPTH: Record<string, number> = {
  waist: 0, torso: 1, collar: 2, neck: 3, head: 4,
  l_shoulder: 3, r_shoulder: 3, l_elbow: 4, r_elbow: 4, l_hand: 5, r_hand: 5,
  l_hip: 1, r_hip: 1, l_knee: 2, r_knee: 2, l_foot: 3, r_foot: 3, l_toe: 4, r_toe: 4
};

const snapOutEase = (t: number) => {
  const c4 = (2 * Math.PI) / 3;
  return t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

const EASING_FUNCTIONS = {
  linear: (t: number) => t,
  easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
  snapOut: snapOutEase,
};

interface HistoryState {
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
  timestamp: number;
}

interface SavedPoseEntry {
  id: number;
  name: string;
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
}

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [showLabels, setShowLabels] = useState(false);
  const [baseH] = useState(150);
  const [isConsoleVisible, setIsConsoleVisible] = useState(false);
  const [activeControlTab, setActiveControlTab] = useState<'pose' | 'props' | 'library'>('pose');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const [isCalibrated, setIsCalibrated] = useState(false);
  const [isCalibrating, setIsCalibrating] = useState(false);
  const [isPlayingTimelapse, setIsPlayingTimelapse] = useState(false);
  const [tokens, setTokens] = useState(0);
  const [lHandFlash, setLHandFlash] = useState(false);
  const [rHandFlash, setRHandFlash] = useState(false);
  const [saveConfirmation, setSaveConfirmation] = useState(false);

  const anomalySize = useMemo(() => 15, []);

  // New State: Joint Modes and Hierarchy
  const [jointModes, setJointModes] = useState<Record<keyof WalkingEnginePivotOffsets, JointMode>>(
    Object.fromEntries(JOINT_KEYS.map(k => [k, 'standard'])) as any
  );
  const [isReversed, setIsReversed] = useState(false);

  // Pinning State
  const [pinningMode, setPinningMode] = useState<'none' | 'rightFoot' | 'dual'>('none');
  const [pinOffset, setPinOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const pinnedWorldPosRef = useRef<Vector2D | null>(null);

  // Tween Configuration State
  const [tweenDuration, setTweenDuration] = useState(1000);
  const [tweenEasing, setTweenEasing] = useState<'linear' | 'easeInOutQuad' | 'snapOut'>('easeInOutQuad');
  const [isTweening, setIsTweening] = useState(false);

  // Interaction Tracking
  const lastInteractionTimeRef = useRef(Date.now());
  const draggingBoneKeyRef = useRef<keyof WalkingEnginePivotOffsets | null>(null);

  // Core State
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(INITIAL_CHALLENGE_POSE);
  const [props, setProps] = useState<WalkingEngineProportions>({
    head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 },
    l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 },
    r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 },
    l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 },
    r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 }
  });

  // Pose Library State
  const [savedPoses, setSavedPoses] = useState<SavedPoseEntry[]>([]);

  // Anomaly State
  const [anomaly, setAnomaly] = useState<Vector2D | null>(null);
  const anomalyRef = useRef<Vector2D | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [redoStack, setRedoStack] = useState<HistoryState[]>([]);

  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);
  const dragStartXRef = useRef(0);
  const dragStartPivotOffsetRef = useRef(0);

  const addLog = useCallback((message: string) => {
    setSystemLogs(prev => [...prev.slice(-49), { timestamp: new Date().toLocaleTimeString(), message }]);
  }, []);

  useEffect(() => {
    try {
      const storedPoses = localStorage.getItem('bitruvian_library');
      if (storedPoses) {
        const parsed = JSON.parse(storedPoses);
        if (Array.isArray(parsed)) setSavedPoses(parsed);
      }
    } catch (e) { console.error("Error loading library", e); }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('bitruvian_library', JSON.stringify(savedPoses));
    } catch (e) { console.error("Error saving library", e); }
  }, [savedPoses]);

  const awardTokens = useCallback((sourceBone: string) => {
    const timeSinceLastInteraction = Date.now() - lastInteractionTimeRef.current;
    let passiveMultiplier = (timeSinceLastInteraction > 1500 || isTweening) ? 2 : 1;
    let limbBonus = CHAIN_DEPTH[sourceBone] || 1;
    const gain = Math.floor(limbBonus * passiveMultiplier);
    setTokens(prev => prev + gain);
    addLog(`[SYSTEM]: POSE_PICKUP - UNIT TOKENS UPDATED (+${gain}) ${passiveMultiplier > 1 ? '[PASSIVE BONUS]' : ''} [${sourceBone.toUpperCase()} DEPTH: ${limbBonus}X]`);
  }, [addLog, isTweening]);

  const handleAnomalyResolve = useCallback((side: 'left' | 'right', boneKey: string) => {
    if (!anomalyRef.current) return;
    if (side === 'left') { setLHandFlash(true); setTimeout(() => setLHandFlash(false), 300); }
    else { setRHandFlash(true); setTimeout(() => setRHandFlash(false), 300); }
    awardTokens(boneKey);
    spawnAnomaly();
  }, [awardTokens]);

  const spawnAnomaly = useCallback(() => {
    const angle = Math.random() * Math.PI * 2;
    const distance = 150 + Math.random() * 350;
    const newAnom = { x: Math.cos(angle) * distance, y: -250 + Math.sin(angle) * distance };
    setAnomaly(newAnom);
    anomalyRef.current = newAnom;
  }, []);

  const calculateAnklePos = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);
    const waistRot = getRot('waist');
    const hipRot = waistRot + getRot('r_hip');
    const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg');
    const kneeRot = hipRot + getRot('r_knee');
    const kneePos = rotateVec({ x: 0, y: thighLen }, hipRot);
    const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg');
    const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
    return anklePos;
  }, [baseH]);

  const togglePinning = useCallback(() => {
    if (pinningMode === 'none') {
      const local = calculateAnklePos(pivotOffsets, props);
      pinnedWorldPosRef.current = { x: local.x + pinOffset.x, y: local.y - 50 + pinOffset.y };
      setPinningMode('rightFoot');
      addLog(`[SYSTEM]: PINNING ENABLED - RIGHT ANKLE ANCHORED.`);
    } else {
      setPinningMode('none');
      pinnedWorldPosRef.current = null;
      setPinOffset({ x: 0, y: 0 });
      addLog(`[SYSTEM]: PINNING DISABLED.`);
    }
  }, [pinningMode, calculateAnklePos, pivotOffsets, props, pinOffset, addLog]);

  const updatePinOffset = useCallback(() => {
    if (pinningMode === 'none' || !pinnedWorldPosRef.current) return;
    const currentLocal = calculateAnklePos(pivotOffsets, props);
    const nextX = pinnedWorldPosRef.current.x - currentLocal.x;
    const nextY = pinnedWorldPosRef.current.y - currentLocal.y + 50;
    setPinOffset({ x: nextX, y: nextY });
  }, [pinningMode, calculateAnklePos, pivotOffsets, props]);

  useEffect(() => {
    if (pinningMode !== 'none') updatePinOffset();
  }, [pivotOffsets, props, updatePinOffset]);

  const handleDrag = useCallback((e: MouseEvent) => {
    if (draggingBoneKey && !isPlayingTimelapse && !isTweening) {
      lastInteractionTimeRef.current = Date.now();
      const delta = (e.clientX - dragStartXRef.current) * 0.5;
      setPivotOffsets(p => ({ ...p, [draggingBoneKey]: dragStartPivotOffsetRef.current + delta }));
    }
  }, [draggingBoneKey, isPlayingTimelapse, isTweening]);

  useEffect(() => {
    const hu = () => { setDraggingBoneKey(null); draggingBoneKeyRef.current = null; };
    if (draggingBoneKey) {
      draggingBoneKeyRef.current = draggingBoneKey;
      window.addEventListener('mousemove', handleDrag);
      window.addEventListener('mouseup', hu);
    }
    return () => { window.removeEventListener('mousemove', handleDrag); window.removeEventListener('mouseup', hu); };
  }, [draggingBoneKey, handleDrag]);

  const setJointMode = (key: keyof WalkingEnginePivotOffsets, mode: JointMode) => {
    setJointModes(prev => ({ ...prev, [key]: mode }));
    addLog(`[SYSTEM]: JOINT_MODE_UPDATE - ${key.toUpperCase()} SET TO ${mode.toUpperCase()}`);
  };

  const runTween = useCallback((target: SavedPoseEntry) => {
    if (isTweening) return;
    setIsTweening(true);
    const startPivot = { ...pivotOffsets };
    const startTime = performance.now();

    const animate = (currentTime: number) => {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / tweenDuration, 1);
      const easedProgress = EASING_FUNCTIONS[tweenEasing](progress);

      const nextPivot = { ...startPivot };
      JOINT_KEYS.forEach(key => {
        const startValue = startPivot[key];
        const endValue = target.pivotOffsets[key];
        nextPivot[key] = startValue + (endValue - startValue) * easedProgress;
      });

      setPivotOffsets(nextPivot);

      if (progress < 1) {
        requestAnimationFrame(animate);
      } else {
        setIsTweening(false);
        setJointModes(target.jointModes);
        setProps(target.props);
        addLog(`[SYSTEM]: TWEEN_COMPLETE - POSE "${target.name.toUpperCase()}" LOADED.`);
      }
    };

    requestAnimationFrame(animate);
  }, [isTweening, pivotOffsets, tweenDuration, tweenEasing, addLog]);

  const saveCurrentPose = useCallback(() => {
    const newEntry: SavedPoseEntry = {
      id: Date.now(),
      name: `Pose ${savedPoses.length + 1}`,
      pivotOffsets: { ...pivotOffsets },
      props: { ...props },
      jointModes: { ...jointModes }
    };
    setSavedPoses(prev => [...prev, newEntry]);
    setSaveConfirmation(true);
    addLog(`[SYSTEM]: POSE_SAVED - ENTITY ID: ${newEntry.id}`);
    setTimeout(() => setSaveConfirmation(false), 2000);
  }, [savedPoses, pivotOffsets, props, jointModes, addLog]);

  return (
    <div className="flex h-full w-full bg-paper font-mono text-ink overflow-hidden select-none">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto z-50">
          <div className="flex justify-between items-center border-b border-ridge pb-2">
            <h1 className="text-xl font-archaic tracking-widest uppercase italic">Bitruvius.Core</h1>
          </div>

          <div className="flex flex-col gap-2">
            {!isCalibrated ? (
              <button onClick={() => setIsCalibrated(true)} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase hover:scale-[1.02] active:scale-[0.98] transition-transform">INITIALIZE ENGINE</button>
            ) : (
              <div className="flex flex-col gap-2">
                <button onClick={() => setPivotOffsets({ ...T_POSE })} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase hover:scale-[1.02] active:scale-[0.98] transition-transform">T-POSE</button>
                <div className="grid grid-cols-2 gap-2">
                    <button 
                    onClick={togglePinning} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase hover:scale-[1.05] active:scale-[0.95] ${pinningMode !== 'none' ? 'bg-accent-purple text-paper border-accent-purple shadow-lg scale-[1.05]' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {pinningMode !== 'none' ? 'FOOT PINNED' : 'PIN FOOT'}
                    </button>
                    <button 
                    onClick={() => { setIsReversed(!isReversed); addLog(`[SYSTEM]: HIERARCHY_REVERSED - ROOT SET TO ${!isReversed ? 'HEAD' : 'WAIST'}`); }} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase hover:scale-[1.05] active:scale-[0.95] ${isReversed ? 'bg-accent-red text-paper border-accent-red shadow-lg scale-[1.05]' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {isReversed ? 'REVERSED' : 'REVERSE'}
                    </button>
                </div>
                <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border transition-all ${showPivots ? 'bg-selection text-paper' : 'border-ridge'}`}>ANCHORS: {showPivots ? 'ON' : 'OFF'}</button>
              </div>
            )}
          </div>

          <div className="flex border-b border-ridge">
            {(['pose', 'props', 'library'] as const).map(tab => (
              <button key={tab} onClick={() => setActiveControlTab(tab)} className={`flex-1 text-[9px] py-2 font-bold transition-all ${activeControlTab === tab ? 'text-selection border-b-2 border-selection bg-white/40' : 'opacity-40 hover:opacity-100'}`}>{tab.toUpperCase()}</button>
            ))}
          </div>

          <div className="flex-grow flex flex-col min-h-0">
            {activeControlTab === 'pose' && (
              <div className="flex flex-col gap-3 overflow-y-auto custom-scrollbar py-2 pr-1">
                {JOINT_KEYS.map(k => (
                  <div key={k} className="p-2 border border-ridge/20 rounded hover:bg-white/30 transition-colors">
                    <div className="flex justify-between items-center mb-2">
                        <span className="text-[10px] uppercase font-bold text-ink">{k.replace(/_/g, ' ')}</span>
                        <div className="flex gap-1">
                            {(['standard', 'bend', 'stretch'] as JointMode[]).map(m => (
                                <button 
                                    key={m} 
                                    onClick={() => setJointMode(k, m)}
                                    title={m.toUpperCase()}
                                    className={`w-5 h-5 flex items-center justify-center rounded-sm text-[9px] font-bold border transition-all hover:scale-110 active:scale-90 ${jointModes[k] === m ? 'bg-selection text-paper border-selection shadow-md translate-y-[-1px]' : 'border-ridge text-mono-mid opacity-40 hover:opacity-100'}`}
                                >
                                    {m[0].toUpperCase()}
                                </button>
                            ))}
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <input type="range" min="-180" max="180" value={pivotOffsets[k]} onChange={e => setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))} className="flex-1 accent-selection h-1 cursor-ew-resize" />
                        <span className="text-[9px] font-mono text-mono-mid w-10 text-right tabular-nums">{Math.round(pivotOffsets[k])}°</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
            {activeControlTab === 'library' && (
              <div className="flex flex-col h-full gap-2">
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                  {savedPoses.map(pe => (
                    <div key={pe.id} className="flex items-center justify-between p-2 border-b border-ridge hover:bg-white/40 group transition-colors">
                      <span className="text-[10px] uppercase font-bold">{pe.name}</span>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => { setPivotOffsets({ ...pe.pivotOffsets }); setJointModes({ ...pe.jointModes }); }} className="text-[8px] px-2 py-1 bg-selection text-paper uppercase hover:scale-105 active:scale-95 transition-transform">Load</button>
                        <button onClick={() => runTween(pe)} className="text-[8px] px-2 py-1 bg-mono-mid text-paper uppercase hover:scale-105 active:scale-95 transition-transform">Tween</button>
                      </div>
                    </div>
                  ))}
                </div>
                <button 
                  onClick={saveCurrentPose} 
                  className={`w-full py-3 text-[10px] font-bold uppercase transition-all hover:scale-[1.02] active:scale-[0.98] ${saveConfirmation ? 'bg-accent-green text-paper scale-[1.02] shadow-lg' : 'bg-selection text-paper shadow-md'}`}
                >
                  {saveConfirmation ? '✓ SAVED' : 'SAVE POSE'}
                </button>
              </div>
            )}
          </div>

          <div className="mt-auto pt-4"><SystemLogger logs={systemLogs} isVisible={true} historyCount={tokens} /></div>
        </div>
      )}

      <div className="flex-1 relative bg-paper flex items-center justify-center overflow-hidden" onClick={() => !isCalibrated && !isCalibrating && setIsCalibrated(true)}>
        <div className="absolute top-4 right-4 z-50 text-right">
          <div className="text-[10px] text-mono-mid uppercase tracking-widest">Unit Tokens</div>
          <div className="text-2xl font-archaic text-ink">{tokens.toLocaleString()}</div>
        </div>

        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 border border-ridge bg-white rounded-full transition-all hover:scale-110 active:scale-95 shadow-lg"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7" /></svg></button>

        {!isCalibrated && !isCalibrating && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none bg-paper/20">
            <h2 className="text-6xl font-archaic uppercase tracking-tighter text-ink">Bitruvian Station</h2>
            <p className="text-[10px] uppercase tracking-[0.5em] animate-pulse text-mono-mid">Touch to Wake Core</p>
          </div>
        )}

        <svg viewBox="-500 -700 1000 1400" className="w-full h-full overflow-visible relative z-10 drop-shadow-2xl">
          <g transform={`translate(${pinOffset.x}, ${-50 + pinOffset.y})`}>
            <Mannequin 
              pose={RESTING_BASE_POSE} 
              pivotOffsets={{...pivotOffsets, l_hand_flash: lHandFlash, r_hand_flash: rHandFlash} as any} 
              props={props} 
              showPivots={showPivots && isCalibrated} 
              showLabels={showLabels} 
              baseUnitH={baseH} 
              onAnchorMouseDown={(k, x) => { setDraggingBoneKey(k); dragStartXRef.current = x; dragStartPivotOffsetRef.current = pivotOffsets[k]; }} 
              draggingBoneKey={draggingBoneKey} 
              isPaused={true} 
              pinningMode={pinningMode} 
              offset={pinOffset} 
              isReversed={isReversed}
              jointModes={jointModes}
            />
          </g>
          {anomaly && (
            <g transform={`translate(${anomaly.x}, ${anomaly.y})`}>
              <rect x={-anomalySize / 2} y={-anomalySize / 2} width={anomalySize} height={anomalySize} className="fill-ink hover:fill-accent-red cursor-crosshair transition-all hover:scale-150 active:scale-90" />
            </g>
          )}
        </svg>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { WalkingEnginePose, WalkingEnginePivotOffsets, WalkingEngineProportions, Vector2D, MaskTransform, JointMode } from './types';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from './constants'; 
import { Mannequin } from './components/Mannequin';
import { SystemLogger } from './components/SystemLogger';

const T_POSE: WalkingEnginePivotOffsets = {
  waist: 0, neck: 0, collar: 0, torso: 0,
  l_shoulder: 0, r_shoulder: 0,
  l_elbow: 0, r_elbow: 0,
  l_hand: 0, r_hand: 0,
  l_hip: 0, r_hip: 0,
  l_knee: 0, r_knee: 0,
  l_foot: 0, r_foot: 0,
  l_toe: 0, r_toe: 0
};

const INITIAL_CHALLENGE_POSE: WalkingEnginePivotOffsets = {
  waist: 180, torso: 180, collar: 0, neck: 180,
  l_shoulder: -95, l_elbow: 180, l_hand: 180,
  r_shoulder: 95, r_elbow: 180, r_hand: 180,
  l_hip: 5, l_knee: 180, l_foot: 180, l_toe: 180,
  r_hip: -5, r_knee: 180, r_foot: 180, r_toe: 180
};

const RESTING_BASE_POSE: WalkingEnginePose = {
  waist: 0, neck: 0, collar: 0, torso: 0, 
  l_shoulder: 0, r_shoulder: 0, l_elbow: 0, r_elbow: 0, l_hand: 0, r_hand: 0, 
  l_hip: 0, r_hip: 0, l_knee: 0, r_knee: 0, l_foot: 0, r_foot: 0, l_toe: 0, r_toe: 0, 
  stride_phase: 0, y_offset: 0, x_offset: 0
};

const JOINT_KEYS: (keyof WalkingEnginePivotOffsets)[] = [
  'waist', 'torso', 'collar', 'neck',
  'l_shoulder', 'l_elbow', 'l_hand',
  'r_shoulder', 'r_elbow', 'r_hand',
  'l_hip', 'l_knee', 'l_foot', 'l_toe',
  'r_hip', 'r_knee', 'r_foot', 'r_toe'
];

const PROP_KEYS: (keyof WalkingEngineProportions)[] = [
  'head', 'collar', 'torso', 'waist',
  'l_upper_arm', 'l_lower_arm', 'l_hand',
  'r_upper_arm', 'r_lower_arm', 'r_hand',
  'l_upper_leg', 'l_lower_leg', 'l_foot', 'l_toe',
  'r_upper_leg', 'r_lower_leg', 'r_foot', 'r_toe'
];

const CHAIN_DEPTH: Record<string, number> = {
  waist: 0, torso: 1, collar: 2, neck: 3, head: 4,
  l_shoulder: 3, r_shoulder: 3, l_elbow: 4, r_elbow: 4, l_hand: 5, r_hand: 5,
  l_hip: 1, r_hip: 1, l_knee: 2, r_knee: 2, l_foot: 3, r_foot: 3, l_toe: 4, r_toe: 4
};

const snapOutEase = (t: number) => {
  const c4 = (2 * Math.PI) / 3;
  return t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

const EASING_FUNCTIONS = {
  linear: (t: number) => t,
  easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
  snapOut: snapOutEase,
};

interface HistoryState {
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
  timestamp: number;
}

interface SavedPoseEntry {
  id: number;
  name: string;
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
}

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [showLabels, setShowLabels] = useState(false);
  const [baseH] = useState(150);
  const [isConsoleVisible, setIsConsoleVisible] = useState(false);
  const [activeControlTab, setActiveControlTab] = useState<'pose' | 'props' | 'library'>('pose');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const [isCalibrated, setIsCalibrated] = useState(false);
  const [isCalibrating, setIsCalibrating] = useState(false);
  const [tokens, setTokens] = useState(0);
  const [lHandFlash, setLHandFlash] = useState(false);
  const [rHandFlash, setRHandFlash] = useState(false);
  const [saveConfirmation, setSaveConfirmation] = useState(false);

  const anomalySize = useMemo(() => 15, []);

  // New State: Joint Modes and Hierarchy
  const [jointModes, setJointModes] = useState<Record<keyof WalkingEnginePivotOffsets, JointMode>>(
    Object.fromEntries(JOINT_KEYS.map(k => [k, 'standard'])) as any
  );
  const [isReversed, setIsReversed] = useState(false);
  const [lastPoppedKey, setLastPoppedKey] = useState<string | null>(null);

  // Pinning State
  const [pinningMode, setPinningMode] = useState<'none' | 'rightFoot' | 'dual'>('none');
  const [pinOffset, setPinOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const pinnedWorldPosRef = useRef<Vector2D | null>(null);

  // Tween Configuration State
  const [tweenDuration, setTweenDuration] = useState(1000);
  const [tweenEasing, setTweenEasing] = useState<'linear' | 'easeInOutQuad' | 'snapOut'>('easeInOutQuad');
  const [isTweening, setIsTweening] = useState(false);

  // Interaction Tracking
  const lastInteractionTimeRef = useRef(Date.now());
  const draggingBoneKeyRef = useRef<keyof WalkingEnginePivotOffsets | null>(null);

  // Core State
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(INITIAL_CHALLENGE_POSE);
  const [props, setProps] = useState<WalkingEngineProportions>({
    head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 },
    l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 },
    r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 },
    l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 },
    r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 }
  });

  // Pose Library State
  const [savedPoses, setSavedPoses] = useState<SavedPoseEntry[]>([]);

  // Anomaly State
  const [anomaly, setAnomaly] = useState<Vector2D | null>(null);
  const anomalyRef = useRef<Vector2D | null>(null);

  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);
  const dragStartXRef = useRef(0);
  const dragStartPivotOffsetRef = useRef(0);

  const addLog = useCallback((message: string) => {
    setSystemLogs(prev => [...prev.slice(-49), { timestamp: new Date().toLocaleTimeString(), message }]);
  }, []);

  useEffect(() => {
    try {
      const storedPoses = localStorage.getItem('bitruvian_library');
      if (storedPoses) {
        const parsed = JSON.parse(storedPoses);
        if (Array.isArray(parsed)) setSavedPoses(parsed);
      }
    } catch (e) { console.error("Error loading library", e); }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('bitruvian_library', JSON.stringify(savedPoses));
    } catch (e) { console.error("Error saving library", e); }
  }, [savedPoses]);

  const awardTokens = useCallback((sourceBone: string) => {
    const timeSinceLastInteraction = Date.now() - lastInteractionTimeRef.current;
    let passiveMultiplier = (timeSinceLastInteraction > 1500 || isTweening) ? 2 : 1;
    let limbBonus = CHAIN_DEPTH[sourceBone] || 1;
    const gain = Math.floor(limbBonus * passiveMultiplier);
    setTokens(prev => prev + gain);
    addLog(`[SYSTEM]: POSE_PICKUP - UNIT TOKENS UPDATED (+${gain}) ${passiveMultiplier > 1 ? '[PASSIVE BONUS]' : ''} [${sourceBone.toUpperCase()} DEPTH: ${limbBonus}X]`);
  }, [addLog, isTweening]);

  const handleAnomalyResolve = useCallback((side: 'left' | 'right', boneKey: string) => {
    if (!anomalyRef.current) return;
    if (side === 'left') { setLHandFlash(true); setTimeout(() => setLHandFlash(false), 300); }
    else { setRHandFlash(true); setTimeout(() => setRHandFlash(false), 300); }
    awardTokens(boneKey);
    spawnAnomaly();
  }, [awardTokens]);

  const spawnAnomaly = useCallback(() => {
    const angle = Math.random() * Math.PI * 2;
    const distance = 150 + Math.random() * 350;
    const newAnom = { x: Math.cos(angle) * distance, y: -250 + Math.sin(angle) * distance };
    setAnomaly(newAnom);
    anomalyRef.current = newAnom;
  }, []);

  const calculateAnklePos = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);
    const waistRot = getRot('waist');
    const hipRot = waistRot + getRot('r_hip');
    const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg');
    const kneeRot = hipRot + getRot('r_knee');
    const kneePos = rotateVec({ x: 0, y: thighLen }, hipRot);
    const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg');
    const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
    return anklePos;
  }, [baseH]);

  const togglePinning = useCallback(() => {
    setLastPoppedKey('pin-foot');
    setTimeout(() => setLastPoppedKey(null), 300);
    if (pinningMode === 'none') {
      const local = calculateAnklePos(pivotOffsets, props);
      pinnedWorldPosRef.current = { x: local.x + pinOffset.x, y: local.y - 50 + pinOffset.y };
      setPinningMode('rightFoot');
      addLog(`[SYSTEM]: PINNING ENABLED - RIGHT ANKLE ANCHORED.`);
    } else {
      setPinningMode('none');
      pinnedWorldPosRef.current = null;
      setPinOffset({ x: 0, y: 0 });
      addLog(`[SYSTEM]: PINNING DISABLED.`);
    }
  }, [pinningMode, calculateAnklePos, pivotOffsets, props, pinOffset, addLog]);

  const updatePinOffset = useCallback(() => {
    if (pinningMode === 'none' || !pinnedWorldPosRef.current) return;
    const currentLocal = calculateAnklePos(pivotOffsets, props);
    const nextX = pinnedWorldPosRef.current.x - currentLocal.x;
    const nextY = pinnedWorldPosRef.current.y - currentLocal.y + 50;
    setPinOffset({ x: nextX, y: nextY });
  }, [pinningMode, calculateAnklePos, pivotOffsets, props]);

  useEffect(() => {
    if (pinningMode !== 'none') updatePinOffset();
  }, [pivotOffsets, props, updatePinOffset]);

  const handleDrag = useCallback((e: MouseEvent) => {
    if (draggingBoneKey && !isTweening) {
      lastInteractionTimeRef.current = Date.now();
      const delta = (e.clientX - dragStartXRef.current) * 0.5;
      setPivotOffsets(p => ({ ...p, [draggingBoneKey]: dragStartPivotOffsetRef.current + delta }));
    }
  }, [draggingBoneKey, isTweening]);

  useEffect(() => {
    const hu = () => { setDraggingBoneKey(null); draggingBoneKeyRef.current = null; };
    if (draggingBoneKey) {
      draggingBoneKeyRef.current = draggingBoneKey;
      window.addEventListener('mousemove', handleDrag);
      window.addEventListener('mouseup', hu);
    }
    return () => { window.removeEventListener('mousemove', handleDrag); window.removeEventListener('mouseup', hu); };
  }, [draggingBoneKey, handleDrag]);

  const setJointMode = (key: keyof WalkingEnginePivotOffsets, mode: JointMode) => {
    setLastPoppedKey(`${key}-${mode}`);
    setTimeout(() => setLastPoppedKey(null), 300);
    setJointModes(prev => ({ ...prev, [key]: mode }));
    addLog(`[SYSTEM]: JOINT_MODE_UPDATE - ${key.toUpperCase()} SET TO ${mode.toUpperCase()}`);
  };

  const runTween = useCallback((target: SavedPoseEntry) => {
    if (isTweening) return;
    setIsTweening(true);
    const startPivot = { ...pivotOffsets };
    const startTime = performance.now();

    const animate = (currentTime: number) => {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / tweenDuration, 1);
      const easedProgress = EASING_FUNCTIONS[tweenEasing](progress);

      const nextPivot = { ...startPivot };
      JOINT_KEYS.forEach(key => {
        const startValue = startPivot[key];
        const endValue = target.pivotOffsets[key];
        nextPivot[key] = startValue + (endValue - startValue) * easedProgress;
      });

      setPivotOffsets(nextPivot);

      if (progress < 1) {
        requestAnimationFrame(animate);
      } else {
        setIsTweening(false);
        setJointModes(target.jointModes);
        setProps(target.props);
        addLog(`[SYSTEM]: TWEEN_COMPLETE - POSE "${target.name.toUpperCase()}" LOADED.`);
      }
    };

    requestAnimationFrame(animate);
  }, [isTweening, pivotOffsets, tweenDuration, tweenEasing, addLog]);

  const saveCurrentPose = useCallback(() => {
    const newEntry: SavedPoseEntry = {
      id: Date.now(),
      name: `Pose ${savedPoses.length + 1}`,
      pivotOffsets: { ...pivotOffsets },
      props: { ...props },
      jointModes: { ...jointModes }
    };
    setSavedPoses(prev => [...prev, newEntry]);
    setSaveConfirmation(true);
    addLog(`[SYSTEM]: POSE_SAVED - ENTITY ID: ${newEntry.id}`);
    setTimeout(() => setSaveConfirmation(false), 2000);
  }, [savedPoses, pivotOffsets, props, jointModes, addLog]);

  return (
    <div className="flex h-full w-full bg-paper font-mono text-ink overflow-hidden select-none">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto z-50">
          <div className="flex justify-between items-center border-b border-ridge pb-2">
            <h1 className="text-xl font-archaic tracking-widest uppercase italic">Bitruvius.Core</h1>
          </div>

          <div className="flex flex-col gap-2">
            {!isCalibrated ? (
              <button onClick={() => setIsCalibrated(true)} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase hover:scale-[1.02] active:scale-[0.98] transition-transform btn-pop">INITIALIZE ENGINE</button>
            ) : (
              <div className="flex flex-col gap-2">
                <button onClick={() => setPivotOffsets({ ...T_POSE })} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase hover:scale-[1.02] active:scale-[0.98] transition-transform btn-pop">T-POSE</button>
                <div className="grid grid-cols-2 gap-2">
                    <button 
                    onClick={togglePinning} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase hover:scale-[1.05] active:scale-[0.95] ${lastPoppedKey === 'pin-foot' ? 'animate-pop' : ''} ${pinningMode !== 'none' ? 'bg-accent-purple text-paper border-accent-purple shadow-lg scale-[1.05]' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {pinningMode !== 'none' ? 'FOOT PINNED' : 'PIN FOOT'}
                    </button>
                    <button 
                    onClick={() => { 
                      setLastPoppedKey('reverse');
                      setTimeout(() => setLastPoppedKey(null), 300);
                      setIsReversed(!isReversed); 
                      addLog(`[SYSTEM]: HIERARCHY_REVERSED - ROOT SET TO ${!isReversed ? 'HEAD' : 'WAIST'}`); 
                    }} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase hover:scale-[1.05] active:scale-[0.95] ${lastPoppedKey === 'reverse' ? 'animate-pop' : ''} ${isReversed ? 'bg-accent-red text-paper border-accent-red shadow-lg scale-[1.05]' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {isReversed ? 'REVERSED' : 'REVERSE'}
                    </button>
                </div>
                <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border transition-all ${showPivots ? 'bg-selection text-paper' : 'border-ridge'}`}>ANCHORS: {showPivots ? 'ON' : 'OFF'}</button>
              </div>
            )}
          </div>

          <div className="flex border-b border-ridge">
            {(['pose', 'props', 'library'] as const).map(tab => (
              <button key={tab} onClick={() => setActiveControlTab(tab)} className={`flex-1 text-[9px] py-2 font-bold transition-all ${activeControlTab === tab ? 'text-selection border-b-2 border-selection bg-white/40' : 'opacity-40 hover:opacity-100'}`}>{tab.toUpperCase()}</button>
            ))}
          </div>

          <div className="flex-grow flex flex-col min-h-0">
            {activeControlTab === 'pose' && (
              <div className="flex flex-col gap-2 overflow-y-auto custom-scrollbar py-2 pr-1">
                {JOINT_KEYS.map(k => (
                  <div key={k} className="p-2 border border-ridge/20 rounded hover:bg-white/30 transition-colors">
                    <div className="flex justify-between items-center mb-1">
                        <div className="flex items-center gap-2">
                            <span className="text-[10px] uppercase font-bold text-ink">{k.replace(/_/g, ' ')}</span>
                            <div className="flex gap-1">
                                {(['standard', 'bend', 'stretch'] as JointMode[]).map(m => (
                                    <button 
                                        key={m} 
                                        onClick={() => setJointMode(k, m)}
                                        title={m.toUpperCase()}
                                        className={`w-5 h-5 flex items-center justify-center rounded-sm text-[8px] font-bold border transition-all hover:scale-110 active:scale-90 ${lastPoppedKey === `${k}-${m}` ? 'animate-pop' : ''} ${jointModes[k] === m ? 'bg-selection text-paper border-selection shadow-md translate-y-[-1px]' : 'border-ridge text-mono-mid opacity-40 hover:opacity-100'}`}
                                    >
                                        {m[0].toUpperCase()}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <span className="text-[8px] font-mono text-mono-mid tabular-nums">{Math.round(pivotOffsets[k])}°</span>
                    </div>
                    <input type="range" min="-180" max="180" value={pivotOffsets[k]} onChange={e => setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))} className="w-full accent-selection h-1 cursor-ew-resize" />
                  </div>
                ))}
              </div>
            )}
            {activeControlTab === 'library' && (
              <div className="flex flex-col h-full gap-2">
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                  {savedPoses.map(pe => (
                    <div key={pe.id} className="flex items-center justify-between p-2 border-b border-ridge hover:bg-white/40 group transition-colors">
                      <span className="text-[10px] uppercase font-bold">{pe.name}</span>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => { setPivotOffsets({ ...pe.pivotOffsets }); setJointModes({ ...pe.jointModes }); }} className="text-[8px] px-2 py-1 bg-selection text-paper uppercase hover:scale-105 active:scale-95 transition-transform">Load</button>
                        <button onClick={() => runTween(pe)} className="text-[8px] px-2 py-1 bg-mono-mid text-paper uppercase hover:scale-105 active:scale-95 transition-transform">Tween</button>
                      </div>
                    </div>
                  ))}
                </div>
                <button 
                  onClick={saveCurrentPose} 
                  className={`w-full py-3 text-[10px] font-bold uppercase transition-all hover:scale-[1.02] active:scale-[0.98] ${saveConfirmation ? 'bg-accent-green text-paper scale-[1.02] shadow-lg' : 'bg-selection text-paper shadow-md'}`}
                >
                  {saveConfirmation ? '✓ SAVED' : 'SAVE POSE'}
                </button>
              </div>
            )}
          </div>

          <div className="mt-auto pt-4"><SystemLogger logs={systemLogs} isVisible={true} historyCount={tokens} /></div>
        </div>
      )}

      <div className="flex-1 relative bg-paper flex items-center justify-center overflow-hidden" onClick={() => !isCalibrated && !isCalibrating && setIsCalibrated(true)}>
        <div className="absolute top-4 right-4 z-50 text-right">
          <div className="text-[10px] text-mono-mid uppercase tracking-widest">Unit Tokens</div>
          <div className="text-2xl font-archaic text-ink">{tokens.toLocaleString()}</div>
        </div>

        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 border border-ridge bg-white rounded-full transition-all hover:scale-110 active:scale-95 shadow-lg"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7" /></svg></button>

        {!isCalibrated && !isCalibrating && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none bg-paper/20">
            <h2 className="text-6xl font-archaic uppercase tracking-tighter text-ink">Bitruvian Station</h2>
            <p className="text-[10px] uppercase tracking-[0.5em] animate-pulse text-mono-mid">Touch to Wake Core</p>
          </div>
        )}

        <svg viewBox="-500 -700 1000 1400" className="w-full h-full overflow-visible relative z-10 drop-shadow-2xl">
          <g transform={`translate(${pinOffset.x}, ${-50 + pinOffset.y})`}>
            <Mannequin 
              pose={RESTING_BASE_POSE} 
              pivotOffsets={{...pivotOffsets, l_hand_flash: lHandFlash, r_hand_flash: rHandFlash} as any} 
              props={props} 
              showPivots={showPivots && isCalibrated} 
              showLabels={showLabels} 
              baseUnitH={baseH} 
              onAnchorMouseDown={(k, x) => { setDraggingBoneKey(k); dragStartXRef.current = x; dragStartPivotOffsetRef.current = pivotOffsets[k]; }} 
              draggingBoneKey={draggingBoneKey} 
              isPaused={true} 
              pinningMode={pinningMode} 
              offset={pinOffset} 
              isReversed={isReversed}
              jointModes={jointModes}
            />
          </g>
          {anomaly && (
            <g transform={`translate(${anomaly.x}, ${anomaly.y})`}>
              <rect x={-anomalySize / 2} y={-anomalySize / 2} width={anomalySize} height={anomalySize} className="fill-ink hover:fill-accent-red cursor-crosshair transition-all hover:scale-150 active:scale-90" />
            </g>
          )}
        </svg>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { WalkingEnginePose, WalkingEnginePivotOffsets, WalkingEngineProportions, Vector2D, MaskTransform, JointMode } from './types';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from './constants'; 
import { Mannequin } from './components/Mannequin';
import { SystemLogger } from './components/SystemLogger';

const T_POSE: WalkingEnginePivotOffsets = {
  waist: 0, neck: 0, collar: 0, torso: 0,
  l_shoulder: 0, r_shoulder: 0,
  l_elbow: 0, r_elbow: 0,
  l_hand: 0, r_hand: 0,
  l_hip: 0, r_hip: 0,
  l_knee: 0, r_knee: 0,
  l_foot: 0, r_foot: 0,
  l_toe: 0, r_toe: 0
};

const INITIAL_CHALLENGE_POSE: WalkingEnginePivotOffsets = {
  waist: 180, torso: 180, collar: 0, neck: 180,
  l_shoulder: -95, l_elbow: 180, l_hand: 180,
  r_shoulder: 95, r_elbow: 180, r_hand: 180,
  l_hip: 5, l_knee: 180, l_foot: 180, l_toe: 180,
  r_hip: -5, r_knee: 180, r_foot: 180, r_toe: 180
};

const RESTING_BASE_POSE: WalkingEnginePose = {
  waist: 0, neck: 0, collar: 0, torso: 0, 
  l_shoulder: 0, r_shoulder: 0, l_elbow: 0, r_elbow: 0, l_hand: 0, r_hand: 0, 
  l_hip: 0, r_hip: 0, l_knee: 0, r_knee: 0, l_foot: 0, r_foot: 0, l_toe: 0, r_toe: 0, 
  stride_phase: 0, y_offset: 0, x_offset: 0
};

const JOINT_KEYS: (keyof WalkingEnginePivotOffsets)[] = [
  'waist', 'torso', 'collar', 'neck',
  'l_shoulder', 'l_elbow', 'l_hand',
  'r_shoulder', 'r_elbow', 'r_hand',
  'l_hip', 'l_knee', 'l_foot', 'l_toe',
  'r_hip', 'r_knee', 'r_foot', 'r_toe'
];

const CHAIN_DEPTH: Record<string, number> = {
  waist: 0, torso: 1, collar: 2, neck: 3, head: 4,
  l_shoulder: 3, r_shoulder: 3, l_elbow: 4, r_elbow: 4, l_hand: 5, r_hand: 5,
  l_hip: 1, r_hip: 1, l_knee: 2, r_knee: 2, l_foot: 3, r_foot: 3, l_toe: 4, r_toe: 4
};

const snapOutEase = (t: number) => {
  const c4 = (2 * Math.PI) / 3;
  return t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

const EASING_FUNCTIONS = {
  linear: (t: number) => t,
  easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
  snapOut: snapOutEase,
};

interface HistoryState {
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
  timestamp: number;
}

interface SavedPoseEntry {
  id: number;
  name: string;
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
}

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [showLabels, setShowLabels] = useState(false);
  const [baseH] = useState(150);
  const [isConsoleVisible, setIsConsoleVisible] = useState(false);
  const [activeControlTab, setActiveControlTab] = useState<'pose' | 'props' | 'library'>('pose');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const [isCalibrated, setIsCalibrated] = useState(false);
  const [tokens, setTokens] = useState(0);
  const [lHandFlash, setLHandFlash] = useState(false);
  const [rHandFlash, setRHandFlash] = useState(false);
  const [saveConfirmation, setSaveConfirmation] = useState(false);

  const anomalySize = useMemo(() => 15, []);

  // New State: Joint Modes and Hierarchy
  const [jointModes, setJointModes] = useState<Record<keyof WalkingEnginePivotOffsets, JointMode>>(
    Object.fromEntries(JOINT_KEYS.map(k => [k, 'standard'])) as any
  );
  const [isReversed, setIsReversed] = useState(false);
  const [lastPoppedKey, setLastPoppedKey] = useState<string | null>(null);

  // Pinning State
  const [pinningMode, setPinningMode] = useState<'none' | 'rightFoot' | 'dual'>('none');
  const [pinOffset, setPinOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const pinnedWorldPosRef = useRef<Vector2D | null>(null);

  // Tween Configuration State
  const [tweenDuration, setTweenDuration] = useState(1000);
  const [tweenEasing, setTweenEasing] = useState<'linear' | 'easeInOutQuad' | 'snapOut'>('easeInOutQuad');
  const [isTweening, setIsTweening] = useState(false);

  // Interaction Tracking
  const lastInteractionTimeRef = useRef(Date.now());
  const draggingBoneKeyRef = useRef<keyof WalkingEnginePivotOffsets | null>(null);

  // Core State
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(INITIAL_CHALLENGE_POSE);
  const [props, setProps] = useState<WalkingEngineProportions>({
    head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 },
    l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 },
    r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 },
    l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 },
    r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 }
  });

  const [savedPoses, setSavedPoses] = useState<SavedPoseEntry[]>([]);
  const [anomaly, setAnomaly] = useState<Vector2D | null>(null);
  const anomalyRef = useRef<Vector2D | null>(null);

  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);
  const dragStartXRef = useRef(0);
  const dragStartPivotOffsetRef = useRef(0);

  const addLog = useCallback((message: string) => {
    setSystemLogs(prev => [...prev.slice(-49), { timestamp: new Date().toLocaleTimeString(), message }]);
  }, []);

  useEffect(() => {
    try {
      const storedPoses = localStorage.getItem('bitruvian_library');
      if (storedPoses) {
        const parsed = JSON.parse(storedPoses);
        if (Array.isArray(parsed)) setSavedPoses(parsed);
      }
    } catch (e) { console.error("Error loading library", e); }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('bitruvian_library', JSON.stringify(savedPoses));
    } catch (e) { console.error("Error saving library", e); }
  }, [savedPoses]);

  const awardTokens = useCallback((sourceBone: string) => {
    const timeSinceLastInteraction = Date.now() - lastInteractionTimeRef.current;
    let passiveMultiplier = (timeSinceLastInteraction > 1500 || isTweening) ? 2 : 1;
    let limbBonus = CHAIN_DEPTH[sourceBone] || 1;
    const gain = Math.floor(limbBonus * passiveMultiplier);
    setTokens(prev => prev + gain);
    addLog(`[SYSTEM]: POSE_PICKUP - UNIT TOKENS UPDATED (+${gain}) ${passiveMultiplier > 1 ? '[PASSIVE BONUS]' : ''} [${sourceBone.toUpperCase()} DEPTH: ${limbBonus}X]`);
  }, [addLog, isTweening]);

  const spawnAnomaly = useCallback(() => {
    const angle = Math.random() * Math.PI * 2;
    const distance = 150 + Math.random() * 350;
    const newAnom = { x: Math.cos(angle) * distance, y: -250 + Math.sin(angle) * distance };
    setAnomaly(newAnom);
    anomalyRef.current = newAnom;
  }, []);

  const calculateAnklePos = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);
    const waistRot = getRot('waist');
    const hipRot = waistRot + getRot('r_hip');
    const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg');
    const kneeRot = hipRot + getRot('r_knee');
    const kneePos = rotateVec({ x: 0, y: thighLen }, hipRot);
    const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg');
    const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
    return anklePos;
  }, [baseH]);

  const togglePinning = useCallback(() => {
    setLastPoppedKey('pin-foot');
    setTimeout(() => setLastPoppedKey(null), 300);
    if (pinningMode === 'none') {
      const local = calculateAnklePos(pivotOffsets, props);
      pinnedWorldPosRef.current = { x: local.x + pinOffset.x, y: local.y - 50 + pinOffset.y };
      setPinningMode('rightFoot');
      addLog(`[SYSTEM]: PINNING ENABLED - RIGHT ANKLE ANCHORED.`);
    } else {
      setPinningMode('none');
      pinnedWorldPosRef.current = null;
      setPinOffset({ x: 0, y: 0 });
      addLog(`[SYSTEM]: PINNING DISABLED.`);
    }
  }, [pinningMode, calculateAnklePos, pivotOffsets, props, pinOffset, addLog]);

  const updatePinOffset = useCallback(() => {
    if (pinningMode === 'none' || !pinnedWorldPosRef.current) return;
    const currentLocal = calculateAnklePos(pivotOffsets, props);
    const nextX = pinnedWorldPosRef.current.x - currentLocal.x;
    const nextY = pinnedWorldPosRef.current.y - currentLocal.y + 50;
    setPinOffset({ x: nextX, y: nextY });
  }, [pinningMode, calculateAnklePos, pivotOffsets, props]);

  useEffect(() => {
    if (pinningMode !== 'none') updatePinOffset();
  }, [pivotOffsets, props, updatePinOffset]);

  const handleDrag = useCallback((e: MouseEvent) => {
    if (draggingBoneKey && !isTweening) {
      lastInteractionTimeRef.current = Date.now();
      const delta = (e.clientX - dragStartXRef.current) * 0.5;
      setPivotOffsets(p => ({ ...p, [draggingBoneKey]: dragStartPivotOffsetRef.current + delta }));
    }
  }, [draggingBoneKey, isTweening]);

  useEffect(() => {
    const hu = () => { setDraggingBoneKey(null); draggingBoneKeyRef.current = null; };
    if (draggingBoneKey) {
      draggingBoneKeyRef.current = draggingBoneKey;
      window.addEventListener('mousemove', handleDrag);
      window.addEventListener('mouseup', hu);
    }
    return () => { window.removeEventListener('mousemove', handleDrag); window.removeEventListener('mouseup', hu); };
  }, [draggingBoneKey, handleDrag]);

  const setJointMode = (key: keyof WalkingEnginePivotOffsets, mode: JointMode) => {
    setLastPoppedKey(`${key}-${mode}`);
    setTimeout(() => setLastPoppedKey(null), 300);
    // If clicking an already active mode, toggle it back to standard
    const nextMode = jointModes[key] === mode ? 'standard' : mode;
    setJointModes(prev => ({ ...prev, [key]: nextMode }));
    addLog(`[SYSTEM]: JOINT_MODE_UPDATE - ${key.toUpperCase()} SET TO ${nextMode.toUpperCase()}`);
  };

  const runTween = useCallback((target: SavedPoseEntry) => {
    if (isTweening) return;
    setIsTweening(true);
    const startPivot = { ...pivotOffsets };
    let startTime: number | null = null;

    const animate = (currentTime: number) => {
      if (!startTime) startTime = currentTime;
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / tweenDuration, 1);
      const easedProgress = EASING_FUNCTIONS[tweenEasing](progress);

      const nextPivot = { ...startPivot };
      JOINT_KEYS.forEach(key => {
        const startValue = startPivot[key];
        const endValue = target.pivotOffsets[key];
        nextPivot[key] = startValue + (endValue - startValue) * easedProgress;
      });

      setPivotOffsets(nextPivot);

      if (progress < 1) {
        requestAnimationFrame(animate);
      } else {
        setIsTweening(false);
        setJointModes(target.jointModes);
        setProps(target.props);
        addLog(`[SYSTEM]: TWEEN_COMPLETE - POSE "${target.name.toUpperCase()}" LOADED.`);
      }
    };

    requestAnimationFrame(animate);
  }, [isTweening, pivotOffsets, tweenDuration, tweenEasing, addLog]);

  const saveCurrentPose = useCallback(() => {
    const newEntry: SavedPoseEntry = {
      id: Date.now(),
      name: `Pose ${savedPoses.length + 1}`,
      pivotOffsets: { ...pivotOffsets },
      props: { ...props },
      jointModes: { ...jointModes }
    };
    setSavedPoses(prev => [...prev, newEntry]);
    setSaveConfirmation(true);
    addLog(`[SYSTEM]: POSE_SAVED - ENTITY ID: ${newEntry.id}`);
    setTimeout(() => setSaveConfirmation(false), 2000);
  }, [savedPoses, pivotOffsets, props, jointModes, addLog]);

  return (
    <div className="flex h-full w-full bg-paper font-mono text-ink overflow-hidden select-none">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto z-50">
          <div className="flex justify-between items-center border-b border-ridge pb-2">
            <h1 className="text-xl font-archaic tracking-widest uppercase italic">Bitruvius.Core</h1>
          </div>

          <div className="flex flex-col gap-2">
            {!isCalibrated ? (
              <button onClick={() => setIsCalibrated(true)} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase hover:scale-[1.02] active:scale-[0.98] transition-transform btn-pop">INITIALIZE ENGINE</button>
            ) : (
              <div className="flex flex-col gap-2">
                <button 
                  onClick={() => {
                    setLastPoppedKey('t-pose');
                    setTimeout(() => setLastPoppedKey(null), 300);
                    runTween({ id: 0, name: 'T-POSE', pivotOffsets: T_POSE, props: props, jointModes: Object.fromEntries(JOINT_KEYS.map(k => [k, 'standard'])) as any });
                  }} 
                  className={`text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase transition-all hover:scale-[1.02] active:scale-[0.98] btn-pop ${lastPoppedKey === 't-pose' ? 'animate-pop' : ''}`}
                >
                  T-POSE
                </button>
                <div className="grid grid-cols-2 gap-2">
                    <button 
                    onClick={togglePinning} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase hover:scale-[1.05] active:scale-[0.95] ${lastPoppedKey === 'pin-foot' ? 'animate-pop' : ''} ${pinningMode !== 'none' ? 'bg-accent-purple text-paper border-accent-purple shadow-lg scale-[1.05]' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {pinningMode !== 'none' ? 'FOOT PINNED' : 'PIN FOOT'}
                    </button>
                    <button 
                    onClick={() => { 
                      setLastPoppedKey('reverse');
                      setTimeout(() => setLastPoppedKey(null), 300);
                      setIsReversed(!isReversed); 
                      addLog(`[SYSTEM]: HIERARCHY_REVERSED - ROOT SET TO ${!isReversed ? 'HEAD' : 'WAIST'}`); 
                    }} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase hover:scale-[1.05] active:scale-[0.95] ${lastPoppedKey === 'reverse' ? 'animate-pop' : ''} ${isReversed ? 'bg-accent-red text-paper border-accent-red shadow-lg scale-[1.05]' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {isReversed ? 'REVERSED' : 'REVERSE'}
                    </button>
                </div>
                <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border transition-all ${showPivots ? 'bg-selection text-paper' : 'border-ridge'}`}>ANCHORS: {showPivots ? 'ON' : 'OFF'}</button>
              </div>
            )}
          </div>

          <div className="flex border-b border-ridge">
            {(['pose', 'props', 'library'] as const).map(tab => (
              <button key={tab} onClick={() => setActiveControlTab(tab)} className={`flex-1 text-[9px] py-2 font-bold transition-all ${activeControlTab === tab ? 'text-selection border-b-2 border-selection bg-white/40' : 'opacity-40 hover:opacity-100'}`}>{tab.toUpperCase()}</button>
            ))}
          </div>

          <div className="flex-grow flex flex-col min-h-0">
            {activeControlTab === 'pose' && (
              <div className="flex flex-col gap-2 overflow-y-auto custom-scrollbar py-2 pr-1">
                {JOINT_KEYS.map(k => (
                  <div key={k} className="p-2 border border-ridge/20 rounded hover:bg-white/30 transition-colors">
                    <div className="flex justify-between items-center mb-1">
                        <div className="flex items-center gap-2">
                            <span className="text-[10px] uppercase font-bold text-ink">{k.replace(/_/g, ' ')}</span>
                            <div className="flex gap-1">
                                {(['bend', 'stretch'] as JointMode[]).map(m => (
                                    <button 
                                        key={m} 
                                        onClick={() => setJointMode(k, m)}
                                        title={m.toUpperCase()}
                                        className={`w-5 h-5 flex items-center justify-center rounded-sm text-[8px] font-bold border transition-all hover:scale-110 active:scale-90 ${lastPoppedKey === `${k}-${m}` ? 'animate-pop' : ''} ${jointModes[k] === m ? 'bg-selection text-paper border-selection shadow-md translate-y-[-1px]' : 'border-ridge text-mono-mid opacity-40 hover:opacity-100'}`}
                                    >
                                        {m === 'bend' ? 'B' : 'T'}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <span className="text-[8px] font-mono text-mono-mid tabular-nums">{Math.round(pivotOffsets[k])}°</span>
                    </div>
                    <input type="range" min="-180" max="180" value={pivotOffsets[k]} onChange={e => !isTweening && setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))} className="w-full accent-selection h-1 cursor-ew-resize" />
                  </div>
                ))}
              </div>
            )}
            {activeControlTab === 'library' && (
              <div className="flex flex-col h-full gap-2">
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                  {savedPoses.map(pe => (
                    <div key={pe.id} className="flex items-center justify-between p-2 border-b border-ridge hover:bg-white/40 group transition-colors">
                      <span className="text-[10px] uppercase font-bold">{pe.name}</span>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => { setPivotOffsets({ ...pe.pivotOffsets }); setJointModes({ ...pe.jointModes }); }} className="text-[8px] px-2 py-1 bg-selection text-paper uppercase hover:scale-105 active:scale-95 transition-transform">Load</button>
                        <button onClick={() => runTween(pe)} className="text-[8px] px-2 py-1 bg-mono-mid text-paper uppercase hover:scale-105 active:scale-95 transition-transform">Tween</button>
                      </div>
                    </div>
                  ))}
                </div>
                <button 
                  onClick={saveCurrentPose} 
                  className={`w-full py-3 text-[10px] font-bold uppercase transition-all hover:scale-[1.02] active:scale-[0.98] ${saveConfirmation ? 'bg-accent-green text-paper scale-[1.02] shadow-lg' : 'bg-selection text-paper shadow-md'}`}
                >
                  {saveConfirmation ? '✓ SAVED' : 'SAVE POSE'}
                </button>
              </div>
            )}
          </div>

          <div className="mt-auto pt-4"><SystemLogger logs={systemLogs} isVisible={true} historyCount={tokens} /></div>
        </div>
      )}

      <div className="flex-1 relative bg-paper flex items-center justify-center overflow-hidden" onClick={() => !isCalibrated && setIsCalibrated(true)}>
        <div className="absolute top-4 right-4 z-50 text-right">
          <div className="text-[10px] text-mono-mid uppercase tracking-widest">Unit Tokens</div>
          <div className="text-2xl font-archaic text-ink">{tokens.toLocaleString()}</div>
        </div>

        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 border border-ridge bg-white rounded-full transition-all hover:scale-110 active:scale-95 shadow-lg"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7" /></svg></button>

        {!isCalibrated && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none bg-paper/20">
            <h2 className="text-6xl font-archaic uppercase tracking-tighter text-ink">Bitruvian Station</h2>
            <p className="text-[10px] uppercase tracking-[0.5em] animate-pulse text-mono-mid">Touch to Wake Core</p>
          </div>
        )}

        <svg viewBox="-500 -700 1000 1400" className="w-full h-full overflow-visible relative z-10 drop-shadow-2xl">
          <g transform={`translate(${pinOffset.x}, ${-50 + pinOffset.y})`}>
            <Mannequin 
              pose={RESTING_BASE_POSE} 
              pivotOffsets={{...pivotOffsets, l_hand_flash: lHandFlash, r_hand_flash: rHandFlash} as any} 
              props={props} 
              showPivots={showPivots && isCalibrated} 
              showLabels={showLabels} 
              baseUnitH={baseH} 
              onAnchorMouseDown={(k, x) => { setDraggingBoneKey(k); dragStartXRef.current = x; dragStartPivotOffsetRef.current = pivotOffsets[k]; }} 
              draggingBoneKey={draggingBoneKey} 
              isPaused={true} 
              pinningMode={pinningMode} 
              offset={pinOffset} 
              isReversed={isReversed}
              jointModes={jointModes}
            />
          </g>
          {anomaly && (
            <g transform={`translate(${anomaly.x}, ${anomaly.y})`}>
              <rect x={-anomalySize / 2} y={-anomalySize / 2} width={anomalySize} height={anomalySize} className="fill-ink hover:fill-accent-red cursor-crosshair transition-all hover:scale-150 active:scale-90" />
            </g>
          )}
        </svg>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { WalkingEnginePose, WalkingEnginePivotOffsets, WalkingEngineProportions, Vector2D, MaskTransform, JointMode } from './types';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from './constants'; 
import { Mannequin } from './components/Mannequin';
import { SystemLogger } from './components/SystemLogger';

const T_POSE: WalkingEnginePivotOffsets = {
  waist: 0, neck: 0, collar: 0, torso: 0,
  l_shoulder: 0, r_shoulder: 0,
  l_elbow: 0, r_elbow: 0,
  l_hand: 0, r_hand: 0,
  l_hip: 180, r_hip: 180, // Legs pointing straight down
  l_knee: 0, r_knee: 0,
  l_foot: 0, r_foot: 0,
  l_toe: 0, r_toe: 0
};

const INITIAL_CHALLENGE_POSE: WalkingEnginePivotOffsets = {
  waist: 0, torso: 0, collar: 0, neck: 0, // Reset these to 0 for a more "natural" starting point for challenges.
  l_shoulder: 0, l_elbow: 0, l_hand: 0,
  r_shoulder: 0, r_elbow: 0, r_hand: 0,
  l_hip: 180, l_knee: 0, l_foot: 0, l_toe: 0, // Legs start pointing down
  r_hip: 180, r_knee: 0, r_foot: 0, r_toe: 0
};

const RESTING_BASE_POSE: WalkingEnginePose = {
  waist: 0, neck: 0, collar: 0, torso: 0, 
  l_shoulder: 0, r_shoulder: 0, l_elbow: 0, r_elbow: 0, l_hand: 0, r_hand: 0, 
  l_hip: 0, r_hip: 0, l_knee: 0, r_knee: 0, l_foot: 0, r_foot: 0, l_toe: 0, r_toe: 0, 
  stride_phase: 0, y_offset: 0, x_offset: 0
};

const JOINT_KEYS: (keyof WalkingEnginePivotOffsets)[] = [
  'waist', 'torso', 'collar', 'neck',
  'l_shoulder', 'l_elbow', 'l_hand',
  'r_shoulder', 'r_elbow', 'r_hand',
  'l_hip', 'l_knee', 'l_foot', 'l_toe',
  'r_hip', 'r_knee', 'r_foot', 'r_toe'
];

const CHAIN_DEPTH: Record<string, number> = {
  waist: 0, torso: 1, collar: 2, neck: 3, head: 4,
  l_shoulder: 3, r_shoulder: 3, l_elbow: 4, r_elbow: 4, l_hand: 5, r_hand: 5,
  l_hip: 1, r_hip: 1, l_knee: 2, r_knee: 2, l_foot: 3, r_foot: 3, l_toe: 4, r_toe: 4
};

const snapOutEase = (t: number) => {
  const c4 = (2 * Math.PI) / 3;
  return t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

const EASING_FUNCTIONS = {
  linear: (t: number) => t,
  easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
  snapOut: snapOutEase,
};

interface HistoryState {
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
  timestamp: number;
}

interface SavedPoseEntry {
  id: number;
  name: string;
  pivotOffsets: WalkingEnginePivotOffsets;
  props: WalkingEngineProportions;
  jointModes: Record<keyof WalkingEnginePivotOffsets, JointMode>;
}

const rotateVec = (vec: Vector2D, angleDeg: number): Vector2D => {
  const r = angleDeg * Math.PI / 180;
  const c = Math.cos(r);
  const s = Math.sin(r);
  return { x: vec.x * c - vec.y * s, y: vec.x * s + vec.y * c };
};
const addVec = (v1: Vector2D, v2: Vector2D): Vector2D => ({ x: v1.x + v2.x, y: v1.y + v2.y });

const App: React.FC = () => {
  const [showPivots, setShowPivots] = useState(true);
  const [showLabels, setShowLabels] = useState(false);
  const [baseH] = useState(150);
  const [isConsoleVisible, setIsConsoleVisible] = useState(false);
  const [activeControlTab, setActiveControlTab] = useState<'pose' | 'props' | 'library'>('pose');
  const [systemLogs, setSystemLogs] = useState<{ timestamp: string; message: string }[]>([]);
  const [isCalibrated, setIsCalibrated] = useState(false);
  const [tokens, setTokens] = useState(0);
  const [lHandFlash, setLHandFlash] = useState(false);
  const [rHandFlash, setRHandFlash] = useState(false);
  const [saveConfirmation, setSaveConfirmation] = useState(false);

  const anomalySize = useMemo(() => 15, []);

  // New State: Joint Modes and Hierarchy
  const [jointModes, setJointModes] = useState<Record<keyof WalkingEnginePivotOffsets, JointMode>>(
    Object.fromEntries(JOINT_KEYS.map(k => [k, 'standard'])) as any
  );
  const [isReversed, setIsReversed] = useState(false);
  const [lastPoppedKey, setLastPoppedKey] = useState<string | null>(null);

  // Pinning State
  const [pinningMode, setPinningMode] = useState<'none' | 'rightFoot' | 'dual'>('none');
  const [pinOffset, setPinOffset] = useState<Vector2D>({ x: 0, y: 0 });
  const pinnedWorldPosRef = useRef<Vector2D | null>(null);

  // Tween Configuration State
  const [tweenDuration, setTweenDuration] = useState(1000);
  const [tweenEasing, setTweenEasing] = useState<'linear' | 'easeInOutQuad' | 'snapOut'>('easeInOutQuad');
  const [isTweening, setIsTweening] = useState(false);

  // Interaction Tracking
  const lastInteractionTimeRef = useRef(Date.now());
  const draggingBoneKeyRef = useRef<keyof WalkingEnginePivotOffsets | null>(null);

  // Core State
  const [pivotOffsets, setPivotOffsets] = useState<WalkingEnginePivotOffsets>(INITIAL_CHALLENGE_POSE);
  const [props, setProps] = useState<WalkingEngineProportions>({
    head: { w: 1, h: 1 }, collar: { w: 1, h: 1 }, torso: { w: 1, h: 1 }, waist: { w: 1, h: 1 },
    l_upper_arm: { w: 1, h: 1 }, l_lower_arm: { w: 1, h: 1 }, l_hand: { w: 1, h: 1 },
    r_upper_arm: { w: 1, h: 1 }, r_lower_arm: { w: 1, h: 1 }, r_hand: { w: 1, h: 1 },
    l_upper_leg: { w: 1, h: 1 }, l_lower_leg: { w: 1, h: 1 }, l_foot: { w: 1, h: 1 }, l_toe: { w: 1, h: 1 },
    r_upper_leg: { w: 1, h: 1 }, r_lower_leg: { w: 1, h: 1 }, r_foot: { w: 1, h: 1 }, r_toe: { w: 1, h: 1 }
  });

  const [savedPoses, setSavedPoses] = useState<SavedPoseEntry[]>([]);
  const [anomaly, setAnomaly] = useState<Vector2D | null>(null);
  const anomalyRef = useRef<Vector2D | null>(null);

  const [draggingBoneKey, setDraggingBoneKey] = useState<keyof WalkingEnginePivotOffsets | null>(null);
  const dragStartXRef = useRef(0);
  const dragStartPivotOffsetRef = useRef(0);

  const addLog = useCallback((message: string) => {
    setSystemLogs(prev => [...prev.slice(-49), { timestamp: new Date().toLocaleTimeString(), message }]);
  }, []);

  useEffect(() => {
    try {
      const storedPoses = localStorage.getItem('bitruvian_library');
      if (storedPoses) {
        const parsed = JSON.parse(storedPoses);
        if (Array.isArray(parsed)) setSavedPoses(parsed);
      }
    } catch (e) { console.error("Error loading library", e); }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem('bitruvian_library', JSON.stringify(savedPoses));
    } catch (e) { console.error("Error saving library", e); }
  }, [savedPoses]);

  const awardTokens = useCallback((sourceBone: string) => {
    const timeSinceLastInteraction = Date.now() - lastInteractionTimeRef.current;
    let passiveMultiplier = (timeSinceLastInteraction > 1500 || isTweening) ? 2 : 1;
    let limbBonus = CHAIN_DEPTH[sourceBone] || 1;
    const gain = Math.floor(limbBonus * passiveMultiplier);
    setTokens(prev => prev + gain);
    addLog(`[SYSTEM]: POSE_PICKUP - UNIT TOKENS UPDATED (+${gain}) ${passiveMultiplier > 1 ? '[PASSIVE BONUS]' : ''} [${sourceBone.toUpperCase()} DEPTH: ${limbBonus}X]`);
  }, [addLog, isTweening]);

  const spawnAnomaly = useCallback(() => {
    const angle = Math.random() * Math.PI * 2;
    const distance = 150 + Math.random() * 350;
    const newAnom = { x: Math.cos(angle) * distance, y: -250 + Math.sin(angle) * distance };
    setAnomaly(newAnom);
    anomalyRef.current = newAnom;
  }, []);

  const calculateAnklePos = useCallback((currentPivotOffsets: WalkingEnginePivotOffsets, currentProps: WalkingEngineProportions) => {
    const getRot = (key: string) => ((currentPivotOffsets as any)[key] || 0);
    const getDim = (raw: number, key: keyof WalkingEngineProportions) => raw * baseH * (currentProps[key]?.h || 1);
    const waistRot = getRot('waist');
    // For calculating ankle position, we still assume legs generally point downwards from hip
    const hipRot = waistRot + getRot('r_hip'); 
    const thighLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_UPPER, 'r_upper_leg');
    const kneeRot = hipRot + getRot('r_knee');
    const kneePos = rotateVec({ x: 0, y: thighLen }, hipRot);
    const calfLen = getDim(ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.LEG_LOWER, 'r_lower_leg');
    const anklePos = addVec(kneePos, rotateVec({ x: 0, y: calfLen }, kneeRot));
    return anklePos;
  }, [baseH]);

  const togglePinning = useCallback(() => {
    setLastPoppedKey('pin-foot');
    setTimeout(() => setLastPoppedKey(null), 300);
    if (pinningMode === 'none') {
      const local = calculateAnklePos(pivotOffsets, props);
      pinnedWorldPosRef.current = { x: local.x + pinOffset.x, y: local.y - 50 + pinOffset.y };
      setPinningMode('rightFoot');
      addLog(`[SYSTEM]: PINNING ENABLED - RIGHT ANKLE ANCHORED.`);
    } else {
      setPinningMode('none');
      pinnedWorldPosRef.current = null;
      setPinOffset({ x: 0, y: 0 });
      addLog(`[SYSTEM]: PINNING DISABLED.`);
    }
  }, [pinningMode, calculateAnklePos, pivotOffsets, props, pinOffset, addLog]);

  const updatePinOffset = useCallback(() => {
    if (pinningMode === 'none' || !pinnedWorldPosRef.current) return;
    const currentLocal = calculateAnklePos(pivotOffsets, props);
    const nextX = pinnedWorldPosRef.current.x - currentLocal.x;
    const nextY = pinnedWorldPosRef.current.y - currentLocal.y + 50;
    setPinOffset({ x: nextX, y: nextY });
  }, [pinningMode, calculateAnklePos, pivotOffsets, props]);

  useEffect(() => {
    if (pinningMode !== 'none') updatePinOffset();
  }, [pivotOffsets, props, updatePinOffset]);

  const handleDrag = useCallback((e: MouseEvent) => {
    if (draggingBoneKey && !isTweening) {
      lastInteractionTimeRef.current = Date.now();
      const delta = (e.clientX - dragStartXRef.current) * 0.5;
      setPivotOffsets(p => ({ ...p, [draggingBoneKey]: dragStartPivotOffsetRef.current + delta }));
    }
  }, [draggingBoneKey, isTweening]);

  useEffect(() => {
    const hu = () => { setDraggingBoneKey(null); draggingBoneKeyRef.current = null; };
    if (draggingBoneKey) {
      draggingBoneKeyRef.current = draggingBoneKey;
      window.addEventListener('mousemove', handleDrag);
      window.addEventListener('mouseup', hu);
    }
    return () => { window.removeEventListener('mousemove', handleDrag); window.removeEventListener('mouseup', hu); };
  }, [draggingBoneKey, handleDrag]);

  const setJointMode = (key: keyof WalkingEnginePivotOffsets, mode: JointMode) => {
    setLastPoppedKey(`${key}-${mode}`);
    setTimeout(() => setLastPoppedKey(null), 300);
    // If clicking an already active mode, toggle it back to standard
    const nextMode = jointModes[key] === mode ? 'standard' : mode;
    setJointModes(prev => ({ ...prev, [key]: nextMode }));
    addLog(`[SYSTEM]: JOINT_MODE_UPDATE - ${key.toUpperCase()} SET TO ${nextMode.toUpperCase()}`);
  };

  const runTween = useCallback((target: SavedPoseEntry) => {
    if (isTweening) return;
    setIsTweening(true);
    const startPivot = { ...pivotOffsets };
    let startTime: number | null = null; // Reset startTime for each new tween

    const animate = (currentTime: number) => {
      if (!startTime) startTime = currentTime;
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / tweenDuration, 1);
      const easedProgress = EASING_FUNCTIONS[tweenEasing](progress);

      const nextPivot = { ...startPivot };
      JOINT_KEYS.forEach(key => {
        const startValue = startPivot[key];
        const endValue = target.pivotOffsets[key];
        nextPivot[key] = startValue + (endValue - startValue) * easedProgress;
      });

      setPivotOffsets(nextPivot);

      if (progress < 1) {
        requestAnimationFrame(animate);
      } else {
        setIsTweening(false);
        setJointModes(target.jointModes);
        setProps(target.props);
        addLog(`[SYSTEM]: TWEEN_COMPLETE - POSE "${target.name.toUpperCase()}" LOADED.`);
      }
    };

    requestAnimationFrame(animate);
  }, [isTweening, pivotOffsets, tweenDuration, tweenEasing, addLog]);

  const saveCurrentPose = useCallback(() => {
    const newEntry: SavedPoseEntry = {
      id: Date.now(),
      name: `Pose ${savedPoses.length + 1}`,
      pivotOffsets: { ...pivotOffsets },
      props: { ...props },
      jointModes: { ...jointModes }
    };
    setSavedPoses(prev => [...prev, newEntry]);
    setSaveConfirmation(true);
    addLog(`[SYSTEM]: POSE_SAVED - ENTITY ID: ${newEntry.id}`);
    setTimeout(() => setSaveConfirmation(false), 2000);
  }, [savedPoses, pivotOffsets, props, jointModes, addLog]);

  return (
    <div className="flex h-full w-full bg-paper font-mono text-ink overflow-hidden select-none">
      {isConsoleVisible && (
        <div className="w-80 border-r border-ridge bg-mono-darker p-4 flex flex-col gap-4 custom-scrollbar overflow-y-auto z-50">
          <div className="flex justify-between items-center border-b border-ridge pb-2">
            <h1 className="text-xl font-archaic tracking-widest uppercase italic">Bitruvius.Core</h1>
          </div>

          <div className="flex flex-col gap-2">
            {!isCalibrated ? (
              <button onClick={() => setIsCalibrated(true)} className="text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase hover:scale-[1.02] active:scale-[0.98] transition-transform btn-pop">INITIALIZE ENGINE</button>
            ) : (
              <div className="flex flex-col gap-2">
                <button 
                  onClick={() => {
                    setLastPoppedKey('t-pose');
                    setTimeout(() => setLastPoppedKey(null), 300);
                    runTween({ id: 0, name: 'T-POSE', pivotOffsets: T_POSE, props: props, jointModes: Object.fromEntries(JOINT_KEYS.map(k => [k, 'standard'])) as any });
                  }} 
                  className={`text-[9px] px-3 py-2 border border-selection bg-selection text-paper font-bold uppercase transition-all hover:scale-[1.02] active:scale-[0.98] btn-pop ${lastPoppedKey === 't-pose' ? 'animate-pop' : ''}`}
                >
                  T-POSE
                </button>
                <div className="grid grid-cols-2 gap-2">
                    <button 
                    onClick={togglePinning} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase hover:scale-[1.05] active:scale-[0.95] ${lastPoppedKey === 'pin-foot' ? 'animate-pop' : ''} ${pinningMode !== 'none' ? 'bg-accent-purple text-paper border-accent-purple shadow-lg scale-[1.05]' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {pinningMode !== 'none' ? 'FOOT PINNED' : 'PIN FOOT'}
                    </button>
                    <button 
                    onClick={() => { 
                      setLastPoppedKey('reverse');
                      setTimeout(() => setLastPoppedKey(null), 300);
                      setIsReversed(!isReversed); 
                      addLog(`[SYSTEM]: HIERARCHY_REVERSED - ROOT SET TO ${!isReversed ? 'HEAD' : 'WAIST'}`); 
                    }} 
                    className={`text-[9px] px-3 py-2 border transition-all font-bold uppercase hover:scale-[1.05] active:scale-[0.95] ${lastPoppedKey === 'reverse' ? 'animate-pop' : ''} ${isReversed ? 'bg-accent-red text-paper border-accent-red shadow-lg scale-[1.05]' : 'bg-paper/10 border-ridge text-mono-light'}`}
                    >
                    {isReversed ? 'REVERSED' : 'REVERSE'}
                    </button>
                </div>
                <button onClick={() => setShowPivots(!showPivots)} className={`text-[9px] px-3 py-1 border transition-all ${showPivots ? 'bg-selection text-paper' : 'border-ridge'}`}>ANCHORS: {showPivots ? 'ON' : 'OFF'}</button>
              </div>
            )}
          </div>

          <div className="flex border-b border-ridge">
            {(['pose', 'props', 'library'] as const).map(tab => (
              <button key={tab} onClick={() => setActiveControlTab(tab)} className={`flex-1 text-[9px] py-2 font-bold transition-all ${activeControlTab === tab ? 'text-selection border-b-2 border-selection bg-white/40' : 'opacity-40 hover:opacity-100'}`}>{tab.toUpperCase()}</button>
            ))}
          </div>

          <div className="flex-grow flex flex-col min-h-0">
            {activeControlTab === 'pose' && (
              <div className="flex flex-col gap-2 overflow-y-auto custom-scrollbar py-2 pr-1">
                {JOINT_KEYS.map(k => (
                  <div key={k} className="p-2 border border-ridge/20 rounded hover:bg-white/30 transition-colors">
                    <div className="flex justify-between items-center mb-1">
                        <div className="flex items-center gap-2">
                            <span className="text-[10px] uppercase font-bold text-ink">{k.replace(/_/g, ' ')}</span>
                            <div className="flex gap-1">
                                {(['bend', 'stretch'] as JointMode[]).map(m => (
                                    <button 
                                        key={m} 
                                        onClick={() => setJointMode(k, m)}
                                        title={m.toUpperCase()}
                                        className={`w-5 h-5 flex items-center justify-center rounded-sm text-[8px] font-bold border transition-all hover:scale-110 active:scale-90 ${lastPoppedKey === `${k}-${m}` ? 'animate-pop' : ''} ${jointModes[k] === m ? 'bg-selection text-paper border-selection shadow-md translate-y-[-1px]' : 'border-ridge text-mono-mid opacity-40 hover:opacity-100'}`}
                                    >
                                        {m === 'bend' ? 'B' : 'T'}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <span className="text-[8px] font-mono text-mono-mid tabular-nums">{Math.round(pivotOffsets[k])}°</span>
                    </div>
                    <input type="range" min="-180" max="180" value={pivotOffsets[k]} onChange={e => !isTweening && setPivotOffsets(p => ({...p, [k]: parseInt(e.target.value)}))} className="w-full accent-selection h-1 cursor-ew-resize" />
                  </div>
                ))}
              </div>
            )}
            {activeControlTab === 'library' && (
              <div className="flex flex-col h-full gap-2">
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                  {savedPoses.map(pe => (
                    <div key={pe.id} className="flex items-center justify-between p-2 border-b border-ridge hover:bg-white/40 group transition-colors">
                      <span className="text-[10px] uppercase font-bold">{pe.name}</span>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => { setPivotOffsets({ ...pe.pivotOffsets }); setJointModes({ ...pe.jointModes }); }} className="text-[8px] px-2 py-1 bg-selection text-paper uppercase hover:scale-105 active:scale-95 transition-transform">Load</button>
                        <button onClick={() => runTween(pe)} className="text-[8px] px-2 py-1 bg-mono-mid text-paper uppercase hover:scale-105 active:scale-95 transition-transform">Tween</button>
                      </div>
                    </div>
                  ))}
                </div>
                <button 
                  onClick={saveCurrentPose} 
                  className={`w-full py-3 text-[10px] font-bold uppercase transition-all hover:scale-[1.02] active:scale-[0.98] ${saveConfirmation ? 'bg-accent-green text-paper scale-[1.02] shadow-lg' : 'bg-selection text-paper shadow-md'}`}
                >
                  {saveConfirmation ? '✓ SAVED' : 'SAVE POSE'}
                </button>
              </div>
            )}
          </div>

          <div className="mt-auto pt-4"><SystemLogger logs={systemLogs} isVisible={true} historyCount={tokens} /></div>
        </div>
      )}

      <div className="flex-1 relative bg-paper flex items-center justify-center overflow-hidden" onClick={() => !isCalibrated && setIsCalibrated(true)}>
        <div className="absolute top-4 right-4 z-50 text-right">
          <div className="text-[10px] text-mono-mid uppercase tracking-widest">Unit Tokens</div>
          <div className="text-2xl font-archaic text-ink">{tokens.toLocaleString()}</div>
        </div>

        <button onClick={() => setIsConsoleVisible(!isConsoleVisible)} className="absolute top-4 left-4 z-50 p-2 border border-ridge bg-white rounded-full transition-all hover:scale-110 active:scale-95 shadow-lg"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7" /></svg></button>

        {!isCalibrated && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center pointer-events-none bg-paper/20">
            <h2 className="text-6xl font-archaic uppercase tracking-tighter text-ink">Bitruvian Station</h2>
            <p className="text-[10px] uppercase tracking-[0.5em] animate-pulse text-mono-mid">Touch to Wake Core</p>
          </div>
        )}

        <svg viewBox="-500 -700 1000 1400" className="w-full h-full overflow-visible relative z-10 drop-shadow-2xl">
          <g transform={`translate(${pinOffset.x}, ${-50 + pinOffset.y})`}>
            <Mannequin 
              pose={RESTING_BASE_POSE} 
              pivotOffsets={{...pivotOffsets, l_hand_flash: lHandFlash, r_hand_flash: rHandFlash} as any} 
              props={props} 
              showPivots={showPivots && isCalibrated} 
              showLabels={showLabels} 
              baseUnitH={baseH} 
              onAnchorMouseDown={(k, x) => { setDraggingBoneKey(k); dragStartXRef.current = x; dragStartPivotOffsetRef.current = pivotOffsets[k]; }} 
              draggingBoneKey={draggingBoneKey} 
              isPaused={true} 
              pinningMode={pinningMode} 
              offset={pinOffset} 
              isReversed={isReversed}
              jointModes={jointModes}
            />
          </g>
          {anomaly && (
            <g transform={`translate(${anomaly.x}, ${anomaly.y})`}>
              <rect x={-anomalySize / 2} y={-anomalySize / 2} width={anomalySize} height={anomalySize} className="fill-ink hover:fill-accent-red cursor-crosshair transition-all hover:scale-150 active:scale-90" />
            </g>
          )}
        </svg>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useCallback } from 'react';
import { Bone } from './Bone';
import { ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT, RIGGING } from '../constants';
import { WalkingEnginePose, WalkingEngineProportions, WalkingEnginePivotOffsets, Vector2D, MaskTransform, JointMode } from '../types';

interface MannequinProps {
  pose: WalkingEnginePose;
  pivotOffsets: WalkingEnginePivotOffsets & { l_hand_flash?: boolean; r_hand_flash?: boolean };
  props: WalkingEngineProportions;
  showPivots: boolean;
  showLabels: boolean;
  baseUnitH: number;
  onAnchorMouseDown: (boneKey: keyof WalkingEnginePivotOffsets, clientX: number) => void;
  draggingBoneKey: keyof WalkingEnginePivotOffsets | null;
  isPaused: boolean;
  pinningMode: 'none' | 'rightFoot' | 'dual';
  maskImage?: string | null;
  maskTransform?: MaskTransform;
  offset: Vector2D;
  isReversed?: boolean;
  jointModes?: Record<keyof WalkingEnginePivotOffsets, JointMode>;
}

const RENDER_ORDER: (keyof WalkingEngineProportions)[] = [
    'waist', 'torso', 'l_upper_leg', 'r_upper_leg', 'l_lower_leg', 'r_lower_leg', 'l_foot', 'r_foot', 'l_toe', 'r_toe', 
    'collar', 'head', 'l_upper_arm', 'r_upper_arm', 'l_lower_arm', 'r_lower_arm', 'l_hand', 'r_hand'
];

const partDefinitions: Record<keyof WalkingEngineProportions, any> = {
    head: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HEAD, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.HEAD_WIDTH, variant: 'head-tall-oval', drawsUpwards: true, label: 'Head', boneKey: 'neck' },
    collar: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.COLLAR_WIDTH, variant: 'collar-horizontal-oval-shape', drawsUpwards: true, label: 'Collar', boneKey: 'collar' },
    torso: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.TORSO_WIDTH, variant: 'torso-teardrop-pointy-down', drawsUpwards: true, label: 'Upper Body', boneKey: 'torso' },
    waist: { rawH: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST, rawW: ANATOMY_RAW_RELATIVE_TO_BASE_HEAD_UNIT.WAIST_WIDTH, variant: 'waist-teardrop-pointy-up', drawsUpwards: true, label: 'Lower Body', boneKey: 'waist' },
